function updateSessionButtonStates() {
  // YO ownership is rendered into pane-tab markup, so a restored/changed worker state must
  // rebuild the shared tab strip as well as the popovers that describe it.
  updateTopbarActivityStatus();
  renderPaneTabStrips();
  refreshPaneTabSessionPopovers();
}

function sessionPopoverNodeFromHtml(html) {
  const template = document.createElement('template');
  if (template?.content !== undefined) {
    template.innerHTML = String(html || '');
    return template.content.firstElementChild;
  }
  const text = String(html || '');
  const match = text.match(/^<div class="session-popover" role="tooltip">([\s\S]*)<\/div>\s*$/);
  return {
    className: 'session-popover',
    innerHTML: match ? match[1] : text,
    getAttribute(name) {
      return name === 'role' ? 'tooltip' : null;
    },
  };
}

function refreshSessionPopoverContent(popover, html) {
  if (!popover) return;
  const fresh = sessionPopoverNodeFromHtml(html);
  if (!fresh) return;
  const keepOpen = popover.classList?.contains?.('popover-open') === true;
  const keepDetached = popover.classList?.contains?.('pane-tab-detached-popover') === true;
  popover.className = fresh.className || 'session-popover';
  if (keepOpen) popover.classList?.add?.('popover-open');
  if (keepDetached) popover.classList?.add?.('pane-tab-detached-popover');
  const role = fresh.getAttribute?.('role') || 'tooltip';
  popover.setAttribute?.('role', role);
  popover.innerHTML = fresh.innerHTML;
}

function refreshPaneTabSessionPopovers() {
  document.querySelectorAll('.pane-tab[data-pane-tab], .dockview-pane-tab[data-pane-tab]').forEach(tab => {
    const session = String(tab?.dataset?.paneTab || '').trim();
    if (!session || tabTypeForItem(session)) return;
    const popover = typeof paneTabPopoverForAnchor === 'function'
      ? paneTabPopoverForAnchor(tab)
      : tab?.querySelector?.(':scope > .session-popover');
    if (!popover || popover.classList?.contains?.('file-popover')) return;
    const info = transcriptMetadataState.payload.sessions?.[session];
    const auto = autoApproveStates.get(session)?.enabled === true;
    const state = sessionState(session, info);
    const agentKind = sessionAgentKind(session);
    refreshSessionPopoverContent(popover, sessionPopoverHtml(session, info, agentKind, auto, state));
  });
}

function bindFilePopoverActions(_container) {
  // Popover copy buttons route through the document-level data-copy-path delegate.
}

function clearTimer(timer) {
  if (timer) clearTimeout(timer);
  return null;
}

function numericOption(value, fallback) {
  const resolved = typeof value === 'function' ? value() : value;
  const number = Number(resolved);
  return Number.isFinite(number) ? number : fallback;
}

function viewportBounds(edgeGap = popoverEdgeGapPx()) {
  const viewport = appViewport();
  const width = Math.max(0, viewport.width || 0);
  const height = Math.max(0, viewport.height || 0);
  return {
    left: edgeGap,
    top: edgeGap,
    right: Math.max(edgeGap, width - edgeGap),
    bottom: Math.max(edgeGap, height - edgeGap),
  };
}

function clampToViewport(left, top, width, height, options = {}) {
  const bounds = viewportBounds(options.edgeGap ?? popoverEdgeGapPx());
  const minTop = Math.max(bounds.top, Number(options.minTop || 0));
  const maxLeft = Math.max(bounds.left, bounds.right - Math.max(0, width || 0));
  const maxTop = Math.max(minTop, bounds.bottom - Math.max(0, height || 0));
  return {
    left: Math.min(Math.max(bounds.left, left), maxLeft),
    top: Math.min(Math.max(minTop, top), maxTop),
  };
}

function stopPopoverEvent(event) {
  event.stopPropagation();
}

function closeOtherSessionPopovers(current, options = {}) {
  const force = options.force === true;
  let changed = false;
  for (const other of document.querySelectorAll('.pane-tab.popover-open, .tabber-session-tab.popover-open, .panel-popover-zone.popover-open')) {
    if (other !== current) {
      const popover = other.querySelector?.(':scope > .session-popover, :scope > .panel-detail-popover')
        || other.__yolomuxDetachedPopover;
      if (current === null && !force && popoverStillActive(other, popover)) continue;
      if (other.classList?.contains('popover-open') || popover?.classList?.contains('popover-open') || other.__yolomuxDetachedPopover?.classList?.contains('popover-open')) changed = true;
      other.classList.remove('popover-open');
      popover?.classList?.remove('popover-open');
      other.__yolomuxDetachedPopover?.classList?.remove('popover-open');
      delete other.dataset.popoverHoverState;
    }
  }
  if (changed && typeof scheduleSharePopupLayerPublish === 'function') scheduleSharePopupLayerPublish({immediate: true});
}

function popoverLifecycleActive(anchor, popover) {
  const state = anchor?.dataset?.popoverHoverState || '';
  return Boolean(
    state === 'open'
      || state === 'pending'
      || state === 'closing'
      || anchor?.classList?.contains?.('popover-open')
      || anchor?.matches?.(':hover')
      || popover?.matches?.(':hover')
  );
}

function popoverStillActive(anchor, popover) {
  const focused = document.activeElement;
  return Boolean(
    anchor?.matches?.(':hover')
      || popover?.matches?.(':hover')
      || (focused && (anchor.contains(focused) || popover?.contains(focused)))
  );
}

function bindPopoverHover(anchor, popover, handlers) {
  const queueOpen = handlers.queueOpen || handlers.keepOpen;
  const keepOpen = handlers.keepOpen || queueOpen;
  const closeSoon = handlers.closeSoon;
  const closeNow = handlers.closeNow;
  const closeIfOutside = event => {
    const next = event?.relatedTarget;
    if (next && (anchor.contains(next) || popover?.contains(next))) return;
    closeSoon(event);
  };

  anchor.addEventListener('pointerenter', event => {
    if (browserHasCursorHover(event)) queueOpen(event);
  });
  anchor.addEventListener('pointerleave', closeIfOutside);
  anchor.addEventListener('focusin', event => {
    // Touching a tab may focus it, but a keyboard-visible focus is the only focus state that
    // should expose a hover-only popover when no cursor is present.
    if (anchor.matches?.(':focus-visible')) queueOpen(event);
  });
  anchor.addEventListener('focusout', closeIfOutside);
  anchor.addEventListener('pointerdown', event => {
    if (!browserHasCursorHover(event)) closeNow?.(event);
  });
  if (!popover) return;
  popover.addEventListener('pointerenter', event => {
    if (browserHasCursorHover(event)) keepOpen(event);
  });
  popover.addEventListener('pointerleave', closeIfOutside);
  popover.addEventListener('click', stopPopoverEvent);
  popover.addEventListener('dragstart', stopPopoverEvent);
  popover.querySelectorAll('a').forEach(link => {
    link.addEventListener('pointerenter', event => {
      if (browserHasCursorHover(event)) keepOpen(event);
    });
    link.addEventListener('click', stopPopoverEvent);
  });
}

function createHoverPopover(options) {
  const anchor = options.anchor;
  if (!anchor) return null;
  if (typeof options.onPointerMove === 'function') anchor.addEventListener('pointermove', options.onPointerMove);
  const stateClass = options.stateClass === undefined ? 'popover-open' : options.stateClass;
  let showTimer = null;
  let hideTimer = null;
  const popover = () => (typeof options.popover === 'function' ? options.popover() : options.popover);
  const canOpen = event => (typeof options.canOpen === 'function' ? options.canOpen(event) !== false : true);
  const stillActive = event => (typeof options.stillActive === 'function'
    ? options.stillActive(event) !== false
    : popoverStillActive(anchor, popover()));
  const markState = state => {
    if (!anchor.dataset) return;
    if (state) anchor.dataset.popoverHoverState = state;
    else delete anchor.dataset.popoverHoverState;
  };
  const cancelTimers = () => {
    showTimer = clearTimer(showTimer);
    hideTimer = clearTimer(hideTimer);
  };
  const closeNow = event => {
    cancelTimers();
    if (stateClass) anchor.classList.remove(stateClass);
    markState('');
    options.onClose?.(event);
    if (typeof scheduleSharePopupLayerPublish === 'function') scheduleSharePopupLayerPublish({immediate: true});
  };
  const openNow = event => {
    cancelTimers();
    markState('');
    if (anchor.isConnected === false || !canOpen(event)) return;
    if (event && !stillActive(event)) return;
    if (stateClass && anchor.classList.contains(stateClass) && stillActive(event)) {
      options.position?.(event);
      options.onOpen?.(event);
      markState('open');
      if (typeof scheduleSharePopupLayerPublish === 'function') scheduleSharePopupLayerPublish();
      return;
    }
    options.position?.(event);
    options.closeOthers?.();
    options.onOpen?.(event);
    if (stateClass) anchor.classList.add(stateClass);
    markState('open');
    if (typeof scheduleSharePopupLayerPublish === 'function') scheduleSharePopupLayerPublish();
    const activePopover = popover();
    if (activePopover && activePopover.dataset.hoverPopoverBound !== 'true') {
      bindPopoverHover(anchor, activePopover, {queueOpen, keepOpen: openNow, closeSoon, closeNow});
      activePopover.dataset.hoverPopoverBound = 'true';
    }
  };
  function queueOpen(event) {
    hideTimer = clearTimer(hideTimer);
    markState('pending');
    if (anchor.isConnected === false || !canOpen(event)) {
      markState('');
      return;
    }
    if (stateClass && anchor.classList.contains(stateClass)) return;
    showTimer = clearTimer(showTimer);
    options.onQueue?.(event);
    const delay = numericOption(options.showDelay, popoverShowDelayMs);
    showTimer = setTimeout(() => openNow(event), Math.max(0, delay));
  }
  function closeSoon(event) {
    showTimer = clearTimer(showTimer);
    hideTimer = clearTimer(hideTimer);
    markState('closing');
    const delay = numericOption(options.hideDelay, popoverHideDelayMs);
    hideTimer = setTimeout(() => {
      if (anchor.isConnected === false) {
        markState('');
        hideTimer = null;
        if (stateClass) anchor.classList.remove(stateClass);
        options.onClose?.(event);
        if (typeof scheduleSharePopupLayerPublish === 'function') scheduleSharePopupLayerPublish({immediate: true});
        return;
      }
      if (stillActive(event)) {
        markState('open');
        hideTimer = null;
        return;
      }
      if (stateClass) anchor.classList.remove(stateClass);
      markState('');
      hideTimer = null;
      options.onClose?.(event);
      if (typeof scheduleSharePopupLayerPublish === 'function') scheduleSharePopupLayerPublish({immediate: true});
    }, Math.max(0, delay));
  }
  const initialPopover = popover();
  bindPopoverHover(anchor, initialPopover, {queueOpen, keepOpen: openNow, closeSoon, closeNow});
  if (initialPopover) initialPopover.dataset.hoverPopoverBound = 'true';
  return {queueOpen, openNow, closeSoon, closeNow, cancelTimers};
}

function tabInteractionControllerForApp() {
  if (tabInteractionController) return tabInteractionController;
  let touchPress = null;
  let suppressContextUntil = 0;
  const cancelCurrentTouchPress = event => {
    if (!touchPress) return;
    const opened = touchPress.opened;
    clearTimer(touchPress.timer);
    touchPress = null;
    // A tab activation may replace its anchor before pointerup reaches that anchor. Own the
    // terminal touch event at document capture so a short tap cannot leave its long-press timer
    // behind to open the action sheet after the selected panel has rendered.
    if (opened && event?.cancelable) {
      event.preventDefault();
      event.stopImmediatePropagation();
    }
  };
  document.addEventListener('pointerup', event => {
    if (event.pointerType === 'touch') cancelCurrentTouchPress(event);
  }, true);
  document.addEventListener('pointercancel', event => {
    if (event.pointerType === 'touch') cancelCurrentTouchPress(event);
  }, true);
  const currentDescriptor = descriptor => descriptor?.anchor?.__yolomuxTabInteractionDescriptor || descriptor;
  const close = () => {
    touchPress = null;
    closeOtherSessionPopovers(null, {force: true});
    closeSessionContextMenu();
  };
  const pointForAnchor = anchor => {
    const rect = anchor?.getBoundingClientRect?.();
    return {
      x: Math.round((rect?.left || 0) + (rect?.width || 0) / 2),
      y: Math.round((rect?.bottom || 0) + 6),
    };
  };
  const showActions = (descriptor, event = null, options = {}) => {
    descriptor = currentDescriptor(descriptor);
    const item = String(descriptor?.item || '').trim();
    if (!item || !isLayoutItem(item)) return false;
    const eventPoint = event && Number.isFinite(event.clientX) && Number.isFinite(event.clientY)
      ? {x: event.clientX, y: event.clientY}
      : pointForAnchor(descriptor.anchor);
    // A touch long press is an anchored tab action, not a global bottom sheet. Use the tab's
    // lower edge so the compact action surface opens beside the tab that owns it.
    const point = options.presentation === 'sheet' ? pointForAnchor(descriptor.anchor) : eventPoint;
    closeOtherSessionPopovers(null, {force: true});
    showTabContextMenu(item, point.x, point.y, {
      tab: descriptor.anchor,
      sourceSlot: descriptor.sourceSlot?.() || slotForItem(item),
      presentation: options.presentation || 'context',
    });
    return true;
  };
  const bindDetail = descriptor => {
    const {anchor} = descriptor;
    const detailPopover = () => {
      const current = currentDescriptor(descriptor);
      return typeof current?.popover === 'function' ? current.popover() : current?.popover;
    };
    if (!detailPopover()) return null;
    return createHoverPopover({
      anchor,
      popover: detailPopover,
      showDelay: () => (document.querySelector('.pane-tab.popover-open, .tabber-session-tab.popover-open') ? tabPopoverFollowDelayMs : tabPopoverShowDelayMs),
      hideDelay: () => popoverHideDelayMs,
      canOpen: () => !appMenuIsOpen() && !contextMenuIsOpen() && !topbar?.matches?.(':hover'),
      onQueue: event => currentDescriptor(descriptor)?.positionDetail?.(event),
      onOpen: event => {
        currentDescriptor(descriptor)?.onDetailOpen?.(event);
      },
      onClose: event => currentDescriptor(descriptor)?.onDetailClose?.(event),
      position: event => currentDescriptor(descriptor)?.positionDetail?.(event),
      closeOthers: () => closeOtherSessionPopovers(anchor),
    });
  };
  const bind = descriptor => {
    const anchor = descriptor?.anchor;
    if (!anchor) return null;
    anchor.__yolomuxTabInteractionDescriptor = descriptor;
    if (anchor.dataset?.tabInteractionBound === 'true') return {showActions: event => showActions(descriptor, event), close};
    if (anchor.dataset) anchor.dataset.tabInteractionBound = 'true';
    const detail = bindDetail(descriptor);
    const cancelTouchPress = () => {
      if (!touchPress || touchPress.anchor !== anchor) return;
      cancelCurrentTouchPress();
    };
    const movedBeyondThreshold = event => {
      if (!touchPress || touchPress.anchor !== anchor) return false;
      return Math.hypot(event.clientX - touchPress.x, event.clientY - touchPress.y) > tabTouchLongPressMoveThresholdPx;
    };
    anchor.addEventListener('contextmenu', event => {
      if (Date.now() < suppressContextUntil) {
        event.preventDefault();
        event.stopPropagation();
        return;
      }
      event.preventDefault();
      event.stopPropagation();
      showActions(descriptor, event);
    });
    anchor.addEventListener('keydown', event => {
      if (event.key !== 'ContextMenu' && !(event.shiftKey && event.key === 'F10')) return;
      event.preventDefault();
      event.stopPropagation();
      showActions(descriptor);
    }, true);
    anchor.addEventListener('pointerdown', event => {
      if (event.pointerType !== 'touch' || event.button !== 0) return;
      cancelTouchPress();
      const current = currentDescriptor(descriptor);
      const item = String(current?.item || '');
      const sourceSlot = current?.sourceSlot?.() || slotForItem(item);
      const record = {
        anchor,
        x: event.clientX,
        y: event.clientY,
        timer: null,
        opened: false,
        sourceSlot,
        priorActiveItem: sourceSlot ? activeItemForSide(sourceSlot) : '',
      };
      record.timer = setTimeout(() => {
        if (touchPress !== record || movedBeyondThreshold({clientX: record.x, clientY: record.y})) return;
        record.opened = showActions(descriptor, {clientX: record.x, clientY: record.y}, {presentation: 'sheet'});
        if (record.opened) {
          // Dockview activates a tab on touch pointer-down before the browser can know this is a
          // long press. Put the prior visible tab back before opening the sheet; a long press is
          // an action gesture, never an activation or keyboard-focus gesture.
          if (record.sourceSlot && record.priorActiveItem && record.priorActiveItem !== item) {
            activatePaneTab(record.sourceSlot, record.priorActiveItem);
          }
          suppressContextUntil = Date.now() + tabTouchLongPressDelayMs;
        }
      }, tabTouchLongPressDelayMs);
      touchPress = record;
    }, true);
    anchor.addEventListener('pointermove', event => {
      if (event.pointerType === 'touch' && movedBeyondThreshold(event)) cancelTouchPress();
    }, true);
    anchor.addEventListener('pointerup', event => {
      if (event.pointerType !== 'touch' || !touchPress || touchPress.anchor !== anchor) return;
      const opened = touchPress.opened;
      cancelTouchPress();
      if (!opened) return;
      event.preventDefault();
      event.stopImmediatePropagation();
    }, true);
    anchor.addEventListener('pointercancel', cancelTouchPress, true);
    anchor.addEventListener('dragstart', cancelTouchPress, true);
    return {detail, showActions: event => showActions(descriptor, event), close};
  };
  tabInteractionController = {bind, close, showActions};
  return tabInteractionController;
}

function bindTabInteraction(descriptor) {
  return tabInteractionControllerForApp().bind(descriptor);
}

function cssEscape(value) {
  if (window.CSS?.escape) return CSS.escape(value);
  return String(value).replace(/["\\]/g, '\\$&');
}

// Tab buttons are also drag handles, so activation waits until pointer release proves it was a click.
function bindTabActivation(node, activate, options = {}) {
  let pointerCandidate = false;
  let pointerActivated = false;
  let dragged = false;
  let startX = 0;
  let startY = 0;
  const stop = event => {
    if (options.stopPropagation) event.stopPropagation();
  };
  const ignored = event => options.ignore?.(event) === true;
  const resetPointer = () => {
    pointerCandidate = false;
    dragged = false;
  };

  node.addEventListener('pointerdown', event => {
    if (event.button !== 0 || ignored(event)) return;
    pointerCandidate = true;
    pointerActivated = false;
    dragged = false;
    startX = event.clientX;
    startY = event.clientY;
  });
  node.addEventListener('pointerup', event => {
    if (!pointerCandidate || event.button !== 0 || ignored(event)) {
      resetPointer();
      return;
    }
    const moved = Math.abs(event.clientX - startX) > 4 || Math.abs(event.clientY - startY) > 4;
    const wasDragged = dragged;
    resetPointer();
    if (wasDragged || moved) return;
    event.preventDefault();
    stop(event);
    pointerActivated = true;
    activate(event);
  });
  node.addEventListener('click', event => {
    if (ignored(event)) return;
    if (pointerActivated) {
      pointerActivated = false;
      event.preventDefault();
      stop(event);
      return;
    }
    event.preventDefault();
    stop(event);
    activate(event);
  });
  node.addEventListener('dragstart', () => {
    dragged = true;
    pointerCandidate = false;
    pointerActivated = false;
  });
  node.addEventListener('dragend', resetPointer);
}

// Tabs, headers, and popovers all use these helpers so badge precedence stays consistent.
function metaSeparatorHtml(classes = '') {
  const extraClasses = String(classes || '').trim();
  return `<span class="meta-sep${extraClasses ? ` ${extraClasses}` : ''}" aria-hidden="true">|</span>`;
}

function metaJoin(parts) {
  return parts.filter(Boolean).join(metaSeparatorHtml());
}

function sessionNumberNameHtml(session, options = {}) {
  const label = sessionLabel(session);
  const className = numericSessionName(label) !== null ? 'session-button-number' : 'session-button-name';
  const labelHtml = options.labelHtml !== undefined ? String(options.labelHtml) : esc(label);
  return `<strong class="${className} session-button-identifier">[${labelHtml}]</strong>`;
}

function yoloMarkerHtml(session, auto, options = {}) {
  const payload = options.payload || autoApproveStates.get(session);
  const locked = !auto && (options.locked === true || (options.locked !== false && autoApproveEnabledElsewhere(payload)));
  if (!auto && !locked && options.enabledOnly !== false) return '';
  const classes = ['session-yolo-marker'];
  if (auto) classes.push('active');
  else if (locked) classes.push('locked');
  else classes.push('inactive');
  if (options.yoloWorking) classes.push('working');
  if (readOnlyMode) classes.push('readonly');
  const yoloAttr = ` data-yolo-session="${esc(session)}"`;
  const toggleAttr = options.toggle && !readOnlyMode ? ` data-auto-session="${esc(session)}" data-action="pane-tab-auto-approve"` : '';
  const stateText = auto ? t('yolo.state.onHere') : (locked ? t('yolo.state.onElsewhere') : t('state.off'));
  const title = options.toggle && readOnlyMode
    ? t('yolo.titleReadonly', {state: stateText, session: sessionLabel(session)})
    : (options.toggle ? t('yolo.titleForSession', {state: stateText, session: sessionLabel(session)}) : t('yolo.title', {state: stateText}));
  return `<span class="${esc(classes.join(' '))}"${yoloAttr}${toggleAttr} title="${esc(title)}" aria-label="${esc(title)}">${esc(t('brand.marker'))}</span>`;
}

function sessionShouldOfferYoloMarker(session, info, payload, auto, state = null) {
  if (auto) return true;
  if (autoApproveEnabledElsewhere(payload)) return true;
  const tabState = state || sessionState(session, info);
  return [STATE_KEY.needsApproval, STATE_KEY.needsInput].includes(tabState?.key) && tabState?.promptAttentionCleared !== true;
}

function sessionStatusBallPlaceholderHtml() {
  // Every session Tab reserves the same ball column. Keeping the placeholder inside the canonical
  // activity wrapper makes its geometry follow the real red/yellow/green status ball exactly.
  return '<span class="session-agent-activity-marker session-agent-activity-marker--placeholder" aria-hidden="true"><span class="agent-window-activity agent-window-activity--status-only"><span class="agent-window-status-dot"></span></span></span>';
}

function sessionTabLeadingActivityContainerHtml(session, info, auto, options = {}) {
  return `<span class="session-tab-leading-activity">${sessionTabLeadingActivityHtml(session, info, auto, options)}</span>`;
}

function sessionTabLeadingActivityHtml(session, info, auto, options = {}) {
  const payload = options.payload || autoApproveStates.get(session);
  const state = Object.prototype.hasOwnProperty.call(options, 'state') ? options.state : sessionState(session, info);
  const offerYolo = sessionShouldOfferYoloMarker(session, info, payload, auto, state);
  const yoloHtml = offerYolo
    ? yoloMarkerHtml(session, auto, {...options, enabledOnly: false, yoloWorking: false, payload})
    : '';
  const statusSummary = sessionAgentWindowStatusSummary(session, info, payload);
  if (statusSummary?.agent) {
    const statusAgent = statusSummary.agent;
    const iconHtml = agentWindowActivityIconHtml(statusAgent.kind, statusAgent.state, agentWindowIdleSeconds(statusAgent), {
      ...agentWindowActivityOptionsForStatus(statusAgent, session),
      item: statusSummary.item,
      label: statusSummary.label,
      statusOnly: true,
    });
    if (iconHtml) {
      return `${yoloHtml}<span class="session-agent-activity-marker">${iconHtml}</span>`;
    }
  }
  const fallbackYoloHtml = offerYolo
    ? yoloMarkerHtml(session, auto, {
      ...options,
      enabledOnly: false,
      yoloWorking: sessionYoloIsWorking(session, payload),
      payload,
    })
    : '';
  return `${fallbackYoloHtml}${sessionStatusBallPlaceholderHtml()}`;
}

// Hovering a tab keeps its popover DOM mounted. Do not let that presentation concern freeze the
// status marker: its color is shared live state and must agree with the Tabber row immediately.
function syncSessionTabLeadingActivityChrome() {
  if (typeof document === 'undefined') return 0;
  let updated = 0;
  for (const tab of document.querySelectorAll('.pane-tab[data-pane-tab], .tmux-pane-tab-token[data-pane-tab]')) {
    const session = String(tab.dataset?.paneTab || '').trim();
    if (!session || !isTmuxSession(session)) continue;
    const leading = tab.querySelector?.(':scope > .session-tab-leading-activity, .pane-tab-core > .session-tab-leading-activity');
    if (!leading) continue;
    const info = transcriptMetadataState.payload.sessions?.[session];
    const auto = autoApproveStates.get(session)?.enabled === true;
    const state = sessionState(session, info);
    const html = sessionTabLeadingActivityHtml(session, info, auto, {enabledOnly: false, toggle: !readOnlyMode, state});
    if (leading.innerHTML === html) continue;
    leading.innerHTML = html;
    updated += 1;
  }
  return updated;
}

function pullRequestCompactBadgesHtml(session, pr) {
  const numberHtml = pullRequestNumberIndicatorHtml(session, pr);
  const statusHtml = pullRequestStatusIndicatorHtml(session, pr);
  const ciHtml = pullRequestCiIndicatorHtml(session, pr);
  const reviewHtml = pullRequestApprovalIndicatorHtml(session, pr);
  return [numberHtml, statusHtml, ciHtml, reviewHtml].filter(Boolean).join('');
}

function applySessionStateClasses(node, state) {
  node.classList.toggle(STATE_CLASS.needsAttention, state?.attention === true);
  node.classList.toggle(STATE_CLASS.needsInput, state?.key === STATE_KEY.needsInput && state?.attention === true);
  node.classList.toggle(STATE_CLASS.needsExec, state?.key === STATE_KEY.needsApproval && state?.attention === true);
  node.classList.toggle(STATE_CLASS.needsBlocked, state?.key === STATE_KEY.blocked);
  syncAttentionAnimation(node, state?.attention === true);
}

function panelHeaderStateHtml(state) {
  return state ? sessionStateHtml(state) : '';
}

function currentBranchSubject(git) {
  const branches = git?.other_branches?.branches || [];
  const current = branches.find(branch => branch.current);
  return current?.subject || '';
}

function isDefaultBranch(git) {
  return ['main', 'master'].includes(String(git?.branch || ''));
}

function gitHeadSubject(git) {
  return String(git?.head || '').replace(/^[0-9a-f]{7,40}\s+/, '');
}

function pullRequestNumberFromSubject(subject) {
  const match = String(subject || '').match(/\(#(\d+)\)\s*$/);
  return match ? Number(match[1]) : null;
}

function subjectWithoutPullRequestNumber(subject) {
  return String(subject || '').replace(/\s*\(#\d+\)\s*$/, '').trim();
}

function githubPullRequestUrlFromGit(git, number) {
  const repoUrl = git?.github_repo?.url;
  return repoUrl && number ? `${repoUrl}/pull/${number}` : '';
}

function pullRequestWithUrl(git, pr) {
  if (!pr?.number) return null;
  return {
    ...pr,
    url: pr.url || githubPullRequestUrlFromGit(git, pr.number),
  };
}

function defaultBranchHeadPullRequestForGit(info, git) {
  if (!isDefaultBranch(git)) return null;
  const subject = gitHeadSubject(git);
  const number = pullRequestNumberFromSubject(subject);
  if (!number) return null;
  const title = subjectWithoutPullRequestNumber(subject);
  const description = subjectWithoutPullRequestNumber(subject);
  return {
    number,
    title,
    description,
    url: githubPullRequestUrlFromGit(git, number),
    checks: {state: 'unknown'},
    // A (#NNNN) in the default branch's HEAD merge commit means that PR is, by definition, merged
    // (it is in main's history). Keep that fact semantic; shared lifecycle rendering localizes it.
    merged: true,
    source_only: true,
  };
}

function defaultBranchHeadPullRequest(info) {
  return defaultBranchHeadPullRequestForGit(info, sessionWorkSummary('', info).git);
}

function currentBranchInventoryPullRequestForGit(git) {
  const branches = git?.other_branches?.branches || [];
  return branches.find(branch => branch.current === true)?.pull_request || null;
}

function currentBranchInventoryPullRequest(info) {
  return currentBranchInventoryPullRequestForGit(sessionWorkSummary('', info).git);
}

function displayPullRequestForGit(info, git) {
  const summary = sessionWorkSummary('', info);
  if (summary.graphBacked) {
    const root = repoRootKey(git?.root);
    const repo = summary.repositories.find(item => repoRootKey(item.root) === root) || summary.selectedRepo;
    const branch = repo?.other_branches?.branches?.find(item => item.current) || null;
    return branch?.pull_requests?.[0] || null;
  }
  return null;
}

function displayPullRequest(info) {
  const summary = sessionWorkSummary('', info);
  return summary.graphBacked ? summary.focusedPullRequest : displayPullRequestForGit(info, summary.git);
}

function pullRequestAggregateLabel(pullRequests = []) {
  const count = Array.isArray(pullRequests) ? pullRequests.length : 0;
  return count > 1 ? tPlural('info.count.pr', count) : '';
}

function pullRequestSummaryBadgesHtml(session, info) {
  const summary = sessionWorkSummary(session, info);
  if (summary.graphBacked && summary.pullRequests.length > 1) {
    return `<span class="${metadataBadgeClasses(session, 'pr', 'pr-number-indicator tab-symbol pr-aggregate-indicator')}">${esc(pullRequestAggregateLabel(summary.pullRequests))}</span>`;
  }
  const pr = summary.graphBacked ? (summary.focusedPullRequest || displayPullRequestForGit(info, summary.git)) : displayPullRequest(info);
  return pullRequestCompactBadgesHtml(session, pr);
}

function metadataBadgePulseClass(session, badge) {
  if (!session) return '';
  const until = sessionStatusRecord(session)?.metadataBadgePulseUntil.get(badge);
  if (!until || until <= Date.now()) return '';
  return ' metadata-pulse';
}

function metadataBadgeClasses(session, badge, classes) {
  return `${classes}${metadataBadgePulseClass(session, badge)}`;
}

function updateMetadataBadgePulses(meta) {
  const now = Date.now();
  for (const record of sessionStatusRecords.values()) {
    for (const [badge, until] of record.metadataBadgePulseUntil.entries()) {
      if (until <= now) record.metadataBadgePulseUntil.delete(badge);
    }
  }
  for (const [session, info] of Object.entries(meta?.sessions || {})) {
    const pulses = info?.metadata_badge_pulse_remaining_ms || {};
    const pulseMap = sessionStatusRecord(session, true)?.metadataBadgePulseUntil;
    if (!pulseMap) continue;
    for (const badge of ['main', 'pr', 'status', 'ci']) {
      const remaining = Number(pulses[badge] || 0);
      if (remaining > 0) {
        pulseMap.set(badge, now + remaining);
      }
    }
  }
}

function defaultBranchBadgeHtml(session, info) {
  if (!isDefaultBranch(sessionWorkSummary(session, info).git)) return '';
  return `<span class="${metadataBadgeClasses(session, 'main', 'ci-indicator tab-symbol branch-indicator')}">MAIN</span>`;
}

function sessionWorkDescriptionSource(session, info) {
  const summary = sessionWorkSummary(session, info);
  const git = summary.git;
  if (summary.graphBacked && summary.pullRequests.length > 1) return pullRequestAggregateLabel(summary.pullRequests);
  const pr = summary.graphBacked ? (summary.focusedPullRequest || displayPullRequestForGit(info, git)) : displayPullRequest(info);
  if (pr?.number) {
    const title = pr.title || pr.description || '';
    const prefix = pullRequestLinkLabel(pr);
    return title ? `${prefix}: ${title}` : prefix;
  }
  const linear = summary.linearIssues;
  const issue = linear.find(item => item.title);
  if (issue) return `${issue.identifier}: ${issue.title}`;
  const subject = currentBranchSubject(git);
  if (subject) return subject;
  if (git?.branch) return shortBranch(git.branch);
  return projectDirName(session, info);
}

function sessionWorkDescription(session, info, limit = 96) {
  const description = sessionWorkDescriptionSource(session, info);
  return Number.isFinite(limit) && limit > 0 ? shortText(description, limit) : description;
}

function sessionTabDescription(session, info) {
  // A fresh Xterm can be fully interactive before transcript/repository metadata exists. Its tab
  // already identifies the session and tmux window, so a generic "Loading..." description implies
  // the terminal itself is blocked. Omit only this tab-local metadata until a real description arrives.
  if (!info) return '';
  const summary = sessionWorkSummary(session, info);
  if (summary.graphBacked && summary.pullRequests.length > 1) return pullRequestAggregateLabel(summary.pullRequests);
  const pr = summary.graphBacked ? (summary.focusedPullRequest || displayPullRequestForGit(info, summary.git)) : displayPullRequest(info);
  if (pr?.number) {
    const title = pr.title || pr.description || '';
    if (title) return shortText(title, 72);
  }
  return sessionWorkDescription(session, info, 72);
}

function tabMenuDetailText(item, info = transcriptMetadataState.payload.sessions?.[item]) {
  if (isInfoItem(item)) return t('tab.info.detail');
  const summary = sessionWorkSummary(item, info);
  const git = summary.git;
  const parts = [];
  if (git?.branch) parts.push(git.branch);
  const path = panelFullPath(item, info);
  if (path) parts.push(compactHomePath(path));
  const pr = displayPullRequest(info);
  const linear = summary.linearIssues.map(issue => issue.identifier).filter(Boolean).join(', ');
  if (linear) parts.push(linear);
  if (summary.graphBacked && summary.pullRequests.length > 1) parts.push(pullRequestAggregateLabel(summary.pullRequests));
  else if (pr?.number) {
    parts.push(pullRequestLinkLabel(pr));
  }
  const desc = sessionWorkDescription(item, info, 180);
  if (desc && !parts.includes(desc)) parts.push(desc);
  return parts.join(' · ') || itemLabel(item);
}

function projectDirName(session, info) {
  if (!info) return t('common.loading');
  const {gitRoot, gitCwd, selectedPath} = sessionTranscriptInfo(session);
  const repo = selectedSessionRepo(session, info);
  // Transcript/repository discovery can lag an already-connected terminal, especially for a
  // non-git shell. The live tmux signal is the owner of that pane's current directory, and the
  // existing terminalCurrentPath() helper already reconciles it with transcript metadata.
  const path = repo?.cwd || repo?.root || gitRoot || gitCwd || selectedPath || terminalCurrentPath(session);
  return pathBasename(path) || t('info.missing.path');
}

function pathBasename(path) {
  const text = String(path || '').replace(/\/+$/, '');
  if (!text) return '';
  const parts = text.split('/');
  return parts[parts.length - 1] || '';
}

function filePopoverHtml(item) {
  const path = fileItemPath(item);
  const state = openFiles.get(path) || {};
  const rows = filePopoverRows(path, state);
  return `<div class="session-popover file-popover" role="tooltip">
    <div class="popover-head">
      <div>
        <div class="popover-title">${esc(basenameOf(path))}</div>
      </div>
    </div>
    ${rows.join('')}
  </div>`;
}

function filePopoverRows(path, state = {}) {
  const kind = state.kind === 'image' ? t('popover.kind.image') : state.kind === 'text' ? t('popover.kind.text') : state.kind || t('popover.kind.file');
  const status = state.dirty ? t('state.modified') : state.loading ? t('common.loading') : state.error ? String(state.error) : kind;
  const rows = [
    popoverRow(t('common.field.path'), filePopoverPathHtml(path)),
  ];
  if (status && status !== kind) rows.push(popoverPairRow(t('popover.type'), esc(kind), t('popover.status'), esc(status)));
  else rows.push(popoverRow(t('popover.type'), esc(kind)));
  if (Number.isFinite(state.size)) rows.push(popoverRow(t('popover.size'), formatFileSize(state.size)));
  return rows;
}

function pathCopyButtonHtml(path, options = {}) {
  const className = ['path-copy-button', options.className || ''].filter(Boolean).join(' ');
  const dataAttr = options.dataAttr || 'data-copy-path';
  const title = options.title || t('contextmenu.copyPath');
  return `<button type="button" class="${esc(className)}" ${dataAttr}="${esc(path)}" title="${esc(title)}" aria-label="${esc(options.ariaLabel || title)}"></button>`;
}

function popoverCopyValueHtml(value, options = {}) {
  const text = String(value || '').trim();
  if (!text) return '';
  const copyLabel = options.title || t('common.copy');
  return `<span class="popover-copy-value">${esc(text)}</span>${pathCopyButtonHtml(text, {className: options.className || 'popover-copy-button', title: copyLabel, ariaLabel: options.ariaLabel || copyLabel})}`;
}

function filePopoverPathHtml(path) {
  return `<span class="popover-copy-value">${esc(path)}</span>${pathCopyButtonHtml(path, {className: 'popover-copy-button'})}`;
}

function sessionPopoverSubtitleHtml(session, info, fallback = '') {
  const summary = sessionWorkSummary(session, info);
  const git = summary.git;
  const pr = pullRequestWithUrl(git, displayPullRequest(info));
  const chips = [];
  if (isDefaultBranch(git)) chips.push(defaultBranchBadgeHtml(session, info));
  if (summary.graphBacked && summary.pullRequests.length > 1) chips.push(`<span class="popover-chip">${esc(pullRequestAggregateLabel(summary.pullRequests))}</span>`);
  else if (pr?.number) chips.push(pullRequestNumberChipLinkHtml(session, pr));
  const text = pr?.number
    ? shortText(pr.title || pr.description || '', 220)
    : String(fallback || '');
  const textHtml = text ? `<span class="popover-subtitle-text">${esc(text)}</span>` : '';
  return `<div class="popover-subtitle">${chips.join('')}${textHtml}</div>`;
}

function sessionBranchValueHtml(session, info) {
  const git = sessionWorkSummary(session, info).git;
  if (!git?.branch) return '';
  const branchHtml = isDefaultBranch(git)
    ? defaultBranchBadgeHtml(session, info)
    : branchLinkHtml(git, git.branch);
  return `${branchHtml}${git.upstream ? `<span class="meta-muted"> -> ${esc(git.upstream)}</span>` : ''}`;
}

function pullRequestPopoverRowHtml(session, pr) {
  const prParts = [pullRequestNumberChipLinkHtml(session, pr), pullRequestAuthorHtml(pr)].filter(Boolean);
  const checks = pullRequestChecksHtml(pr);
  if (checks) prParts.push(checks);
  const review = pullRequestReviewInlineHtml(pr);
  if (review) prParts.push(review);
  return metaJoin(prParts);
}

function gitStatusHasFacts(git) {
  return Number.isFinite(git?.dirty_count) || Number.isFinite(git?.ahead) || Number.isFinite(git?.behind);
}

function popoverActivityText(session, git) {
  const text = String(sessionActivitySummary(session)?.local || '').trim();
  if (!text) return '';
  return gitStatusHasFacts(git)
    ? text.replace(/\s*Status check:\s*[^.]+\.?\s*$/i, '').trim()
    : text;
}

function gitHeadValueHtml(git) {
  const head = String(git?.head || '').trim();
  const match = head.match(/^([0-9a-f]{7,40})\b/i);
  if (match) return esc(match[1]);
  return esc(shortText(subjectWithoutPullRequestNumber(gitHeadSubject(git)), 120));
}

function sessionPopoverAgentRecencyText(agent, nowSeconds = Date.now() / 1000, options = {}) {
  const lastActive = Number(agent?.idle_since || agent?.last_active_ts || 0);
  let timestamp = Number.isFinite(lastActive) && lastActive > 0 ? lastActive : nowSeconds;
  if (options.forceAgo === true && timestamp >= nowSeconds) timestamp = nowSeconds - 1;
  return sessionFileRelativeTimeText(timestamp, nowSeconds);
}

function sessionPopoverAgentStateText(agent, nowSeconds = Date.now() / 1000) {
  const state = String(agent?.state || STATE_KEY.idle);
  if (agentWindowIsWorkingState(state)) {
    const elapsed = Number(agent?.working_elapsed_seconds);
    return Number.isFinite(elapsed) && elapsed >= 0
      ? t('state.workingFor', {duration: compactElapsedDurationText(elapsed)})
      : stateDef(STATE_KEY.working).label;
  }
  if (agentWindowIsAttentionState(state)) return sessionPopoverAgentRecencyText(agent, nowSeconds, {forceAgo: true});
  const lastActive = Number(agent?.idle_since || agent?.last_active_ts || 0);
  return Number.isFinite(lastActive) && lastActive > 0 ? sessionPopoverAgentRecencyText(agent, nowSeconds) : stateDef(STATE_KEY.idle).label;
}

function sessionPopoverAgentStatusHtml(agent, nowSeconds = Date.now() / 1000, className = 'session-agent-status') {
  const text = sessionPopoverAgentStateText(agent, nowSeconds);
  if (agentWindowIsAttentionState(agent?.state)) return statusIndicatorLabelHtml(text, 'attention', className, 'agent-status-attention');
  return `<span class="${esc(className)}">${esc(text)}</span>`;
}

function tmuxSessionDescriptorLabel(label) {
  const text = String(label || '').trim();
  if (/^tmux\s+session\b/i.test(text)) return text;
  return t('common.tmuxSession', {label: text});
}

function tmuxWindowDescriptorLabel(label) {
  const text = String(label || '').trim();
  if (/^tmux\s+window\b/i.test(text)) return text;
  return t('popover.tmuxWindow', {label: text});
}

function sessionPopoverWindowPidByIndex(info) {
  if (typeof tmuxWindowRecords !== 'function') return new Map();
  return new Map(tmuxWindowRecords(info?.panes || [])
    .map(record => [tmuxWindowIndexKey(record.index ?? record.indexText), record.pid])
    .filter(([index, pid]) => index !== null && Number.isFinite(Number(pid)) && Number(pid) > 0));
}

function sessionPopoverAgentWindowPid(agent, pidByIndex) {
  const directPid = Number(agent?.pid || agent?.process_label_pid || 0);
  if (Number.isFinite(directPid) && directPid > 0) return Math.floor(directPid);
  const index = agentWindowIndex(agent);
  const sharedPid = index !== null ? Number(pidByIndex.get(index)) : null;
  if (Number.isFinite(sharedPid) && sharedPid > 0) return Math.floor(sharedPid);
  return null;
}

function sessionPopoverActiveWindowIndex(session, info) {
  if (typeof tmuxWindowCurrentActiveIndex === 'function') return tmuxWindowCurrentActiveIndex(session, info);
  const active = typeof tmuxWindowInfoActiveIndex === 'function' ? tmuxWindowInfoActiveIndex(info) : null;
  if (active !== null) return active;
  const pane = info?.selected_pane || null;
  return tmuxWindowIndexKey(pane?.window ?? pane?.window_index);
}

function sessionPopoverSortedAgentWindows(session, info, autoPayload) {
  const activeWindowIndex = sessionPopoverActiveWindowIndex(session, info);
  const pidByIndex = sessionPopoverWindowPidByIndex(info);
  return sessionAgentWindowStatusPayloads(session, info, autoPayload)
    .map((agent, index) => ({
      ...agent,
      _session: session,
      _index: index,
      kind: String(agent?.kind || '').toLowerCase(),
      state: String(agent?.state || STATE_KEY.idle),
      current: typeof agentWindowPayloadCurrent === 'function' && agentWindowPayloadCurrent(agent) !== null
        ? agentWindowPayloadCurrent(agent) === true
        : activeWindowIndex !== null && agentWindowIndex(agent) === activeWindowIndex,
      pid: sessionPopoverAgentWindowPid(agent, pidByIndex),
    }))
    .filter(agent => ['claude', 'codex'].includes(agent.kind))
    .sort((left, right) => agentWindowStateRank(left.state) - agentWindowStateRank(right.state)
      || Number(left.window_index ?? 9999) - Number(right.window_index ?? 9999)
      || left._index - right._index);
}

function sessionPopoverAgentWindowRowHtml(agent, nowSeconds = Date.now() / 1000) {
  const working = agentWindowIsWorkingState(agent.state);
  const attention = agentWindowIsAttentionState(agent.state);
  const descriptor = tmuxWindowDescriptorLabel(agentWindowCanonicalLabel(agent.window_index ?? agent.window, agent.kind, agent.window_label || agent.kind));
  const label = typeof tmuxWindowDisplayLabel === 'function' ? tmuxWindowDisplayLabel(descriptor, agent.pid) : descriptor;
  const classes = ['session-agent-row', `state-${agent.state}`];
  if (working) classes.push('working');
  if (attention) classes.push('attention');
  if (agent.current === true) classes.push('current');
  // Match the tmux-window button and attention toast: the state glyph (play/stop/pause)
  // comes before the stable Claude/Codex identity everywhere a sub-window is shown.
  const activityHtml = agentWindowActivityIconHtmlForStatus(agent, agent.kind, agent._session || '', {statusBeforeAgent: true});
  return `<div class="${esc(classes.join(' '))}">
    <span class="session-agent-kind">${activityHtml}</span>${esc(label)}
    <span class="session-agent-sep">—</span>
    ${sessionPopoverAgentStatusHtml(agent, nowSeconds)}
  </div>`;
}

function sessionPopoverWindowMetadataItems(session, info, agentRows) {
  const agents = Array.isArray(agentRows) ? agentRows : [];
  if (!agents.length) return [];
  return agents.map(agent => {
    const pathEntries = typeof agentWindowPathEntries === 'function' ? agentWindowPathEntries(agent) : [];
    const paths = pathEntries.map(item => item.path).filter(Boolean);
    const git = typeof agentWindowPrimaryGit === 'function' ? agentWindowPrimaryGit(agent) : (agent?.git || null);
    const path = paths[0] || (typeof agentWindowPrimaryPath === 'function' ? agentWindowPrimaryPath(agent) : String(agent?.path || ''));
    const meta = {
      window: String(agent?.window ?? ''),
      window_index: agentWindowIndex(agent),
      window_name: String(agent?.window_name || ''),
      path,
      paths,
      path_entries: pathEntries,
      git,
    };
    const html = windowMetadataRowsHtml(meta);
    return html ? {agent, meta, html} : null;
  }).filter(Boolean);
}

function sessionPopoverAgentWindowHtml(session, info, autoPayload, agentRows = null, metadataItems = null) {
  const agents = Array.isArray(agentRows) ? agentRows : sessionPopoverSortedAgentWindows(session, info, autoPayload);
  if (!agents.length) {
    return `<div class="session-agent-list empty"><div class="session-agent-empty">${esc(t('yoagent.emptyPerSession'))}</div></div>`;
  }
  const nowSeconds = Date.now() / 1000;
  const items = Array.isArray(metadataItems) ? metadataItems : sessionPopoverWindowMetadataItems(session, info, agents);
  const metadataByWindow = new Map(items.map(item => [agentWindowIndex(item.agent), item]));
  const sharedMetadata = items.length > 1 && items.length === agents.length && new Set(items.map(item => sessionWindowMetadataSignature(item.meta))).size === 1;
  const rows = agents.map(agent => {
    const row = sessionPopoverAgentWindowRowHtml(agent, nowSeconds);
    const item = metadataByWindow.get(agentWindowIndex(agent));
    const transcriptHtml = agentTranscriptRowsHtml(agent);
    if ((!item || sharedMetadata) && !transcriptHtml) return row;
    const metadataHtml = item && !sharedMetadata ? item.html : '';
    return `<div class="session-agent-window-block">${row}<div class="session-window-metadata">${metadataHtml}${transcriptHtml}</div></div>`;
  }).join('');
  const sharedRows = sharedMetadata ? `<div class="session-window-metadata-list shared">${items[0].html}</div>` : '';
  const metadataClass = items.length ? ' has-window-metadata' : '';
  return `<div class="session-agent-list${metadataClass}">${rows}${sharedRows}</div>`;
}

function sessionWindowMetadataSignature(row) {
  const git = row?.git || {};
  const paths = Array.isArray(row?.paths) ? row.paths.join('\u0001') : (row?.path || '');
  return [paths, git.root || '', git.branch || '', git.worktree?.path || ''].join('\u0000');
}

function windowMetadataBranchHtml(git) {
  if (!git?.branch) return '';
  return `${branchLinkHtml(git, git.branch)}${git.upstream ? `<span class="meta-muted"> -> ${esc(git.upstream)}</span>` : ''}`;
}

function worktreePopoverValueHtml(worktree) {
  return esc(worktreeDisplayText(worktree));
}

function windowMetadataRowsHtml(row) {
  if (!row) return '';
  const git = row.git || {};
  const rows = [];
  const paths = Array.isArray(row.paths) ? row.paths.map(path => String(path || '').trim()).filter(Boolean) : [];
  const displayPaths = paths.length ? paths : (row.path ? [String(row.path)] : []);
  for (const path of displayPaths) rows.push(popoverRow(t('common.field.path'), filePopoverPathHtml(path)));
  if (git.branch) rows.push(popoverRow(t('common.field.branch'), windowMetadataBranchHtml(git)));
  if (git.root && !displayPaths.includes(git.root)) rows.push(popoverRow(t('popover.repo'), git.root));
  if (git.worktree) rows.push(popoverRow(t('popover.worktree'), worktreePopoverValueHtml(git.worktree)));
  if (git.head) rows.push(popoverRow('HEAD', gitHeadValueHtml(git)));
  if (gitStatusHasFacts(git)) rows.push(popoverRow(t('popover.git'), gitStatusText(git)));
  return rows.join('');
}

function agentTranscriptId(agent) {
  const direct = String(agent?.transcript_id || agent?.agent_session_id || agent?.session_id || '').trim();
  if (direct) return direct;
  const transcript = String(agent?.transcript || '').trim();
  if (!transcript) return '';
  return basenameOf(transcript).replace(/\.[^.]+$/, '');
}

function agentTranscriptRowsHtml(agent) {
  const transcript = String(agent?.transcript || '').trim();
  if (!transcript) return '';
  const transcriptId = agentTranscriptId(agent);
  const rows = [];
  if (transcriptId) rows.push(popoverRow(t('popover.sessionId'), popoverCopyValueHtml(transcriptId, {title: t('popover.copySessionId')})));
  rows.push(popoverRow(t('common.transcript'), popoverCopyValueHtml(transcript, {title: t('common.copyTranscriptPath')})));
  return rows.join('');
}

function sessionPopoverHtml(session, info, agentKind, autoEnabled, state = sessionState(session, info)) {
  const summary = sessionWorkSummary(session, info);
  const git = summary.git;
  const pr = pullRequestWithUrl(git, displayPullRequest(info));
  const linear = summary.linearIssues;
  const pane = info?.selected_pane;
  const description = sessionWorkDescription(session, info, 220);
  const title = `${tmuxSessionDescriptorLabel(sessionLabel(session))} · ${projectDirName(session, info)}`;
  const subtitle = description || git?.branch || pane?.current_path || t('git.noCheckout');
  const subtitleHtml = sessionPopoverSubtitleHtml(session, info, subtitle);
  const rows = [];
  const stateValue = `${sessionStateHtml(state)} <span class="meta-muted">${esc(state.reason)}</span>`;
  const autoPayload = autoApproveStates.get(session);
  const autoElsewhere = autoApproveEnabledElsewhere(autoPayload);
  const autoText = autoEnabled ? t('yolo.on') : (autoElsewhere ? t('yolo.elsewhere') : '');
  const agentValue = agentKind
    ? `${agentName(agentKind)}${autoText ? ` · ${autoText}` : ''}`
    : (autoText || `<span data-locale-text-key="agent.notDetected">${esc(t('agent.notDetected'))}</span>`);
  const displayPath = panelFullPath(session, info) || pane?.current_path || t('common.notAvailable');
  const agentRows = sessionPopoverSortedAgentWindows(session, info, autoPayload);
  const windowMetadataItems = sessionPopoverWindowMetadataItems(session, info, agentRows);
  const agentWindowsHtml = sessionPopoverAgentWindowHtml(session, info, autoPayload, agentRows, windowMetadataItems);
  const perWindowMetadata = Boolean(windowMetadataItems.length);
  if (!perWindowMetadata) rows.push(popoverPairRow(t('common.stateLabel'), stateValue, t('common.agentLabel'), agentValue));
  const activityText = popoverActivityText(session, git);
  if (activityText) rows.push(popoverRow(yoagentTabLabel(), esc(activityText)));
  if (!perWindowMetadata) {
    rows.push(popoverRow(t('common.field.path'), displayPath));
    if (git?.branch) rows.push(popoverRow(t('common.field.branch'), sessionBranchValueHtml(session, info)));
  }
  let linearValue = '';
  let linearDesc = '';
  if (linear.length) {
    linearValue = linearInlineHtml(linear);
    linearDesc = linearDescriptionsInlineHtml(linear);
    if (linearValue) rows.push(popoverRow(t('info.field.linear'), linearValue));
    if (linearDesc) rows.push(popoverRow(t('common.details'), linearDesc));
  }
  if (pr?.number) {
    rows.push(popoverRow(t('common.pullRequestShort'), pullRequestPopoverRowHtml(session, pr)));
  }
  const subject = currentBranchSubject(git);
  if (subject && !pr?.number) rows.push(popoverRow(t('common.descriptionShort'), `<div class="popover-desc">${esc(subject)}</div>`));
  if (!perWindowMetadata && git?.root && git.root !== displayPath) rows.push(popoverRow(t('popover.repo'), git.root));
  // S7: name a linked worktree vs its parent repo so the focused path isn't mistaken for the main checkout.
  if (!perWindowMetadata && git?.worktree) rows.push(popoverRow(t('popover.worktree'), worktreePopoverValueHtml(git.worktree)));
  if (!perWindowMetadata && git?.head) rows.push(popoverRow('HEAD', gitHeadValueHtml(git)));
  if (!perWindowMetadata && gitStatusHasFacts(git)) rows.push(popoverRow(t('popover.git'), gitStatusText(git)));
  return `<div class="session-popover" role="tooltip">
    <div class="popover-head">
      <div>
        <div class="popover-title">${esc(title)}</div>
        ${subtitleHtml}
      </div>
    </div>
    ${agentWindowsHtml}
    ${rows.join('')}
    ${otherBranchesHtml(session, info)}
  </div>`;
}

function popoverRow(label, valueHtml) {
  return `<div class="popover-row"><div class="popover-label">${esc(label)}</div><div class="popover-value">${stripTitleAttrs(valueHtml)}</div></div>`;
}

function popoverPairRow(leftLabel, leftValueHtml, rightLabel, rightValueHtml) {
  return `<div class="popover-row compact">
    <div class="popover-label">${esc(leftLabel)}</div><div class="popover-value">${stripTitleAttrs(leftValueHtml)}</div>
    <div class="popover-label">${esc(rightLabel)}</div><div class="popover-value">${stripTitleAttrs(rightValueHtml)}</div>
  </div>`;
}

function stripTitleAttrs(html) {
  return String(html || '').replace(/\s+title=(?:"[^"]*"|'[^']*'|[^\s>]+)/g, '');
}

function linearInlineHtml(issues) {
  const parts = [];
  for (const issue of issues || []) {
    const label = issue.identifier || '';
    if (!label) continue;
    const link = linkHtml(issue.url, label, issue.title || '');
    if (!link) continue;
    const state = issue.state ? `<span class="meta-muted"> ${esc(issue.state)}</span>` : '';
    parts.push(`${link}${state}`);
  }
  return metaJoin(parts);
}

function linearDescriptionsInlineHtml(issues) {
  const parts = [];
  for (const issue of issues || []) {
    if (!issue?.title) continue;
    const prefix = issue.identifier ? `${issue.identifier} ` : '';
    parts.push(`${prefix}${issue.title}`);
  }
  return parts.length ? esc(shortText(parts.join(' · '), 180)) : '';
}

function gitStatusText(git) {
  const parts = [];
  if (Number.isFinite(git.dirty_count)) parts.push(t('git.dirty', {count: git.dirty_count}));
  if (Number.isFinite(git.ahead) && git.ahead > 0) parts.push(t('git.ahead', {count: git.ahead}));
  if (Number.isFinite(git.behind) && git.behind > 0) parts.push(t('git.behind', {count: git.behind}));
  return esc(parts.length ? parts.join(' · ') : t('git.clean'));
}

function branchLinkHtml(git, branchName) {
  return esc(branchName || '');
}

function linearIssueHtml(issue) {
  const label = `${issue.identifier}${issue.state ? ` ${issue.state}` : ''}`;
  return linkHtml(issue.url, label, issue.title || '');
}

function linearIssueUrl(identifier) {
  const id = String(identifier || '').trim();
  if (!id || !linearIssueBaseUrl) return '';
  return `${linearIssueBaseUrl}/${encodeURIComponent(id)}`;
}

function linearIssueLinkHtml(identifier) {
  if (!identifier) return '';
  return linkHtml(linearIssueUrl(identifier), identifier, identifier);
}

function pullRequestLinkForBranch(git, branch) {
  const pr = branch?.pull_request;
  const repoUrl = git?.github_repo?.url;
  if (!pr?.number) return '';
  const url = pr.url || (repoUrl ? `${repoUrl}/pull/${pr.number}` : '');
  return linkHtml(url, pullRequestLinkLabel(pr), pr.title || pr.description || branch.subject || '', pullRequestStatusClass(pr));
}

function pullRequestNumberChipLinkHtml(session, pr) {
  if (!pr?.number) return '';
  const chip = pullRequestNumberIndicatorHtml(session, pr);
  if (!pr.url) return chip;
  const title = pr.title || pr.description || '';
  const titleAttr = title ? ` title="${esc(title)}"` : '';
  return `<a href="${esc(pr.url)}" target="_blank" rel="noreferrer noopener" draggable="false"${titleAttr} class="popover-chip-link">${chip}</a>`;
}

function pullRequestForBranch(git, branch, info) {
  const pr = branch?.current ? displayPullRequest(info) || branch.pull_request : branch?.pull_request;
  return pullRequestWithUrl(git, pr);
}

function branchListBranchHtml(session, git, branch) {
  const branchName = branch?.name || '';
  if (isDefaultBranch({branch: branchName})) {
    const classes = branch?.current
      ? metadataBadgeClasses(session, 'main', 'ci-indicator tab-symbol branch-indicator')
      : 'ci-indicator tab-symbol branch-indicator';
    return `<span class="${esc(classes)}">MAIN</span>`;
  }
  return branchLinkHtml(git, branchName);
}

function normalizeBranchSubjectText(value) {
  return subjectWithoutPullRequestNumber(value).replace(/\s+/g, ' ').trim().toLowerCase();
}

function branchListSubjectHtml(branch, pr) {
  const subject = subjectWithoutPullRequestNumber(branch?.subject || '');
  if (!subject) return '';
  if (branch?.current) {
    // A default-branch merge commit title retains its SHA in canonical PR data while the local
    // branch subject does not. Treat the SHA-free title as the same description.
    const currentTitles = [pr?.title, pr?.description]
      .flatMap(value => {
        const normalized = normalizeBranchSubjectText(value);
        return [normalized, normalized.replace(/^[0-9a-f]{7,40}\s+/i, '')].filter(Boolean);
      });
    if (currentTitles.includes(normalizeBranchSubjectText(subject))) return '';
  }
  return `<div class="branch-subject">${esc(shortText(subject, 240))}</div>`;
}

function branchPullRequestMetaHtml(session, pr) {
  if (!pr?.number) return '';
  const parts = [pullRequestNumberChipLinkHtml(session, pr)];
  const status = pullRequestInlineStatusDisplay(pr);
  if (status) parts.push(pullRequestStatusBadgeHtml('', status, pullRequestStatusClass(pr), {variant: 'meta'}));
  return metaJoin(parts);
}

function pullRequestTextForBranch(pr, fallback = '') {
  if (!pr?.number) return '';
  return [pullRequestLinkLabel(pr), pr.title || pr.description || fallback].filter(Boolean).join(' ');
}

function branchUpdatedText(branch) {
  const ts = Number(branch?.updated_ts || 0);
  if (Number.isFinite(ts) && ts > 0) {
    const seconds = Math.max(0, Math.floor(Date.now() / 1000) - ts);
    return relativeTimeFormat(seconds);
  }
  return branch?.updated || '';
}

function otherBranchesHtml(session, info) {
  const git = sessionWorkSummary(session, info).git;
  const inventory = git?.other_branches || {};
  const branches = inventory.branches || [];
  if (!branches.length) {
    return `<div class="branch-list"><div class="branch-list-title">${esc(t('branch.all'))}</div><div class="meta-muted">${esc(t('branch.none'))}</div></div>`;
  }
  const items = branches.map(branch => {
    const pr = pullRequestForBranch(git, branch, info);
    const branchLink = branchListBranchHtml(session, git, branch);
    const prLink = branchPullRequestMetaHtml(session, pr);
    const linearLinks = (branch.linear_ids || []).map(linearIssueLinkHtml).filter(Boolean).join(' ');
    const meta = [prLink, linearLinks, esc(branchUpdatedText(branch))].filter(Boolean).join(' ');
    return `<div class="branch-item">
      <div class="branch-name">${branchLink}</div>
      <div class="branch-meta">${meta}</div>
      ${branchListSubjectHtml(branch, pr)}
    </div>`;
  }).join('');
  const hidden = Number(inventory.hidden_count || 0) > 0
    ? `<div class="meta-muted">${esc(t('branch.more', {count: inventory.hidden_count}))}</div>`
    : '';
  return `<div class="branch-list"><div class="branch-list-title">${esc(t('branch.all'))}</div>${items}${hidden}</div>`;
}

function dragPayload(event) {
  const raw = event.dataTransfer?.getData('application/x-yolomux-session') || '';
  if (!raw && dragState.paneSlot) return null;
  if (!raw && dragState.item) return {session: dragState.item, sourceSlot: dragState.sourceSlot};
  if (!raw) return null;
  try {
    const parsed = JSON.parse(raw);
    return isLayoutItem(parsed.session) ? parsed : null;
  } catch (_) {
    return isLayoutItem(raw) ? {session: raw, sourceSlot: null} : null;
  }
}

function paneDragPayload(event) {
  const raw = event.dataTransfer?.getData('application/x-yolomux-pane') || '';
  if (!raw && dragState.paneSlot) return {slot: dragState.paneSlot};
  if (!raw) return null;
  try {
    const parsed = JSON.parse(raw);
    return layoutSlotKeys().includes(parsed.slot) ? parsed : null;
  } catch (_) {
    return layoutSlotKeys().includes(raw) ? {slot: raw} : null;
  }
}

function normalizeFileDragPayload(parsed) {
  if (!parsed?.path && !Array.isArray(parsed?.paths)) return null;
  const paths = Array.isArray(parsed.paths) ? parsed.paths.filter(Boolean) : [parsed.path].filter(Boolean);
  return paths.length ? {...parsed, path: parsed.path || paths[0], paths} : null;
}

function parseFileDragPayload(raw) {
  if (!raw) return null;
  try {
    return normalizeFileDragPayload(JSON.parse(raw));
  } catch (_) {
    return null;
  }
}

function hasYolomuxFileDrag(event) {
  return Array.from(event.dataTransfer?.types || []).includes('application/x-yolomux-file');
}

function fileDragPayload(event) {
  const raw = event.dataTransfer?.getData('application/x-yolomux-file') || '';
  return parseFileDragPayload(raw) || (hasYolomuxFileDrag(event) ? dragState.filePayload : null);
}

async function openDraggedFilesInEditor(payload, options = {}) {
  const paths = Array.from(new Set((payload?.paths || [payload?.path]).filter(Boolean)));
  if (!paths.length) return;
  let opened = 0;
  for (const [index, path] of paths.entries()) {
    try {
      const info = await fetchFilePathInfo(path);
      if (info.kind !== 'file') continue;
      await openFileInEditor(path, info, {
        forceNewTab: true,
        targetSlot: options.targetSlot || null,
        targetZone: options.targetZone || 'middle',
        targetIndex: options.targetIndex == null ? null : Number(options.targetIndex) + index,
        rehomeExisting: true,
      });
      // Unify with double-click: a dragged CHANGED (tracked, has-diff) file opens in the SAME diff
      // view (ensureCodeMirrorDiffPanel) as openChangedFileInDiff, not a plain edit-mode editor.
      // Files with no diff payload stay in edit.
      await refreshOpenFileDiff(path, {silent: true});
      const draggedState = openFiles.get(path);
      if (draggedState && openFileDiffAvailable(draggedState)) {
        setFileEditorViewMode(path, 'diff', fileEditorItemFor(path));
        for (const draggedPanel of fileEditorPanelsForPath(path)) {
          renderFileEditorPanel(draggedPanel, draggedPanel.dataset.layoutItem || fileEditorItemFor(path));
        }
      }
      // #260: a drag-drop open is a FRESH open at the current disk state, not a "changed on disk"
      // conflict. If the just-opened file is NOT dirty, clear any external-change flags so it never
      // pops a spurious reload prompt (this matches double-click's openChangedFileInDiff, which opens
      // with a clean baseline). A dirty file keeps its conflict state so real unsaved-edit warnings stay.
      if (draggedState && !draggedState.dirty) {
        delete draggedState.externalChanged;
        clearOpenFileMissingState(draggedState);
        delete draggedState.externalError;
        delete draggedState.externalChangeEditPrompted;
        renderOpenFilePath(path);
      }
      opened += 1;
    } catch (error) {
      showFileOpenError(path, error);
    }
  }
  if (opened) statusOk(esc(tPlural('status.openedFiles', opened, {name: basenameOf(paths[0])})));
}

function terminalCurrentPath(session) {
  const signalPath = tmuxSignalPanePathForSession(session);
  if (signalPath) return signalPath;
  const info = transcriptMetadataState.payload.sessions?.[session];
  return terminalDisplayPane(info, session)?.current_path || info?.selected_pane?.current_path || '';
}

function pathRelativeToDirectory(path, directory) {
  const fullPath = String(path || '');
  const rawBase = String(directory || '');
  const base = rawBase === '/' ? '/' : rawBase.replace(/\/+$/, '');
  if (!fullPath || !base || !fullPath.startsWith('/')) return fullPath;
  if (fullPath === base) return '.';
  if (base === '/') return fullPath.slice(1);
  if (!fullPath.startsWith(`${base}/`)) return fullPath;
  return fullPath.slice(base.length + 1);
}

function terminalFileReference(session, path) {
  return pathRelativeToDirectory(path, terminalCurrentPath(session));
}

function terminalFileReferences(session, payload) {
  const paths = Array.isArray(payload?.paths) ? payload.paths : [payload?.path].filter(Boolean);
  return paths.map(path => terminalFileReference(session, path));
}

function transparentNativeDragImage() {
  if (dragState.transparentImage) return dragState.transparentImage;
  const node = document.createElement('div');
  node.className = 'transparent-drag-image';
  document.body.appendChild(node);
  dragState.transparentImage = node;
  return node;
}

function clearNativeDragImagePreview() {
  dragState.nativePreview?.remove?.();
  dragState.nativePreview = null;
}

function beginFileDrag(payloadObject) {
  dragState.item = null;
  dragState.sourceSlot = null;
  dragState.paneSlot = null;
  dragState.tabRectCache = null;
  clearNativeDragImagePreview();
  dragState.filePayload = normalizeFileDragPayload(payloadObject);
  return dragState.filePayload;
}

function moveCustomDragPreview(event) {
  if (!dragState.customPreview || !Number.isFinite(event.clientX) || !Number.isFinite(event.clientY)) return;
  dragState.customPreview.style.left = `${Math.round(event.clientX - dragState.customPreviewOffset.x)}px`;
  dragState.customPreview.style.top = `${Math.round(event.clientY - dragState.customPreviewOffset.y)}px`;
}

const customDragPreviewCleanupEvents = ['drop', 'dragend', 'pointerup', 'mouseup', 'blur', 'visibilitychange'];

function customDragPreviewEventTargets() {
  return [document, window].filter(Boolean);
}

function bindCustomDragPreviewListeners() {
  for (const target of customDragPreviewEventTargets()) {
    target.addEventListener?.('dragover', moveCustomDragPreview, true);
    target.addEventListener?.('drag', moveCustomDragPreview, true);
    for (const eventName of customDragPreviewCleanupEvents) {
      target.addEventListener?.(eventName, cancelDragOperationState, true);
    }
  }
}

function unbindCustomDragPreviewListeners() {
  for (const target of customDragPreviewEventTargets()) {
    target.removeEventListener?.('dragover', moveCustomDragPreview, true);
    target.removeEventListener?.('drag', moveCustomDragPreview, true);
    for (const eventName of customDragPreviewCleanupEvents) {
      target.removeEventListener?.(eventName, cancelDragOperationState, true);
    }
  }
}

function stopCustomDragPreview() {
  unbindCustomDragPreviewListeners();
  dragState.customPreview?.remove();
  dragState.customPreview = null;
  closeFileImagePreview();
}

function cancelDragOperationState() {
  dragState.item = null;
  dragState.sourceSlot = null;
  dragState.paneSlot = null;
  dragState.filePayload = null;
  dragState.tabRectCache = null;
  clearNativeDragImagePreview();
  stopCustomDragPreview();
  clearDropPreview();
}

function paneDragPreviewMetrics(slot, event) {
  const rect = layoutSlotScreenRect(slot);
  const fallbackWidth = 360;
  const fallbackHeight = 220;
  const sourceWidth = Math.max(1, Number(rect?.width) || fallbackWidth);
  const sourceHeight = Math.max(1, Number(rect?.height) || fallbackHeight);
  const viewport = appViewport();
  const viewportWidth = effectiveViewportWidth(viewport);
  const viewportHeight = Math.max(240, Number(viewport.height) || 800);
  const maxWidth = Math.min(720, Math.max(220, viewportWidth * 0.64));
  const maxHeight = Math.min(420, Math.max(160, viewportHeight * 0.58));
  const scale = Math.min(1, maxWidth / sourceWidth, maxHeight / sourceHeight);
  const width = Math.max(180, Math.round(sourceWidth * scale));
  const height = Math.max(120, Math.round(sourceHeight * scale));
  const sourceOffsetX = rect ? (Number(event?.clientX) || rect.left) - rect.left : width * 0.12;
  const sourceOffsetY = rect ? (Number(event?.clientY) || rect.top) - rect.top : 18;
  return {
    width,
    height,
    offsetX: Math.max(16, Math.min(width - 16, Math.round(sourceOffsetX * scale))),
    offsetY: Math.max(16, Math.min(height - 16, Math.round(sourceOffsetY * scale))),
  };
}

function paneDragPreviewHtml(slot) {
  const tabs = paneTabs(slot);
  const active = activeItemForSide(slot) || tabs[0] || slot;
  const title = itemLabel(active);
  const count = tabs.length;
  const extra = tabs
    .filter(item => item !== active)
    .slice(0, 3)
    .map(item => `<span>${esc(itemLabel(item))}</span>`)
    .join('');
  return `
    <div class="pane-drag-image-frame">
      <div class="pane-drag-image-title">${esc(title)}</div>
      <div class="pane-drag-image-meta">${esc(tPlural('common.tabs', count))}</div>
      ${extra ? `<div class="pane-drag-image-tabs">${extra}</div>` : ''}
    </div>`;
}

function startPaneDragPreview(event, slot, options = {}) {
  stopCustomDragPreview();
  const metrics = paneDragPreviewMetrics(slot, event);
  const preview = document.createElement('div');
  preview.className = 'pane-drag-image drag-image';
  preview.dataset.dragSlot = slot;
  preview.innerHTML = paneDragPreviewHtml(slot);
  preview.style.position = 'fixed';
  preview.style.pointerEvents = 'none';
  preview.style.zIndex = '99999';
  preview.style.width = `${metrics.width}px`;
  preview.style.height = `${metrics.height}px`;
  document.body.appendChild(preview);
  dragState.customPreview = preview;
  dragState.customPreviewOffset = {x: metrics.offsetX, y: metrics.offsetY};
  moveCustomDragPreview(event);
  if (options.nativeDrag === true) {
    bindCustomDragPreviewListeners();
    preview.getBoundingClientRect();
    event.dataTransfer?.setDragImage?.(transparentNativeDragImage(), 0, 0);
  }
}

// #47: tab drags use the native drag image (see startSessionDrag) — the clone-follow tab preview is
// gone. The custom-preview machinery below is retained only for the rich FILE drag preview.
function startFileDragPreview(event, paths, entry) {
  stopCustomDragPreview();
  const normalizedPaths = Array.from(new Set((paths || []).filter(Boolean)));
  const firstPath = normalizedPaths[0] || '';
  const preview = document.createElement('div');
  preview.className = 'file-drag-image drag-image';
  const title = normalizedPaths.length === 1 ? basenameOf(firstPath) : t('common.items', {count: normalizedPaths.length});
  const pathRows = normalizedPaths.slice(0, 4)
    .map(path => `<div class="file-drag-path">${esc(path)}</div>`)
    .join('');
  const more = normalizedPaths.length > 4 ? `<div class="file-drag-more">${esc(t('common.more', {count: normalizedPaths.length - 4}))}</div>` : '';
  preview.innerHTML = `
    <div class="file-drag-main">
      ${fileDragPreviewMedia(firstPath, entry)}
      <div class="file-drag-copy">
        <div class="file-drag-title">${esc(title)}</div>
        ${pathRows}${more}
      </div>
    </div>`;
  preview.style.position = 'fixed';
  preview.style.pointerEvents = 'none';
  preview.style.zIndex = '99999';
  document.body.appendChild(preview);
  dragState.customPreview = preview;
  dragState.customPreviewOffset = {x: -14, y: -14};
  moveCustomDragPreview(event);
  bindCustomDragPreviewListeners();
  preview.getBoundingClientRect();
  event.dataTransfer?.setDragImage?.(transparentNativeDragImage(), 0, 0);
}

function fileDragPreviewMedia(path, entry) {
  const kind = entry?.kind || 'file';
  if (kind === 'file' && previewMediaKindForPath(path) === 'image') {
    return `<img class="file-drag-thumb" src="${rawFileUrl(path)}" alt="">`;
  }
  const icon = kind === 'dir' ? disclosureTriangleCollapsedGlyph : '📄';
  return `<span class="file-drag-thumb file-drag-icon" aria-hidden="true">${icon}</span>`;
}

// S14: OPT-IN tab-drag timing to diagnose the ~500ms first-drag delay without guessing. Off by
// default (no permanent user-visible perf log). Enable by setting storage key 'yolomux.debugDragTiming' to
// '1' (via storageSet in the console), drag a tab, then read the per-bucket console.table at drop. Marks
// the buckets the DOIT calls out: pointerdown -> dragstart/startSessionDrag (begin/end) -> first dragover
// -> first dragMeasureStrip / paneTabDropPlacement. dragTimingMarkOnce dedups the repeating measure calls.
let dragTimingMarks = null;
const dragTimingSeen = new Set();
function dragTimingEnabled() {
  return storageGet('yolomux.debugDragTiming') === '1';
}
function dragTimingReset() {
  dragTimingSeen.clear();
  dragTimingMarks = dragTimingEnabled() ? [] : null;
}
function dragTimingMark(label) {
  if (dragTimingMarks) dragTimingMarks.push({label, t: performance.now()});
}
function dragTimingMarkOnce(label) {
  if (dragTimingMarks && !dragTimingSeen.has(label)) { dragTimingSeen.add(label); dragTimingMark(label); }
}
function dragTimingReport() {
  if (dragTimingMarks && dragTimingMarks.length >= 2) {
    const first = dragTimingMarks[0].t;
    const rows = dragTimingMarks.map((mark, i) => ({
      mark: mark.label,
      deltaMs: i ? Number((mark.t - dragTimingMarks[i - 1].t).toFixed(1)) : 0,
      sinceStartMs: Number((mark.t - first).toFixed(1)),
    }));
    console.table(rows);
    showDragTimingOverlay(rows);   // copyable on-page readout — no DevTools needed
  }
  dragTimingMarks = null;
  dragTimingSeen.clear();
}

// S14: render the last drag's timing into a fixed, click-to-select-all box so it can be
// copy-pasted (or screenshotted) back without opening DevTools. Created lazily; only the flag-gated
// dragTimingReport calls it, so it never appears in normal use.
function showDragTimingOverlay(rows) {
  let el = document.getElementById('drag-timing-overlay');
  if (!el) {
    el = document.createElement('pre');
    el.id = 'drag-timing-overlay';
    el.className = 'drag-timing-overlay';
    el.title = t('debug.dragTimingTitle');
    el.addEventListener('click', () => {
      const range = document.createRange();
      range.selectNodeContents(el);
      const selection = window.getSelection();
      selection.removeAllRanges();
      selection.addRange(range);
    });
    document.body.appendChild(el);
  }
  const width = Math.max(...rows.map(row => row.mark.length));
  el.textContent = ['drag timing (ms) — click to select, copy, paste back:',
    ...rows.map(row => `${row.mark.padEnd(width)}  +${String(row.deltaMs).padStart(7)}  total ${String(row.sinceStartMs).padStart(7)}`)].join('\n');
}

function startSessionDrag(event, session, sourceSlot = null, options = {}) {
  dragTimingMark('startSessionDrag:begin');
  clearNativeDragImagePreview();
  dragState.item = session;
  dragState.sourceSlot = sourceSlot;
  dragState.paneSlot = null;
  dragState.filePayload = null;
  const payload = JSON.stringify({session, sourceSlot});
  event.dataTransfer.effectAllowed = 'move';
  event.dataTransfer.setData('application/x-yolomux-session', payload);
  event.dataTransfer.setData('text/plain', session);
  // #47: use the NATIVE drag image — a one-time compositor snapshot of the tab itself — instead of the
  // JS clone-follow preview. That removes the per-move reposition, the two document capture listeners,
  // and the animated heavyweight clone that caused the "won't budge" first drag and the per-move jank.
  // C12 F2: take the grab offset from event.offsetX/offsetY (already on the event) instead of
  // getBoundingClientRect(), which forced a synchronous layout reflow inside the handler — coldest on the
  // first drag after load — before the browser could start the drag.
  const source = event.currentTarget;
  const dragImageSource = typeof options.dragImage === 'function'
    ? (options.dragImage(event, source) || source)
    : (options.dragImage || source);
  if (dragImageSource && event.dataTransfer?.setDragImage) {
    const offsetX = Math.max(0, Number(event.offsetX) || 0);
    const offsetY = Math.max(0, Number(event.offsetY) || 0);
    event.dataTransfer.setDragImage(dragImageSource, offsetX, offsetY);
  }
  resetDragTabRectCache();
  dragTimingMark('startSessionDrag:end');
}

function startPaneDrag(event, sourceSlot) {
  const slot = layoutSlotKeys().includes(sourceSlot) ? sourceSlot : null;
  if (!slot || slotIsFileExplorerPane(slot)) {
    event.preventDefault?.();
    return;
  }
  const active = activeItemForSide(slot);
  if (!active) {
    event.preventDefault?.();
    return;
  }
  dragTimingMark('startPaneDrag');
  dragState.item = active;
  dragState.sourceSlot = slot;
  dragState.paneSlot = slot;
  dragState.filePayload = null;
  const payload = JSON.stringify({slot});
  event.dataTransfer.effectAllowed = 'move';
  event.dataTransfer.setData('application/x-yolomux-pane', payload);
  event.dataTransfer.setData('text/plain', paneTabs(slot).map(itemLabel).join('\n'));
  startPaneDragPreview(event, slot, {nativeDrag: true});
}

function endSessionDrag(event) {
  cancelDragOperationState();
  sessionButtons.classList.remove(CLS.dragOver);
  // flush any tab/preferences re-renders that were deferred during the drag.
  if (pendingTabStripRender) { pendingTabStripRender = false; renderPaneTabStrips(); }
  if (pendingPreferencesRender) { pendingPreferencesRender = false; renderPreferencesPanels(); }
  flushDeferredJsDebugPanelRefresh();
  // flush through the shared layout render scheduler so same-shape drops keep the cheap path.
  flushPendingLayoutRender();
  dragTimingReport();
}
function layoutWithoutItemFromSlots(item, slots = layoutSlots, options = {}) {
  const next = emptyLayoutSlots();
  next[layoutTreeKey] = slots?.[layoutTreeKey] || null;
  const preserveEmptySlot = options.preserveEmptySlot || null;
  const preserveRemovedSlot = options.preserveRemovedSlot === true;
  const preservePlaceholders = options.preservePlaceholders !== false;
  for (const side of layoutSlotKeys(slots)) {
    if (paneIsPlaceholder(side, slots)) {
      if (preservePlaceholders) next[side] = emptyPlaceholderPaneState();
      continue;
    }
    const hadItem = paneTabs(side, slots).includes(item);
    const active = activeItemForSide(side, slots);
    const tabs = paneTabs(side, slots).filter(value => value !== item);
    next[side] = !tabs.length && (side === preserveEmptySlot || (preserveRemovedSlot && hadItem))
      ? emptyPlaceholderPaneState(paneRoleForSlot(side, slots))
      : paneStateWithTabs(tabs, active === item ? null : active, paneRoleForSlot(side, slots));
  }
  return next;
}

function layoutWithoutItem(item, options = {}) {
  return layoutWithoutItemFromSlots(item, layoutSlots, options);
}

function fileExplorerHiddenStatusMessage() {
  return t('finder.hiddenStatus', {name: fileExplorerLabel(), keys: appShortcutText('B')});
}

function hiddenFromLayoutStatusMessage(item) {
  return isFileExplorerItem(item) ? fileExplorerHiddenStatusMessage() : t('layout.status.hidden', {items: itemLabel(item)});
}

function removeSessionFromLayout(item, options = {}) {
  if (!itemInLayout(item)) return;
  const isFiles = isFileExplorerItem(item);
  const sourceSlot = slotForItem(item);
  if (isFiles) rememberFileExplorerOpenIntent(false);
  if (typeof closePopoutsForLayoutItem === 'function') closePopoutsForLayoutItem(item);
  applyLayoutSlots(layoutWithoutItem(item, {
    // Generic tab closure keeps the pane as an intentional drop target. A Vertical Side Pane leaf
    // must instead compact when its final tab closes; preserving it creates a generic-looking empty
    // region beside the surviving Side leaf after a YO!* cross-role move.
    preserveRemovedSlot: !isFiles && !slotIsSidePane(sourceSlot),
    preservePlaceholders: !isFiles,
  }), {
    message: options.message || hiddenFromLayoutStatusMessage(item),
    focusSession: options.focusSession,
  });
}

function removePaneFromLayout(item) {
  const slot = slotForSession(item);
  if (!slot) return;
  const moved = paneTabs(slot);
  if (moved.includes(fileExplorerItemId)) rememberFileExplorerOpenIntent(false);
  if (typeof closePopoutsForLayoutItem === 'function') moved.forEach(closePopoutsForLayoutItem);
  applyLayoutSlots(layoutWithoutSlot(slot, {preserveRemovedSlot: shouldPreserveClosedPaneSlot(slot)}), {
    message: moved.length ? t('layout.status.hidden', {items: moved.map(itemLabel).join(', ')}) : '',
  });
}

// Placeholders are deliberate drop targets after a split/move, but they are still disposable UI.
// Keep their dismissal on the same layout transaction path as pane-frame close so Dockview, the
// DOM renderer, URL state, and shared layout snapshots cannot disagree about which leaf vanished.
function canCloseEmptyPane(slot, slots = layoutSlots) {
  if (!slot || !paneIsPlaceholder(slot, slots) || slotIsSidePane(slot, slots)) return false;
  return layoutSlotKeys(slots).some(candidate => (
    candidate !== slot
    && !slotIsSidePane(candidate, slots)
    && paneHasLayoutContent(candidate, slots)
  ));
}

function closeEmptyPaneFromLayout(slot) {
  if (!canCloseEmptyPane(slot)) return false;
  applyLayoutSlots(layoutWithoutSlot(slot), {
    preserveMissingSidePane: sidePaneSlots().length > 0,
    preservePlaceholderSlots: true,
    prune: false,
  });
  return true;
}

function emptyPaneCanClose(slot, slots = layoutSlots) {
  return canCloseEmptyPane(slot, slots);
}

function closePaneFrameItem(item) {
  const emptySlot = typeof dockviewEmptyPaneSlot === 'function' ? dockviewEmptyPaneSlot(item) : null;
  if (emptySlot) {
    closeEmptyPaneFromLayout(emptySlot);
    return;
  }
  const resolved = resolveLayoutItem(item);
  if (isFileExplorerItem(resolved)) {
    removeSessionFromLayout(resolved);
    return;
  }
  if (narrowPaneFrameActionTargetsTab(resolved)) {
    removeSessionFromLayout(resolved, {focusSession: nextNarrowPaneFrameItem(resolved)});
    return;
  }
  removePaneFromLayout(resolved);
}

function shouldPreserveClosedPaneSlot(slot) {
  if (!slot || isFileExplorerItem(activeItemForSide(slot))) return false;
  return layoutSlotKeys().some(side => side !== slot && isFileExplorerItem(activeItemForSide(side)));
}

function layoutWithoutSlot(slot, options = {}) {
  const next = emptyLayoutSlots();
  next[layoutTreeKey] = layoutSlots[layoutTreeKey];
  for (const side of layoutSlotKeys()) {
    if (side === slot) {
      if (options.preserveRemovedSlot === true) next[side] = emptyPlaceholderPaneState();
      continue;
    }
    next[side] = paneStateForLayoutSlot(side);
  }
  return next;
}

function appendUniqueItems(target, items) {
  for (const item of items) {
    if (isLayoutItem(item) && !target.includes(item)) target.push(item);
  }
  return target;
}

// Per-pane tab cap (LRU eviction). Records when a tab was last activated so the oldest UNUSED tab
// can auto-close once a pane grows past appearance.max_tabs_per_pane.
function recordTabActivation(item) {
  if (isLayoutItem(item)) tabLastActivatedAt.set(item, Date.now());
}

function maxTabsPerPane() {
  const raw = Math.floor(Number(initialSetting('appearance.max_tabs_per_pane', 10)));
  if (!Number.isFinite(raw)) return 10;
  return Math.max(2, Math.min(30, raw));
}

function capKeepItemSet(keepItem, keepItems = []) {
  const result = new Set();
  if (keepItem instanceof Set) {
    for (const item of keepItem) if (isLayoutItem(item)) result.add(item);
  } else if (isLayoutItem(keepItem)) {
    result.add(keepItem);
  }
  for (const item of keepItems || []) if (isLayoutItem(item)) result.add(item);
  return result;
}

// A tab may be auto-evicted unless it is being kept active, pinned, the Finder dock,
// or a dirty/unsaved editor (never silently drop unsaved edits).
function tabIsEvictableForCap(item, keepItem) {
  const keep = keepItem instanceof Set ? keepItem : capKeepItemSet(keepItem);
  if (keep.has(item) || tabIsPinned(item) || isFileExplorerItem(item)) return false;
  if (isFileEditorItem(item)) {
    const state = openFiles.get(fileItemPath(item));
    if (state && state.dirty) return false;
  }
  return true;
}

function capRefusalReason(tabs, keep) {
  const protectedTabs = tabs.filter(item => !keep.has(item));
  return protectedTabs.length > 0 && protectedTabs.every(item => tabIsPinned(item)) ? 'all-pinned' : 'nothing-evictable';
}

function paneCapacityCheckForInsert(slot, incomingTabs = [], keepItem = null, slots = layoutSlots, options = {}) {
  const keep = capKeepItemSet(keepItem, options.keepItems);
  const baseTabs = Array.isArray(options.tabs) ? [...options.tabs] : paneTabs(slot, slots);
  const tabs = appendUniqueItems([...baseTabs], Array.isArray(incomingTabs) ? incomingTabs : [incomingTabs]);
  const cap = maxTabsPerPane();
  const overflow = tabs.length - cap;
  if (overflow <= 0) return {ok: true, cap, overflow: 0, evicted: [], finalTabs: tabs, reason: ''};
  const evictable = tabs.filter(item => tabIsEvictableForCap(item, keep));
  if (!evictable.length) return {ok: false, cap, overflow, evicted: [], finalTabs: tabs, reason: capRefusalReason(tabs, keep)};
  const originalIndex = new Map(tabs.map((item, index) => [item, index]));
  const byLeastRecent = [...evictable].sort((a, b) => {
    const delta = (tabLastActivatedAt.get(a) || 0) - (tabLastActivatedAt.get(b) || 0);
    return delta || ((originalIndex.get(a) || 0) - (originalIndex.get(b) || 0));
  });
  const evicted = byLeastRecent.slice(0, Math.min(overflow, byLeastRecent.length));
  if (evicted.length < overflow) return {ok: false, cap, overflow, evicted: [], finalTabs: tabs, reason: capRefusalReason(tabs, keep)};
  return {ok: true, cap, overflow, evicted, finalTabs: tabs.filter(item => !evicted.includes(item)), reason: ''};
}

// Given a pane's tab list (newest tab already inserted) return the least-recently-used evictable
// tabs to drop so the pane fits the cap. Keeps keepItem, dirty editors, and the Finder.
function tabsToEvictForCap(tabs, keepItem) {
  return paneCapacityCheckForInsert('', [], keepItem, layoutSlots, {tabs}).evicted;
}

function paneCapacityRefusalStatus(item, capacity, targetSlot = '') {
  return paneCapacityRefusalStatusForItems([item], capacity, targetSlot);
}

function layoutItemLabels(items = []) {
  return (Array.isArray(items) ? items : [items]).filter(isLayoutItem).map(itemLabel).join(', ');
}

function paneCapacityRefusalStatusForItems(items, capacity, targetSlot = '') {
  const statusKey = capacity?.reason === 'all-pinned'
    ? 'layout.status.paneFullPinned'
    : 'layout.status.nothingEvictable';
  return t(statusKey, {
    item: layoutItemLabels(items) || targetSlot || t('layout.zone.middle'),
    pane: targetSlot || t('layout.zone.middle'),
    limit: capacity?.cap || maxTabsPerPane(),
  });
}

function pinnedPaneAtCapStatus(items, cap = maxTabsPerPane()) {
  return t('layout.status.pinnedPaneAtCap', {items: layoutItemLabels(items) || t('tab.pinned'), limit: cap});
}

function pinnedTabsInSlot(slot, slots = layoutSlots) {
  return paneTabs(slot, slots).filter(tabIsPinned);
}

function unpinnedTabsInSlot(slot, slots = layoutSlots) {
  return paneTabs(slot, slots).filter(item => !tabIsPinned(item));
}

function dropIntentCapacityCheckForSession(session, intent, sourceSlot = null) {
  if (!intent?.targetSlot || intent.zone !== 'middle' || intent.boundary) return null;
  if (sourceSlot && sourceSlot === intent.targetSlot) return null;
  return paneCapacityCheckForInsert(intent.targetSlot, [session], session, layoutSlots);
}

function dropIntentCapacityAllowsSession(session, intent, sourceSlot = null) {
  const capacity = dropIntentCapacityCheckForSession(session, intent, sourceSlot);
  return !capacity || capacity.ok;
}

function dropIntentCapacityRefusalStatus(session, intent, sourceSlot = null) {
  const capacity = dropIntentCapacityCheckForSession(session, intent, sourceSlot);
  return capacity && !capacity.ok ? paneCapacityRefusalStatus(session, capacity, intent.targetSlot) : '';
}

function paneTabsForGenericActions(slot, slots = layoutSlots) {
  return slotIsSidePane(slot, slots) ? [] : paneTabs(slot, slots);
}

// A narrow touch layout has one shared tab strip, not independent panes. Its frame controls must
// therefore operate on the selected tab; removing the only pane would make the control appear to
// do nothing (or blank the whole view). Keep one remaining tab as the stable single-column view.
function narrowPaneFrameActionTargetsTab(item, slots = layoutSlots) {
  if (!narrowSingleColumnMode()) return false;
  const slot = slotForItem(item, slots);
  return Boolean(slot && paneTabs(slot, slots).length > 1);
}

function nextNarrowPaneFrameItem(item, slots = layoutSlots) {
  const slot = slotForItem(item, slots);
  if (!slot) return null;
  const remaining = paneTabs(slot, slots).filter(value => value !== item);
  return remaining.find(value => !isFileExplorerItem(value)) || remaining[0] || null;
}

function canPaneExpand(item, slots = layoutSlots) {
  const targetSlot = slotForItem(item, slots);
  if (!targetSlot || slotIsSidePane(targetSlot, slots)) return false;
  if (!activeItemForSide(targetSlot, slots)) return false;
  return layoutSlotKeys(slots).some(slot => (
    slot !== targetSlot
    && !slotIsSidePane(slot, slots)
    && unpinnedTabsInSlot(slot, slots).length > 0
  ));
}

function minimizePaneFromLayout(item) {
  const sourceSlot = slotForSession(item);
  if (!sourceSlot) return;
  if (narrowPaneFrameActionTargetsTab(item)) {
    removeSessionFromLayout(item, {focusSession: nextNarrowPaneFrameItem(item)});
    return;
  }
  if (narrowSingleColumnMode()) return;
  if (slotIsSidePane(sourceSlot)) {
    removePaneFromLayout(item);
    return;
  }
  const sourceTabs = paneTabsForGenericActions(sourceSlot);
  const targetSlot = largestNonFileExplorerPaneSlot(new Set([sourceSlot]));
  if (!targetSlot || !sourceTabs.length) {
    removePaneFromLayout(item);
    return;
  }
  const targetActive = activeItemForSide(targetSlot);
  const next = layoutWithoutSlot(sourceSlot, {preserveRemovedSlot: shouldPreserveClosedPaneSlot(sourceSlot)});
  const capacity = paneCapacityCheckForInsert(targetSlot, sourceTabs, null, next, {keepItems: sourceTabs});
  if (!capacity.ok) {
    showLayoutStatus(paneCapacityRefusalStatusForItems(sourceTabs, capacity, targetSlot), 'danger');
    return;
  }
  next[targetSlot] = paneStateWithTabsForSlot(targetSlot, capacity.finalTabs, targetActive, next);
  const messages = [t('layout.status.minimized', {items: sourceTabs.map(itemLabel).join(', ')})];
  if (capacity.evicted.length) {
    messages.push(t('layout.status.autoClosed', {items: capacity.evicted.map(itemLabel).join(', '), limit: capacity.cap}));
  }
  applyLayoutSlots(next, {
    focusSession: targetActive || capacity.finalTabs[0],
    prune: false,
    message: messages.filter(Boolean).join('; '),
  });
}

function expandPaneFromLayout(item) {
  const targetSlot = slotForSession(item);
  if (!targetSlot || !canPaneExpand(item)) return;
  const active = activeItemForSide(targetSlot);
  if (!active) return;
  const incomingTabs = [];
  for (const slot of layoutSlotKeys()) {
    if (slot === targetSlot) continue;
    appendUniqueItems(incomingTabs, unpinnedTabsInSlot(slot));
  }
  if (!incomingTabs.length) return;
  const capacity = paneCapacityCheckForInsert(targetSlot, incomingTabs, active, layoutSlots);
  if (!capacity.ok) {
    showLayoutStatus(paneCapacityRefusalStatusForItems(incomingTabs, capacity, targetSlot), 'danger');
    return;
  }
  if (!incomingTabs.some(tab => capacity.finalTabs.includes(tab))) {
    showLayoutStatus(paneCapacityRefusalStatusForItems(incomingTabs, {
      ...capacity,
      ok: false,
      reason: 'nothing-evictable',
    }, targetSlot), 'danger');
    return;
  }
  const next = cloneLayoutSlots(layoutSlots);
  next[targetSlot] = paneStateWithTabsForSlot(targetSlot, capacity.finalTabs, active, next);
  for (const slot of layoutSlotKeys(next)) {
    if (slot === targetSlot || slotIsSidePane(slot, next)) continue;
    const pinnedTabs = pinnedTabsInSlot(slot, next);
    next[slot] = pinnedTabs.length
      ? paneStateWithTabsForSlot(slot, pinnedTabs, pinnedTabs[0], next)
      : emptyPaneState(paneRoleForSlot(slot, next));
  }
  applyLayoutSlots(next, {
    focusSession: active,
    prune: false,
    preserveMissingSidePane: sidePaneSlots(next).length > 0,
    preservePlaceholderSlots: true,
    message: t('layout.status.expanded', {item: itemLabel(active)}),
  });
}

function visibleNonFinderPaneItems(slots = layoutSlots) {
  const result = [];
  for (const slot of layoutSlotKeys(slots)) appendUniqueItems(result, paneTabsForGenericActions(slot, slots));
  return result;
}

function firstNonFinderPaneSlot(slots = layoutSlots) {
  return layoutSlotKeys(slots).find(slot => !slotIsSidePane(slot, slots) && paneTabsForGenericActions(slot, slots).length > 0) || null;
}

function preferredNonFinderLayoutSlots(finderSlot = null) {
  return layoutSlotKeys().filter(slot => slot !== finderSlot && paneTabsForGenericActions(slot).length > 0);
}

function layoutModeStatusMessage(mode) {
  const normalized = normalizeLayoutMode(mode);
  return t(`menu.view.layout.${normalized}`);
}

function applyNonFinderLayoutMode(mode) {
  const items = visibleNonFinderPaneItems();
  if (!items.length) return;
  const normalized = normalizeLayoutMode(mode);
  const active = items.includes(focusedPanelItem) ? focusedPanelItem : items[0];
  const preserveSlots = normalized === 'single' || normalized === 'split';
  const content = layoutSlotsForItems(items, normalized, {
    active,
    preferredSlots: preserveSlots ? preferredNonFinderLayoutSlots() : [],
    reservedSlots: sidePaneSlots(),
  });
  const next = layoutWithPreservedSidePanes(content);
  applyLayoutSlots(next, {focusSession: active, prune: false, message: layoutModeStatusMessage(normalized)});
}

function applyLayoutMode(mode) {
  applyNonFinderLayoutMode(narrowSingleColumnMode() ? 'single' : normalizeLayoutMode(mode));
}

function setLayoutToSinglePane() {
  applyLayoutMode('single');
}

function setLayoutToSplitPanes() {
  applyLayoutMode('split');
}

function setLayoutToGridPanes() {
  applyLayoutMode('grid');
}

function setLayoutToWallPanes() {
  applyLayoutMode('wall');
}

function layoutWithFileExplorerDockedLeft(slots = layoutSlots, options = {}) {
  // Compatibility callers still use the old Finder-specific name. Rebuild through the shared
  // Side Pane transaction so this path cannot drop Differ/Tabber or silently create a generic pane.
  const withoutFileSurfaces = layoutWithoutFileSurfaces(slots);
  return layoutWithSidePaneItems(withoutFileSurfaces, layoutFileSurfaceItems(), {
    side: paneSideLeft,
    forceCreate: true,
    active: options.active || fileExplorerItemId,
  });
}

function dockFileExplorerPane() {
  rememberFileExplorerOpenIntent(true);
  if (fileExplorerUsesNormalTabMovement()) {
    void openFileSurfacePane(fileExplorerItemId);
    return;
  }
  applyLayoutSlots(layoutWithFileExplorerDockedLeft(), {
    focusSession: fileExplorerItemId,
    prune: false,
  });
}

function firstEmptyPane(slots = layoutSlots) {
  const placeholderSlot = layoutSlotKeys(slots).find(slot => !slotIsSidePane(slot, slots) && paneIsPlaceholder(slot, slots));
  if (placeholderSlot) return placeholderSlot;
  return layoutSlotKeys(slots).length ? null : 'left';
}

function slotForNewSession() {
  const empty = firstEmptyPane();
  if (empty) return empty;
  const focusedSlot = focusedPanelItem ? slotForSession(focusedPanelItem) : null;
  if (focusedSlot && !slotIsSidePane(focusedSlot)) return focusedSlot;
  return layoutSlotKeys().find(slot => !slotIsSidePane(slot)) || 'left';
}

function focusedActivationSlot() {
  const item = currentActiveMenuItem();
  const slot = item ? slotForSession(item) : null;
  return slot && !slotIsFileExplorerPane(slot) ? slot : null;
}

function fileEditorActivationSlot() {
  const focusedSlot = focusedActivationSlot();
  if (focusedSlot) return focusedSlot;
  const previousSlot = lastActiveNonFileExplorerPaneItem ? slotForSession(lastActiveNonFileExplorerPaneItem) : null;
  return previousSlot && !slotIsFileExplorerPane(previousSlot) ? previousSlot : null;
}

function slotForTabActivation(item) {
  const currentSlot = slotForSession(item);
  if (currentSlot) return currentSlot;
  return fileEditorActivationSlot() || largestNonFileExplorerPaneSlot() || firstEmptyPane() || largestPaneSlot() || slotForNewSession();
}

async function activateTabInExistingPane(item, options = {}) {
  if (!isLayoutItem(item)) return;
  const targetSlot = options.preferFocused === true
    ? (fileEditorActivationSlot() || slotForTabActivation(item))
    : slotForTabActivation(item);
  if (!targetSlot) return;
  const currentSlot = slotForSession(item);
  if (currentSlot === targetSlot) {
    activatePaneTab(targetSlot, item, {userInitiated: options.userInitiated === true});
    return;
  }
  await moveSessionToSlot(item, targetSlot, currentSlot, paneTabs(targetSlot).length);
}

function filesOnlySlotForSession(session) {
  const filesSlot = slotForSession(fileExplorerItemId);
  if (!filesSlot) return null;
  const stack = paneTabs(filesSlot).filter(item => item !== session);
  return stack.length === 1 && stack[0] === fileExplorerItemId ? filesSlot : null;
}

function slotForNewTmuxSession(session) {
  const currentSlot = slotForSession(session);
  if (currentSlot) return currentSlot;
  const empty = firstEmptyPane();
  if (empty) return empty;
  const targetSlot = largestNonFileExplorerPaneSlot();
  if (targetSlot) return targetSlot;
  return filesOnlySlotForSession(session) || largestPaneSlot() || slotForNewSession();
}

async function placeTmuxSession(session) {
  const currentSlot = slotForSession(session);
  if (currentSlot) {
    activatePaneTab(currentSlot, session);
    return;
  }
  const targetSlot = slotForNewTmuxSession(session);
  if (!targetSlot) return;
  if (paneIsPlaceholder(targetSlot) || !paneTabs(targetSlot).length) {
    await moveSessionToSlot(session, targetSlot, null);
    return;
  }
  if (isFileExplorerItem(activeItemForSide(targetSlot))) {
    await splitSessionAtSlot(session, targetSlot, 'right', null, sidePaneDefaultWidthPercent);
    return;
  }
  await moveSessionToSlot(session, targetSlot, null, paneTabs(targetSlot).length);
}

// File -> Finder and Mod+B toggle the reserved Finder/Differ/Tabber pane. Hide it when it is already in
// the layout (same path as the close button), otherwise open/focus it. The menu's `checked` state tracks this.
function toggleFinderPane() {
  if (itemInLayout(fileExplorerItemId)) {
    removeSessionFromLayout(fileExplorerItemId);
    return false;
  }
  selectSession(fileExplorerItemId);
  return true;
}

async function openFileExplorerPane() {
  rememberFileExplorerOpenIntent(true);
  return openFileSurfacePane(fileExplorerItemId);
}

// The menu and shortcuts call this shared placement transaction for Finder, Differ, and Tabber.
// Existing tabs are activated in place.  Only a missing item is inserted into the left home column.
async function openFileSurfacePane(item) {
  const resolved = resolveLayoutItem(item);
  if (!layoutIsFileSurfaceItem(resolved)) return false;
  const currentSlot = slotForItem(resolved);
  if (currentSlot) {
    activatePaneTab(currentSlot, resolved, {userInitiated: true});
    return true;
  }
  if (sidePaneConstrainedMode()) {
    const next = layoutWithItems(layoutSlots, [resolved], slotForNewSession());
    const placed = narrowSingleColumnMode()
      ? narrowSingleColumnLayoutSlots(next, {focusSession: resolved})
      : next;
    applyLayoutSlots(placed, {focusSession: resolved, prune: false, preserveMissingSidePane: true});
    return true;
  }
  const next = layoutWithSidePaneItems(layoutSlots, [resolved], {side: paneSideLeft});
  const homeSlot = sidePaneSlot(paneSideLeft, next);
  applyLayoutSlots(next, {focusSession: resolved, prune: false});
  if (homeSlot) activatePaneTab(homeSlot, resolved, {userInitiated: true});
  return true;
}

// Public triplet placement entry point used by menus, keyboard shortcuts, and future callers.
// Keep the alias here with the slot mutation rather than teaching each consumer where a home
// column lives.
async function openFileSurface(item) {
  return openFileSurfacePane(item);
}

// File-menu navigation is intentionally broader on a desktop/wide tablet: choosing any triplet
// destination restores all missing Finder/Differ/Tabber tabs, while retaining every existing
// placement, then activates the item the user chose. Narrow touch remains one selected surface.
async function openFileSurfaceFromMenu(item) {
  const resolved = resolveLayoutItem(item);
  if (!layoutIsFileSurfaceItem(resolved)) return false;
  if (sidePaneConstrainedMode()) return openFileSurfacePane(resolved);
  // Pass only absent items to the left-edge creator. Existing triplet tabs are already placed by the
  // user, possibly in the right Vertical Side Pane or another vertical leaf, and must not be re-homed.
  const missing = fileSurfaceItems.filter(candidate => !itemInLayout(candidate));
  const next = missing.length
    ? layoutWithSidePaneItems(layoutSlots, missing, {
      side: paneSideLeft,
      forceCreate: true,
      active: missing.includes(resolved) ? resolved : missing[0],
    })
    : layoutSlots;
  const targetSlot = slotForItem(resolved, next);
  applyLayoutSlots(next, {focusSession: resolved, prune: false});
  if (targetSlot) activatePaneTab(targetSlot, resolved, {userInitiated: true});
  return true;
}

function layoutWithoutFileSurfaces(slots = layoutSlots) {
  const next = cloneLayoutSlots(slots);
  for (const slot of layoutSlotKeys(next)) {
    const tabs = paneTabs(slot, next).filter(item => !layoutIsFileSurfaceItem(item));
    if (tabs.length) {
      next[slot] = paneStateWithTabsForSlot(slot, tabs, activeItemForSide(slot, next), next);
    } else if (slotIsSidePane(slot, next)) {
      delete next[slot];
    } else {
      next[slot] = emptyPlaceholderPaneState();
    }
  }
  return compactLayoutSlots(next, {preservePlaceholderSlots: false});
}

// Cmd/Ctrl+B deliberately differs from an individual close: it is an explicit whole-triplet
// transaction. Hiding retains no second layout source; restoring intentionally creates the
// documented default 22% home column with Finder active.
async function toggleAllFileSurfaces() {
  if (layoutFileSurfaceItems().some(item => itemInLayout(item))) {
    applyLayoutSlots(layoutWithoutFileSurfaces(), {
      preserveMissingSidePane: true,
      message: fileExplorerHiddenStatusMessage(),
    });
    return false;
  }
  const next = layoutWithDefaultLeftSidePane(layoutSlots);
  const homeSlot = sidePaneSlot(paneSideLeft, next);
  applyLayoutSlots(next, {focusSession: finderItemId, prune: false});
  if (homeSlot) activatePaneTab(homeSlot, finderItemId, {userInitiated: true});
  return true;
}

async function splitSessionBesidePlaceholder(session, targetSlot, zone, pct = defaultSplitPercent) {
  if (!isLayoutItem(session) || !targetSlot || !['top', 'bottom', 'left', 'right'].includes(zone)) return;
  if (!paneIsPlaceholder(targetSlot)) {
    await splitSessionAtSlot(session, targetSlot, zone, null, pct);
    return;
  }
  const next = layoutWithoutItem(session);
  if (!next[layoutTreeKey]) next[layoutTreeKey] = leafNode(targetSlot);
  if (!next[targetSlot]) next[targetSlot] = emptyPlaceholderPaneState();
  const newSlot = nextLayoutSlot(next);
  next[newSlot] = paneStateWithTabs([session], session);
  const direction = zone === 'left' || zone === 'right' ? 'row' : 'column';
  const existingNode = leafNode(targetSlot);
  const newNode = leafNode(newSlot);
  const splitPct = splitPercentForNewItem(session, zone, pct);
  const replacement = zone === 'right' || zone === 'bottom'
    ? splitNode(direction, existingNode, newNode, splitPct)
    : splitNode(direction, newNode, existingNode, splitPct);
  next[layoutTreeKey] = replaceLayoutLeaf(next[layoutTreeKey], targetSlot, replacement);
  applyLayoutSlots(next, {focusSession: session, prune: false});
}

async function moveSessionToSlot(session, targetSlot, sourceSlot = null, insertIndex = 0, options = {}) {
  if (!isLayoutItem(session) || !targetSlot) return false;
  const actualSourceSlot = sourceSlot || slotForItem(session);
  if (!paneRoleAllowsItemTransfer(session, actualSourceSlot, targetSlot, layoutSlots, {
    allowRequiredInGeneric: sidePaneConstrainedMode(),
  })) return false;
  // Placement is always visual-first. applyLayoutSlots -> ensureTerminalRunning owns the
  // asynchronous readiness check and renders the shared connecting/unavailable state while it
  // reconciles. Never put /api/ensure-session back in this user-action critical path.
  const next = layoutWithoutItem(session, {
    // Directional Move deliberately leaves the source as an explicit drop target when its
    // final tab leaves. Ordinary tab drag/move continues to compact that now-empty slot.
    preserveRemovedSlot: options.preserveSourcePlaceholder === true,
  });
  if (!next[layoutTreeKey]) next[layoutTreeKey] = leafNode(targetSlot);
  if (!next[targetSlot]) next[targetSlot] = emptyPaneState();
  const tabs = next[targetSlot].tabs;
  const index = Math.max(0, Math.min(Number.isFinite(insertIndex) ? insertIndex : 0, tabs.length));
  tabs.splice(index, 0, session);
  recordTabActivation(session);
  // Enforce the per-pane tab cap through the shared capacity owner. Later pinned/cap items reuse
  // the same result shape for visible refusals, preview parity, minimize, and expand.
  const capacity = paneCapacityCheckForInsert(targetSlot, [], session, next, {tabs});
  if (!capacity.ok) {
    showLayoutStatus(paneCapacityRefusalStatus(session, capacity, targetSlot), 'danger');
    return false;
  }
  next[targetSlot] = paneStateWithTabsForSlot(targetSlot, capacity.finalTabs, session, next);
  applyLayoutSlots(next, {
    focusSession: session,
    prune: false,
    preservePlaceholderSlots: options.preserveSourcePlaceholder === true,
    message: capacity.evicted.length ? t('layout.status.autoClosed', {items: capacity.evicted.map(itemLabel).join(', '), limit: capacity.cap}) : '',
  });
  return true;
}

async function dropSessionWithIntent(session, intent, sourceSlot = null) {
  if (!dropIntentAllowsSession(session, intent, {sourceSlot})) return false;
  if (intent?.boundary === 'gutter') {
    return splitSessionAtGutter(session, intent.splitPath, intent.zone, sourceSlot);
  }
  if (intent?.boundary === 'root') {
    return splitSessionAtLayoutBoundary(session, intent.zone, sourceSlot);
  }
  if (!intent?.targetSlot || intent.zone === 'middle') {
    return moveSessionToSlot(session, intent?.targetSlot || slotForNewSession(), sourceSlot);
  }
  return splitSessionAtSlot(session, intent.targetSlot, intent.zone, sourceSlot);
}

function splitPercentForNewItem(session, zone, pct = null) {
  if (pct !== null && pct !== undefined && pct !== '' && Number.isFinite(Number(pct))) return Number(pct);
  return defaultSplitPercent;
}

function rootBoundarySplitPercent(existingNode, zone, pct = null, slots = layoutSlots, movingItem = null) {
  if (pct !== null && pct !== undefined && pct !== '' && Number.isFinite(Number(pct))) return splitPercent(pct);
  const existingPaneCount = Math.max(1, layoutLeafSlots(existingNode).filter(slot => (
    paneTabs(slot, slots).some(item => item !== movingItem)
      || (paneIsPlaceholder(slot, slots) && !paneTabs(slot, slots).includes(movingItem))
  )).length);
  const newPanePercent = 100 / (existingPaneCount + 1);
  return splitPercent(zone === 'right' || zone === 'bottom' ? 100 - newPanePercent : newPanePercent);
}

function shouldPreserveSourceSlotForSplit(sourceSlot, targetSlot, item, slots = layoutSlots) {
  if (!sourceSlot || sourceSlot === targetSlot || !slotIsSidePane(targetSlot, slots)) return false;
  if (slotIsSidePane(sourceSlot, slots) || paneTabs(sourceSlot, slots).some(tab => tab !== item)) return false;
  // A Vertical Side Pane cannot become the only workspace content: retain the final Generic leaf as
  // its protected filler. When another Generic pane already exists, retaining this emptied source
  // creates an orphaned Drop-a-tab-here region after the moved YO!* tab is later closed.
  return !layoutSlotKeys(slots).some(slot => (
    slot !== sourceSlot
      && !slotIsSidePane(slot, slots)
      && paneHasLayoutContent(slot, slots)
  ));
}

function layoutSidePaneRootSplit(node, slots = layoutSlots, requestedSide = null) {
  if (!node || node.split !== 'row' || !Array.isArray(node.children) || node.children.length !== 2) return null;
  const sideIndex = node.children.findIndex(child => {
    const leaves = layoutLeafSlots(child);
    const populated = leaves.filter(slot => paneHasLayoutContent(slot, slots));
    if (!populated.length || populated.length !== leaves.length || populated.some(slot => !slotIsSidePane(slot, slots))) return false;
    const sides = new Set(populated.map(slot => paneRoleForSlot(slot, slots).side));
    if (sides.size !== 1) return false;
    return !requestedSide || sides.has(requestedSide);
  });
  if (sideIndex < 0) return null;
  const sideSlots = layoutLeafSlots(node.children[sideIndex]).filter(slot => slotIsSidePane(slot, slots));
  const sideSlot = sideSlots[0];
  return {
    sideIndex,
    sideSlot,
    sideSlots,
    side: paneRoleForSlot(sideSlot, slots).side,
    contentIndex: sideIndex === 0 ? 1 : 0,
    pct: Number.isFinite(Number(node.pct)) ? Number(node.pct) : sidePaneDefaultWidthPercent,
  };
}

function splitRootPreservingSidePane(root, newNode, session, zone, pct = null, slots = layoutSlots) {
  const docked = layoutSidePaneRootSplit(root, slots);
  if (!docked) return null;
  const children = [...(root.children || [])];
  const contentNode = children[docked.contentIndex];
  if (!contentNode) return null;
  const direction = layoutSplitDirectionForZone(zone);
  const splitPct = rootBoundarySplitPercent(contentNode, zone, pct, slots);
  children[docked.contentIndex] = zone === 'right' || zone === 'bottom'
    ? splitNode(direction, contentNode, newNode, splitPct)
    : splitNode(direction, newNode, contentNode, splitPct);
  return splitNode('row', children[0], children[1], docked.pct);
}

async function splitLayoutItemAtSlot(item, targetSlot, zone, sourceSlot = null, pct = null, options = {}) {
  if (!isLayoutItem(item) || !targetSlot || !['top', 'bottom', 'left', 'right'].includes(zone)) return false;
  const actualSourceSlot = sourceSlot || slotForItem(item);
  const targetRole = paneRoleForSlot(targetSlot);
  if ((targetRole.kind === paneRoleSide && !['top', 'bottom'].includes(zone))
    || !paneRoleAllowsItemTransfer(item, actualSourceSlot, targetSlot, layoutSlots)) return false;
  const preserveRemovedSlot = options.preserveSourcePlaceholder === true
    && sourceSlot === targetSlot
    && paneTabs(sourceSlot).length === 1;
  // Layout placement is synchronous, so the source cannot drift during a readiness round trip;
  // applyLayoutSlots delegates any cold terminal reconciliation to ensureTerminalRunning.
  const liveSourceSlot = slotForItem(item) || actualSourceSlot;
  const liveTargetSlot = targetSlot === actualSourceSlot ? liveSourceSlot : targetSlot;
  // Dockview can retain an unrendered empty group from an earlier arrangement. Directional Move
  // operates on what the user can see, so that old group cannot become a hidden third pane.
  const sourceSlots = options.forceSplitEmpty === true
    ? layoutSlotsWithoutUnrenderedPlaceholders()
    : layoutSlots;
  const preserveEmptySlot = preserveRemovedSlot || shouldPreserveSourceSlotForSplit(
    liveSourceSlot, liveTargetSlot, item, sourceSlots,
  )
    ? liveSourceSlot
    : null;
  const next = layoutWithoutItemFromSlots(item, sourceSlots, {
    preserveEmptySlot,
    preserveRemovedSlot,
  });
  const targetTabs = paneTabs(liveTargetSlot, next);
  if (!targetTabs.length && options.forceSplitEmpty !== true) {
    await moveSessionToSlot(item, liveTargetSlot, liveSourceSlot);
    return true;
  }
  const newSlot = nextLayoutSlot(next);
  next[newSlot] = paneStateWithTabs([item], item, targetRole);
  const direction = zone === 'left' || zone === 'right' ? 'row' : 'column';
  const existingNode = leafNode(liveTargetSlot);
  const newNode = leafNode(newSlot);
  const splitPct = splitPercentForNewItem(item, zone, pct);
  const replacement = zone === 'right' || zone === 'bottom'
    ? splitNode(direction, existingNode, newNode, splitPct)
    : splitNode(direction, newNode, existingNode, splitPct);
  next[layoutTreeKey] = replaceLayoutLeaf(next[layoutTreeKey], liveTargetSlot, replacement);
  applyLayoutSlots(next, {
    focusSession: item,
    preservePlaceholderSlots: preserveRemovedSlot || targetRole.kind === paneRoleSide,
    prune: false,
  });
  return true;
}

async function splitSessionAtSlot(session, targetSlot, zone, sourceSlot = null, pct = null) {
  return splitLayoutItemAtSlot(session, targetSlot, zone, sourceSlot, pct);
}

function layoutSlotsWithoutUnrenderedPlaceholders(slots = layoutSlots) {
  const next = emptyLayoutSlots();
  const copy = node => {
    if (!node) return null;
    if (node.slot) {
      const slot = node.slot;
      if (!paneHasLayoutContent(slot, slots)) return null;
      // An empty group with no DOM rectangle is a Dockview bookkeeping artifact. A rendered
      // placeholder remains a real user-visible pane and must keep its position.
      if (paneIsPlaceholder(slot, slots) && !layoutSlotScreenRect(slot)) return null;
      next[slot] = paneStateForLayoutSlot(slot, slots);
      return leafNode(slot);
    }
    const children = (node.children || []).map(copy).filter(Boolean);
    if (children.length === 1) return children[0];
    if (children.length < 2) return null;
    return splitNode(node.split === 'column' ? 'column' : 'row', children[0], children[1], node.pct);
  };
  next[layoutTreeKey] = copy(slots[layoutTreeKey]);
  return compactLayoutSlots(next, {preservePlaceholderSlots: true});
}

function directionalRectValue(rect, edge) {
  if (!rect) return 0;
  if (Number.isFinite(Number(rect[edge]))) return Number(rect[edge]);
  if (edge === 'right') return Number(rect.left || 0) + Number(rect.width || 0);
  if (edge === 'bottom') return Number(rect.top || 0) + Number(rect.height || 0);
  return Number(rect[edge] || 0);
}

function directionalRectOverlap(firstStart, firstEnd, secondStart, secondEnd) {
  return Math.max(0, Math.min(firstEnd, secondEnd) - Math.max(firstStart, secondStart));
}

function layoutSlotsTouchingDirection(sourceSlot, zone, slots = layoutSlots) {
  const sourceRect = layoutSlotScreenRect(sourceSlot);
  if (!sourceRect) return [];
  const tolerance = directionalPaneAdjacencyTolerancePx;
  const sourceLeft = directionalRectValue(sourceRect, 'left');
  const sourceRight = directionalRectValue(sourceRect, 'right');
  const sourceTop = directionalRectValue(sourceRect, 'top');
  const sourceBottom = directionalRectValue(sourceRect, 'bottom');
  return layoutSlotKeys(slots).filter(targetSlot => {
    if (targetSlot === sourceSlot) return false;
    const targetRect = layoutSlotScreenRect(targetSlot);
    if (!targetRect) return false;
    const targetLeft = directionalRectValue(targetRect, 'left');
    const targetRight = directionalRectValue(targetRect, 'right');
    const targetTop = directionalRectValue(targetRect, 'top');
    const targetBottom = directionalRectValue(targetRect, 'bottom');
    if (zone === 'left') {
      return Math.abs(targetRight - sourceLeft) <= tolerance
        && directionalRectOverlap(sourceTop, sourceBottom, targetTop, targetBottom) > tolerance;
    }
    if (zone === 'right') {
      return Math.abs(targetLeft - sourceRight) <= tolerance
        && directionalRectOverlap(sourceTop, sourceBottom, targetTop, targetBottom) > tolerance;
    }
    if (zone === 'top') {
      return Math.abs(targetBottom - sourceTop) <= tolerance
        && directionalRectOverlap(sourceLeft, sourceRight, targetLeft, targetRight) > tolerance;
    }
    return Math.abs(targetTop - sourceBottom) <= tolerance
      && directionalRectOverlap(sourceLeft, sourceRight, targetLeft, targetRight) > tolerance;
  });
}

function directionalLocalSplitHasRoom(rect, zone) {
  if (zone === 'left' || zone === 'right') return rect.width / 2 >= minSplitPaneWidthPx();
  return rect.height / 2 >= minSplitPaneHeightPx();
}

function directionalLocalSplitAvailable(sourceSlot, zone, sourceRect, slots, targets) {
  const directTargets = Array.isArray(targets) ? targets : layoutSlotsTouchingDirection(sourceSlot, zone, slots);
  const finderOnly = directTargets.length === 1 && isFileExplorerItem(activeItemForSide(directTargets[0], slots));
  if (directTargets.length && !finderOnly) return false;
  const oppositeZone = zone === 'left' ? 'right'
    : zone === 'right' ? 'left'
      : zone === 'top' ? 'bottom'
        : 'top';
  // Finder/Differ is a reserved pane, not a peer tab target. It must not block creating a
  // local terminal split on the content side of its boundary.
  const oppositeContentTargets = layoutSlotsTouchingDirection(sourceSlot, oppositeZone, slots)
    .filter(slot => !isFileExplorerItem(activeItemForSide(slot, slots)));
  return oppositeContentTargets.length === 0 && directionalLocalSplitHasRoom(sourceRect, zone);
}

// Directional tab actions resolve visible pane geometry first. A layout tree can encode the same
// rendered grid in more than one way; users must get the same Move/Swap choices in both forms.
// If a side touches more than one leaf, moving into an arbitrary one would be surprising, so that
// direction is intentionally unavailable rather than using a hidden tree-order tie breaker.
function tabDirectionalActionCapabilities(item, sourceSlot = slotForItem(item), slots = layoutSlots) {
  const visibleSlots = layoutSlotsWithoutUnrenderedPlaceholders(slots);
  const sourceRect = sourceSlot ? layoutSlotScreenRect(sourceSlot) : null;
  const sourceRole = sourceSlot ? paneRoleForSlot(sourceSlot, slots) : paneRoleDefinition(paneRoleGeneric);
  const allowed = Boolean(
    isLayoutItem(item)
      && sourceSlot
      && !narrowSingleColumnMode()
      && !tabIsPinned(item)
      && sourceRect,
  );
  const result = {move: {}, swap: {}, targets: {}};
  for (const zone of ['left', 'right', 'top', 'bottom']) {
    if (!allowed) {
      result.move[zone] = false;
      result.swap[zone] = false;
      result.targets[zone] = null;
      continue;
    }
    if (sourceRole.kind === paneRoleSide && (zone === 'left' || zone === 'right')) {
      const targetSide = zone;
      const oppositeEdge = sourceRole.side !== targetSide;
      result.move[zone] = oppositeEdge;
      result.swap[zone] = false;
      result.targets[zone] = oppositeEdge ? sidePaneSlot(targetSide, slots) : null;
      continue;
    }
    const targets = layoutSlotsTouchingDirection(sourceSlot, zone, visibleSlots);
    if (targets.length === 1) {
      const targetSlot = targets[0];
      const targetRole = paneRoleForSlot(targetSlot, visibleSlots);
      const targetIsUsable = sourceRole.kind === paneRoleSide
        ? targetRole.kind === paneRoleSide && targetRole.side === sourceRole.side
        : targetRole.kind === paneRoleGeneric;
      const targetItem = activeItemForSide(targetSlot, visibleSlots);
      const targetHasTab = Boolean(targetItem);
      if (!targetIsUsable) {
        result.targets[zone] = null;
        result.move[zone] = directionalLocalSplitAvailable(sourceSlot, zone, sourceRect, visibleSlots, targets);
        result.swap[zone] = false;
        continue;
      }
      result.targets[zone] = targetSlot;
      result.move[zone] = true;
      result.swap[zone] = targetHasTab && !tabIsPinned(targetItem) && !paneIsPlaceholder(targetSlot, slots);
      continue;
    }
    result.targets[zone] = null;
    result.move[zone] = directionalLocalSplitAvailable(sourceSlot, zone, sourceRect, visibleSlots, targets);
    result.swap[zone] = false;
  }
  return Object.freeze({
    move: Object.freeze(result.move),
    swap: Object.freeze(result.swap),
    targets: Object.freeze(result.targets),
  });
}

// Compatibility adapter for callers that only need the Move availability map.
function tabSplitCapabilities(item, sourceSlot = slotForItem(item), slots = layoutSlots) {
  return tabDirectionalActionCapabilities(item, sourceSlot, slots).move;
}

function tabCanFillWorkspace(item, slots = layoutSlots) {
  const sourceSlot = slotForItem(item, slots);
  return Boolean(
    isLayoutItem(item)
      && sourceSlot
      && !slotIsSidePane(sourceSlot, slots)
      && layoutLeafSlots(slots[layoutTreeKey]).length > 1
      && !paneIsPlaceholder(sourceSlot, slots),
  );
}

function tabWorkspaceIsFilled(item) {
  return filledWorkspaceLayout?.item === item;
}

function toggleTabWorkspaceFill(item) {
  if (!isLayoutItem(item)) return false;
  if (tabWorkspaceIsFilled(item)) {
    const saved = filledWorkspaceLayout;
    filledWorkspaceLayout = null;
    applyLayoutSlots(cloneLayoutSlots(saved.slots), {
      focusSession: item,
      message: t('layout.status.restored', {item: itemLabel(item)}),
      preserveFilledWorkspaceLayout: true,
      preservePlaceholderSlots: true,
      prune: false,
    });
    return true;
  }
  if (!tabCanFillWorkspace(item)) return false;
  const sourceSlot = slotForItem(item);
  const content = emptyLayoutSlots();
  content[sourceSlot] = paneStateForLayoutSlot(sourceSlot);
  content[layoutTreeKey] = leafNode(sourceSlot);
  const next = layoutWithPreservedSidePanes(content);
  filledWorkspaceLayout = {item, slots: cloneLayoutSlots(layoutSlots)};
  applyLayoutSlots(next, {
    focusSession: item,
    message: t('layout.status.expanded', {item: itemLabel(item)}),
    preserveFilledWorkspaceLayout: true,
    preservePlaceholderSlots: true,
    prune: false,
  });
  return true;
}

async function moveLayoutItemDirectional(item, sourceSlot = slotForItem(item), zone) {
  const capabilities = tabDirectionalActionCapabilities(item, sourceSlot);
  if (capabilities.move[zone] !== true) return false;
  const sourceRole = paneRoleForSlot(sourceSlot);
  if (sourceRole.kind === paneRoleSide && (zone === 'left' || zone === 'right')) {
    return splitSessionAtLayoutBoundary(item, zone, sourceSlot);
  }
  const targetSlot = capabilities.targets[zone];
  if (targetSlot) {
    await moveSessionToSlot(item, targetSlot, sourceSlot, 0, {preserveSourcePlaceholder: true});
    return true;
  }
  return splitLayoutItemAtSlot(item, sourceSlot, zone, sourceSlot, null, {
    forceSplitEmpty: true,
    preserveSourcePlaceholder: true,
  });
}

async function swapLayoutItemDirectional(item, sourceSlot = slotForItem(item), zone) {
  const capabilities = tabDirectionalActionCapabilities(item, sourceSlot);
  const targetSlot = capabilities.targets[zone];
  if (capabilities.swap[zone] !== true || !targetSlot) return false;
  const targetItem = activeItemForSide(targetSlot);
  if (!targetItem) return false;
  const next = cloneLayoutSlots(layoutSlots);
  const sourceTabs = paneTabs(sourceSlot, next).map(tab => tab === item ? targetItem : tab);
  const targetTabs = paneTabs(targetSlot, next).map(tab => tab === targetItem ? item : tab);
  next[sourceSlot] = paneStateWithTabsForSlot(sourceSlot, sourceTabs, targetItem, next);
  next[targetSlot] = paneStateWithTabsForSlot(targetSlot, targetTabs, item, next);
  applyLayoutSlots(next, {focusSession: item, prune: false});
  return true;
}

// Existing callers use the old verb. Keep it as the one-line alias so Split and Move cannot drift.
async function splitLayoutItemDirectional(item, sourceSlot = slotForItem(item), zone) {
  return moveLayoutItemDirectional(item, sourceSlot, zone);
}

async function splitSessionAtLayoutBoundary(session, zone, sourceSlot = null, pct = null) {
  if (!isLayoutItem(session) || !layoutSplitZone(zone)) return false;
  const actualSourceSlot = sourceSlot || slotForItem(session);
  const sourceRole = actualSourceSlot ? paneRoleForSlot(actualSourceSlot) : paneRoleDefinition(paneRoleGeneric);
  let targetRole = paneRoleDefinition(paneRoleGeneric);
  if (sourceRole.kind === paneRoleSide) {
    if (!['left', 'right'].includes(zone) || sourceRole.side === zone) return false;
    const existingTarget = sidePaneSlot(zone);
    if (existingTarget) return moveSessionToSlot(session, existingTarget, actualSourceSlot, paneTabs(existingTarget).length);
    targetRole = paneRoleDefinition(paneRoleSide, zone);
    if (pct === null || pct === undefined || pct === '') {
      const sourceWidth = sidePaneWidthPercent(sourceRole.side, layoutSlots);
      pct = zone === paneSideRight ? 100 - sourceWidth : sourceWidth;
    }
  }
  if (!paneRoleAllowsItemTransfer(session, actualSourceSlot, null, layoutSlots, {targetRole})) return false;
  const next = layoutWithoutItem(session);
  const root = next[layoutTreeKey] || legacyLayoutTree(next);
  if (!root) {
    return moveSessionToSlot(session, actualSourceSlot || slotForNewSession(), actualSourceSlot);
  }
  const newSlot = nextLayoutSlot(next);
  next[newSlot] = paneStateWithTabs([session], session, targetRole);
  const newNode = leafNode(newSlot);
  const direction = layoutSplitDirectionForZone(zone);
  const splitPct = rootBoundarySplitPercent(root, zone, pct, next);
  next[layoutTreeKey] = splitRootPreservingSidePane(root, newNode, session, zone, pct, next)
    || (zone === 'right' || zone === 'bottom'
    ? splitNode(direction, root, newNode, splitPct)
    : splitNode(direction, newNode, root, splitPct));
  applyLayoutSlots(next, {focusSession: session, prune: false});
  return true;
}

async function splitSessionAtGutter(session, splitPath, zone, sourceSlot = null, pct = null) {
  if (!isLayoutItem(session) || !layoutSplitZone(zone)) return false;
  const actualSourceSlot = sourceSlot || slotForItem(session);
  if (!paneRoleAllowsItemTransfer(session, actualSourceSlot, null, layoutSlots, {
    targetRole: paneRoleDefinition(paneRoleGeneric),
  })) return false;
  const next = layoutWithoutItem(session);
  const root = next[layoutTreeKey] || legacyLayoutTree(next);
  const target = layoutNodeAtPath(splitPath, root);
  if (layoutNodeContainsSidePane(target, next)) return false;
  if (!root || !target?.children?.length) {
    return splitSessionAtLayoutBoundary(session, zone, actualSourceSlot, pct);
  }
  const newSlot = nextLayoutSlot(next);
  next[newSlot] = paneStateWithTabs([session], session, paneRoleDefinition(paneRoleGeneric));
  const replacement = splitLayoutNodeAtGutter(target, leafNode(newSlot), session, zone, pct);
  next[layoutTreeKey] = replaceLayoutNodeAtPath(root, splitPath, replacement);
  applyLayoutSlots(next, {focusSession: session, prune: false});
  return true;
}

function layoutSplitZone(zone) {
  return zone === 'top' || zone === 'bottom' || zone === 'left' || zone === 'right';
}

function layoutSplitDirectionForZone(zone) {
  return zone === 'left' || zone === 'right' ? 'row' : 'column';
}

function splitLayoutNodeAtGutter(node, newNode, session, zone, pct = null) {
  const direction = node.split === 'column' ? 'column' : 'row';
  const first = node.children?.[0] || null;
  const second = node.children?.[1] || null;
  if (!first || !second) return newNode;
  const insertAfterFirst = direction === 'row' ? zone === 'left' : zone === 'top';
  if (insertAfterFirst) {
    const nestedZone = direction === 'row' ? 'right' : 'bottom';
    return splitNode(direction, splitNode(direction, first, newNode, splitPercentForNewItem(session, nestedZone, pct)), second, node.pct);
  }
  const nestedZone = direction === 'row' ? 'left' : 'top';
  return splitNode(direction, first, splitNode(direction, newNode, second, splitPercentForNewItem(session, nestedZone, pct)), node.pct);
}

function replaceLayoutLeaf(node, slot, replacement) {
  if (!node) return replacement;
  if (node.slot) return node.slot === slot ? replacement : node;
  const children = (node.children || []).map(child => replaceLayoutLeaf(child, slot, replacement));
  return splitNode(node.split === 'column' ? 'column' : 'row', children[0], children[1], node.pct);
}

function replaceLayoutNodeAtPath(node, path, replacement) {
  if (!path) return replacement;
  if (!node?.children) return node;
  const parts = String(path).split('.');
  const index = Number(parts[0]);
  if (!Number.isInteger(index) || index < 0 || index > 1) return node;
  const children = [...node.children];
  children[index] = replaceLayoutNodeAtPath(children[index], parts.slice(1).join('.'), replacement);
  return splitNode(node.split === 'column' ? 'column' : 'row', children[0], children[1], node.pct);
}

function activatePaneTab(side, session, options = {}) {
  if (!layoutSlotKeys().includes(side) || !itemInLayout(session)) return;
  if (options.userInitiated === true) {
    dismissSessionToasts(session);
    acknowledgeNotificationTarget(session);
  }
  if (options.userInitiated === true && isTmuxSession(session)) {
    noteFileExplorerChangesSessionInteraction(session);
  }
  if (options.userInitiated === true && isFileEditorItem(session)) {
    const path = fileItemPath(session);
    const owners = openFileOwnerSessionsForPath(path);
    const owner = changedFileOwnerSessionForPath(path, {owners}) || (owners.length === 1 ? owners[0] : '');
    if (owner) noteFileExplorerChangesSessionInteraction(owner);
  }
  recordTabActivation(session);
  const previous = activeItemForSide(side);
  if (previous && previous !== session) capturePaneViewStateForItemIfPresent(previous);
  if (isFileEditorItem(session)) {
    activeFile = fileItemPath(session);
    updateFileExplorerCurrentFileHighlight();
  }
  if (!shareViewMode && isTmuxSession(session)) {
    const item = terminals.get(session);
    if (item?.term) sharePublish('host-resize', {session, rows: item.term.rows, cols: item.term.cols});
  }
  sharePublish('active-tab', {slot: side, item: session});
  scheduleShareTopologySnapshot('tab-activation');
  if (activeItemForSide(side) === session) {
    // A user-initiated tab switch is navigation. Record focus only after the layout already names
    // this item active so Tabber never renders the transient old-active/new-focus combination.
    setFocusedPanelItem(session, {userInitiated: options.userInitiated === true});
    if (isFileExplorerItem(session)) activateFileExplorerSurface(session);
    focusPanel(session, {userInitiated: options.userInitiated === true});
    return;
  }
  const next = emptyLayoutSlots();
  next[layoutTreeKey] = layoutSlots[layoutTreeKey];
  for (const key of layoutSlotKeys()) next[key] = paneStateForLayoutSlot(key);
  next[side].active = session;
  applyLayoutSlots(next, {focusSession: session});
  setFocusedPanelItem(session, {userInitiated: options.userInitiated === true});
  if (isFileExplorerItem(session)) activateFileExplorerSurface(session);
  if (options.userInitiated && isTmuxSession(session)) focusTerminalFromUserAction(session, 25);
}

async function selectSession(session, options = {}) {
  if (options.userInitiated === true && isTmuxSession(session)) {
    noteFileExplorerChangesSessionInteraction(session);
  }
  if (isFileEditorItem(session)) {
    activeFile = fileItemPath(session);
    updateFileExplorerCurrentFileHighlight();
  }
  if (layoutIsFileSurfaceItem(session)) {
    await openFileSurfacePane(session);
    scheduleFileExplorerActiveTabSync();
    return;
  }
  if (activeSessions.includes(session)) {
    focusPanel(session, {userInitiated: options.userInitiated === true});
    return;
  }
  if (isTmuxSession(session) && filesOnlySlotForSession(session)) {
    await placeTmuxSession(session);
    return;
  }
  await activateTabInExistingPane(session);
}

function layoutPaneTabTraversalPositions(slots = layoutSlots) {
  return layoutLeafSlots(slots?.[layoutTreeKey])
    .flatMap(slot => paneTabs(slot, slots).map(item => ({slot, item})))
    .filter(position => position.item);
}

function renderedPaneTabTraversalPositions(slots = layoutSlots) {
  const groups = Array.from(grid?.querySelectorAll?.('.dv-groupview') || []);
  const knownSlots = new Set(layoutSlotKeys(slots));
  const seenSlots = new Set();
  const records = [];
  groups.forEach((group, index) => {
    const slot = typeof dockviewSlotForGroupElement === 'function' ? dockviewSlotForGroupElement(group) : '';
    if (!knownSlots.has(slot) || seenSlots.has(slot)) return;
    const rect = group.getBoundingClientRect?.() || {};
    const width = Number(rect.width || 0);
    const height = Number(rect.height || 0);
    if (width <= 0 && height <= 0) return;
    seenSlots.add(slot);
    records.push({
      slot,
      group,
      index,
      left: Number.isFinite(Number(rect.left)) ? Number(rect.left) : index,
      top: Number.isFinite(Number(rect.top)) ? Number(rect.top) : index,
    });
  });
  if (!records.length) return [];
  records.sort((a, b) => (a.left - b.left) || (a.top - b.top) || (a.index - b.index));
  const positions = [];
  const seenItems = new Set();
  const appendItem = (slot, item) => {
    if (!item || seenItems.has(item) || !paneTabs(slot, slots).includes(item)) return;
    seenItems.add(item);
    positions.push({slot, item});
  };
  for (const record of records) {
    const renderedTabs = Array.from(record.group.querySelectorAll?.('.dockview-pane-tab') || [])
      .map(tab => tab?.dataset?.paneTab || '')
      .filter(Boolean);
    const tabItems = renderedTabs.length ? renderedTabs : paneTabs(record.slot, slots);
    tabItems.forEach(item => appendItem(record.slot, item));
  }
  for (const position of layoutPaneTabTraversalPositions(slots)) appendItem(position.slot, position.item);
  return positions;
}

function paneTabTraversalPositions(slots = layoutSlots) {
  const rendered = renderedPaneTabTraversalPositions(slots);
  return rendered.length ? rendered : layoutPaneTabTraversalPositions(slots);
}

function adjacentPaneTabPosition(direction, options = {}) {
  const slots = options.slots || layoutSlots;
  const positions = paneTabTraversalPositions(slots);
  if (positions.length < 2) return null;
  const currentItem = String(options.item || visualActivePaneItem() || activePaneItems(slots)[0] || '');
  const currentSlot = options.slot || slotForItem(currentItem, slots);
  if (!currentItem || !currentSlot) return null;
  const index = positions.findIndex(position => position.slot === currentSlot && position.item === currentItem);
  if (index < 0) return null;
  const offset = direction < 0 ? -1 : 1;
  const nextIndex = index + offset;
  if (nextIndex < 0 || nextIndex >= positions.length) return null;
  return positions[nextIndex] || null;
}

function selectAdjacentPaneTab(direction, options = {}) {
  const target = adjacentPaneTabPosition(direction, options);
  if (!target?.item || !target.slot) return false;
  const currentItem = String(options.item || visualActivePaneItem() || '');
  if (target.item === currentItem && target.slot === (options.slot || slotForItem(currentItem))) return false;
  const activationOptions = {...options};
  delete activationOptions.item;
  delete activationOptions.slot;
  delete activationOptions.slots;
  activatePaneTab(target.slot, target.item, activationOptions);
  return true;
}

function sessionAgentKind(session) {
  const info = transcriptMetadataState.payload.sessions?.[session];
  const agent = info?.agents?.find(item => item.transcript) || info?.agents?.[0];
  const kind = String(agent?.kind || '').toLowerCase();
  return kind === 'claude' || kind === 'codex' ? kind : '';
}

function agentIcon(kind, options = {}) {
  const name = agentLabel(kind);
  const label = options.label || name;
  const labelAttr = label ? ` aria-label="${esc(label)}" title="${esc(label)}"` : '';
  const extraClass = String(options.className || '').trim();
  const classes = agentKind => ['agent-icon', agentKind, extraClass].filter(Boolean).join(' ');
  if (kind === 'codex') {
    return `<span class="${esc(classes('codex'))}"${labelAttr}>${codexIcon()}</span>`;
  }
  if (kind === 'claude') {
    return `<span class="${esc(classes('claude'))}"${labelAttr}>${claudeIcon()}</span>`;
  }
  return '';
}

function codexIcon() {
  return `<svg viewBox="0 0 24 24" aria-hidden="true">
    <path fill="#667ef8" d="M7.3 20.8c-3.1 0-5.7-2.4-5.9-5.5-.2-2.4 1.1-4.6 3.1-5.7C4.8 5.9 7.9 3 11.8 3c3.3 0 6.2 2.2 7 5.4 2.4.7 4 2.8 4 5.4 0 3.2-2.6 5.8-5.8 5.8-.9 1.1-2.2 1.8-3.8 1.8-1.2 0-2.3-.4-3.1-1.1-.8.3-1.8.5-2.8.5z"/>
    <path fill="#fff" d="M6.4 8.2c.5-.5 1.2-.5 1.7 0l2.8 2.8c.5.5.5 1.2 0 1.7l-2.8 2.8c-.5.5-1.2.5-1.7 0s-.5-1.2 0-1.7l1.9-1.9-1.9-1.9c-.5-.5-.5-1.3 0-1.8zM13 13.2h5.1c.7 0 1.2.5 1.2 1.2s-.5 1.2-1.2 1.2H13c-.7 0-1.2-.5-1.2-1.2s.5-1.2 1.2-1.2z"/>
  </svg>`;
}

function claudeIcon() {
  return `<svg viewBox="0 0 24 24" aria-hidden="true">
    <rect width="24" height="24" rx="5.5" fill="#cf7554"/>
    <g fill="#fff7f1">
      <path d="M11.1 2.4h1.8l1.1 7.9-2 .6-2-.6 1.1-7.9z"/>
      <path d="m17.8 4.3 1.4 1.1-4.3 6.7-2.1-1.3 5-6.5z"/>
      <path d="m21.5 10.2.3 1.8-8.2 2-1-2.3 8.9-1.5z"/>
      <path d="m20.2 16.8-1.1 1.4-6.7-4.3 1.3-2.1 6.5 5z"/>
      <path d="m13.8 21.5-1.8.3-2-8.2 2.3-1 1.5 8.9z"/>
      <path d="m6.2 19.7-1.4-1.1 4.3-6.7 2.1 1.3-5 6.5z"/>
      <path d="m2.5 13.8-.3-1.8 8.2-2 1 2.3-8.9 1.5z"/>
      <path d="m3.8 7.2 1.1-1.4 6.7 4.3-1.3 2.1-6.5-5z"/>
      <circle cx="12" cy="12" r="2.2"/>
    </g>
  </svg>`;
}

function agentName(kind) {
  return kind === 'codex' ? 'Codex' : kind === 'claude' ? 'Claude' : kind === 'term' ? 'Xterm' : '';
}

function numericSessionName(session) {
  const match = String(session).match(/^[1-9]\d*$/);
  return match ? Number(match[0]) : null;
}

function sessionLabelAssignments() {
  const assigned = new Map();
  const used = new Set();
  for (const session of visibleSessions) {
    const numeric = numericSessionName(session);
    if (numeric !== null) {
      assigned.set(session, String(numeric));
      used.add(numeric);
    }
  }

  const backfill = [];
  for (let value = 9; value >= 1; value -= 1) {
    if (!used.has(value)) backfill.push(value);
  }

  let overflow = 10;
  for (const session of visibleSessions) {
    if (assigned.has(session)) continue;
    let label = backfill.length ? backfill.shift() : overflow;
    while (used.has(label)) label += 1;
    assigned.set(session, String(label));
    used.add(label);
    if (label >= overflow) overflow = label + 1;
  }
  return assigned;
}

function sessionForLabel(label) {
  const text = String(label);
  for (const [session, assignedLabel] of sessionLabelAssignments()) {
    if (assignedLabel === text) return session;
  }
  return null;
}

function sessionShortcutLabel(session) {
  const assigned = sessionLabelAssignments().get(session);
  if (assigned) return assigned;
  const numeric = numericSessionName(session);
  if (numeric !== null) return String(numeric);
  return String(session);
}

function sessionLabel(session) {
  const numeric = numericSessionName(session);
  return numeric !== null ? String(numeric) : String(session);
}

function shortText(value, limit = 96) {
  const text = String(value || '').replace(/\s+/g, ' ').trim();
  if (text.length <= limit) return text;
  return `${text.slice(0, Math.max(0, limit - 3))}...`;
}

function shortBranch(value) {
  const text = String(value || '');
  if (text.length <= 46) return text;
  return `${text.slice(0, 18)}...${text.slice(-25)}`;
}

function linkHtml(url, label, title = '', className = '') {
  if (!url) return `<span>${esc(label)}</span>`;
  const titleAttr = title ? ` title="${esc(title)}"` : '';
  const classAttr = className ? ` class="${esc(className)}"` : '';
  return `<a href="${esc(url)}" target="_blank" rel="noreferrer noopener" draggable="false"${titleAttr}${classAttr}>${esc(label)}</a>`;
}

function pullRequestStatusLabel(pr) {
  if (!pr) return '';
  if (pr.status_label) return pr.status_label;
  if (pr.source_only) return '';
  if (pr.draft) return 'draft';
  if (pr.merged || pr.merged_at) return 'merged';
  return pr.state || '';
}

function pullRequestStatusDisplay(pr) {
  const status = pullRequestStatusLabel(pr);
  if (!status) return '';
  const lifecycle = pullRequestLifecycleStatus(pr);
  if (lifecycle.state && lifecycle.state !== 'open') return lifecycle.text;
  const key = status.toLowerCase();
  if (key === 'unknown') return '';
  if (['draft', 'closed', 'open'].includes(key)) return lifecycle.text;
  const ci = pullRequestCiStatus(pr);
  if (ci) return ci.text;
  return status.replace(/\bci\b/gi, 'CI').toUpperCase();
}

function pullRequestIsMerged(pr) {
  if (!pr) return false;
  if (pr.merged === true || pr.merged_at) return true;
  return /\bmerged\b/.test(pullRequestStatusLabel(pr).toLowerCase());
}

const PULL_REQUEST_LIFECYCLE_SPECS = Object.freeze({
  merged: Object.freeze({className: 'pr-status-merged', key: 'pr.status.merged'}),
  draft: Object.freeze({className: 'pr-status-draft', key: 'pr.status.draft'}),
  closed: Object.freeze({className: 'pr-status-closed', key: 'pr.status.closed'}),
  open: Object.freeze({className: 'pr-status-open', key: 'pr.status.open'}),
});

function pullRequestLifecycleState(pr) {
  if (!pr?.number) return '';
  if (pullRequestIsMerged(pr)) return 'merged';
  const status = pullRequestStatusLabel(pr).toLowerCase();
  if (pr.draft === true || /\bdraft\b/.test(status)) return 'draft';
  if (/\bclosed\b/.test(status)) return 'closed';
  return 'open';
}

function pullRequestLifecycleStatus(pr) {
  const state = pullRequestLifecycleState(pr);
  const spec = PULL_REQUEST_LIFECYCLE_SPECS[state];
  return spec ? {state, className: spec.className, text: t(spec.key)} : {state: '', className: '', text: ''};
}

function pullRequestInlineStatusDisplay(pr) {
  const lifecycle = pullRequestLifecycleState(pr);
  if (lifecycle === 'merged') return '';
  const status = pullRequestStatusLabel(pr).trim().toLowerCase();
  if (lifecycle === 'open' && status === 'open') return '';
  return pullRequestStatusDisplay(pr);
}

function pullRequestLinkLabel(pr) {
  const status = pullRequestInlineStatusDisplay(pr);
  return `#${pr.number}${status ? ` ${status}` : ''}`;
}

const PULL_REQUEST_CI_STATUS_SPECS = Object.freeze({
  passing: Object.freeze({className: 'pr-status-passing', key: 'pr.ci.passing', fallback: 'CI passing'}),
  failing: Object.freeze({className: 'pr-status-failing', key: 'pr.ci.failing', fallback: 'CI failing'}),
  pending: Object.freeze({className: 'pr-status-pending', key: 'pr.ci.pending', fallback: 'CI pending'}),
});

function pullRequestCiState(pr) {
  if (!pr || pullRequestIsMerged(pr)) return '';
  const checks = pr.checks && typeof pr.checks === 'object' ? pr.checks : {};
  const candidates = [checks.state, checks.status_label, checks.conclusion, pr.status_label];
  for (const value of candidates) {
    const raw = String(value || '').trim().toLowerCase();
    if (!raw || raw === 'unknown' || raw === 'ci unknown') continue;
    if (/\b(failure|failing|failed|red|error|cancelled|timed_out|action_required)\b/.test(raw)) return 'failing';
    if (/\b(pending|queued|in_progress|running|waiting|requested)\b/.test(raw)) return 'pending';
    if (/\b(success|passing|passed|green)\b/.test(raw)) return 'passing';
  }
  return '';
}

function pullRequestCiStatus(pr) {
  const state = pullRequestCiState(pr);
  const spec = PULL_REQUEST_CI_STATUS_SPECS[state];
  if (!spec) return null;
  const descriptor = {key: spec.key, params: {}, fallback: spec.fallback};
  return {state, className: spec.className, descriptor, text: messageDescriptorText(descriptor)};
}

function pullRequestStatusClass(pr) {
  const lifecycle = pullRequestLifecycleStatus(pr);
  if (lifecycle.state && lifecycle.state !== 'open') return lifecycle.className;
  const ci = pullRequestCiStatus(pr);
  if (ci) return ci.className;
  return 'pr-status-unknown';
}

function pullRequestStatusBadgeHtml(session, text, statusClass, options = {}) {
  const label = String(text || '').trim();
  if (!label) return '';
  const labelHtml = options.labelHtml === undefined ? esc(label) : String(options.labelHtml || '');
  const stateClass = statusClass || 'pr-status-unknown';
  let classes;
  if (options.variant === 'meta') {
    classes = `meta-pr-status ${stateClass}`;
  } else if (options.variant === 'muted') {
    classes = 'meta-muted';
  } else {
    const extraClass = String(options.extraClass || '').trim();
    classes = metadataBadgeClasses(
      session,
      options.kind || 'status',
      ['ci-indicator', 'tab-symbol', extraClass, stateClass].filter(Boolean).join(' '),
    );
  }
  return `<span class="${esc(classes)}">${labelHtml}</span>`;
}

function pullRequestStatusIndicatorHtml(session, pr) {
  if (!pr?.number) return '';
  const lifecycle = pullRequestLifecycleStatus(pr);
  if (!['draft', 'closed'].includes(lifecycle.state)) return '';
  return pullRequestStatusBadgeHtml(session, lifecycle.text, lifecycle.className);
}

function pullRequestCiIndicatorHtml(session, pr) {
  const ci = pullRequestCiStatus(pr);
  if (!ci) return '';
  return pullRequestStatusBadgeHtml(session, 'CI', ci.className, {kind: 'ci'});
}

function pullRequestNumberIndicatorHtml(session, pr) {
  if (!pr?.number) return '';
  // No native title — the rich custom session popover already shows PR #, CI, and review state
  // (avoid a duplicate browser tooltip alongside the popover).
  const classes = pullRequestIsMerged(pr)
    ? metadataBadgeClasses(session, 'status', `ci-indicator tab-symbol pr-number-chip ${pullRequestStatusClass(pr)}`)
    : 'ci-indicator tab-symbol pr-number-chip';
  return `<span class="${esc(classes)}">#${esc(String(pr.number))}</span>`;
}

// #38: GitHub reviewDecision (APPROVED / CHANGES_REQUESTED / REVIEW_REQUIRED) per PR.
function pullRequestReviewDecision(pr) {
  return String(pr?.review_decision || '').toUpperCase();
}

function pullRequestApprovalClass(decision) {
  if (decision === 'APPROVED') return 'pr-review-approved';
  if (decision === 'CHANGES_REQUESTED') return 'pr-review-changes';
  if (decision === 'REVIEW_REQUIRED') return 'pr-review-required';
  return '';
}

function pullRequestApprovalLabel(decision) {
  if (decision === 'APPROVED') return t('pr.review.approvedShort');
  if (decision === 'CHANGES_REQUESTED') return t('pr.review.changesShort');
  if (decision === 'REVIEW_REQUIRED') return t('pr.review.reviewShort');
  return '';
}

function pullRequestApprovalIndicatorHtml(session, pr) {
  if (!pr?.number) return '';
  // No review badge once the PR is merged/closed (review state no longer actionable).
  if (['merged', 'closed'].includes(pullRequestLifecycleState(pr))) return '';
  const decision = pullRequestReviewDecision(pr);
  const cls = pullRequestApprovalClass(decision);
  if (!cls) return '';
  const label = pullRequestApprovalLabel(decision);
  // No native title — the session popover carries the review state (no duplicate tooltip).
  return pullRequestStatusBadgeHtml(session, label, cls, {kind: 'review', extraClass: 'pr-review-chip'});
}

// review status + reviewer(s) for the session popover PR row ("Approved by alice" /
// "Changes requested by bob" / "Review required"). Reuses the meta-pr-status color classes.
function pullRequestReviewInlineHtml(pr) {
  const decision = pullRequestReviewDecision(pr);
  if (!decision) return '';
  const reviewers = Array.isArray(pr?.review_reviewers) ? pr.review_reviewers : [];
  const loginsFor = state => reviewers
    .filter(reviewer => String(reviewer?.state || '').toUpperCase() === state)
    .map(reviewer => reviewer.login)
    .filter(Boolean);
  const by = logins => (logins.length ? t('pr.by', {logins: logins.join(', ')}) : '');
  if (decision === 'APPROVED') {
    const text = `${t('pr.approved')}${by(loginsFor('APPROVED'))}`;
    return pullRequestStatusBadgeHtml('', text, 'pr-status-passing', {variant: 'meta'});
  }
  if (decision === 'CHANGES_REQUESTED') {
    const text = `${t('pr.changesRequested')}${by(loginsFor('CHANGES_REQUESTED'))}`;
    return pullRequestStatusBadgeHtml('', text, 'pr-status-failing', {variant: 'meta'});
  }
  if (decision === 'REVIEW_REQUIRED') {
    return pullRequestStatusBadgeHtml('', t('pr.reviewRequired'), '', {variant: 'muted'});
  }
  return '';
}

function pullRequestLinkHtml(pr) {
  return linkHtml(pr.url, pullRequestLinkLabel(pr), pr.title || pr.description || '', pullRequestStatusClass(pr));
}

function pullRequestAuthorHtml(pr) {
  const author = String(pr?.author_login || '').trim();
  return author ? `<span class="meta-muted">${esc(t('pr.authorBy', {author}))}</span>` : '';
}

function pullRequestChecksHtml(pr) {
  const ci = pullRequestCiStatus(pr);
  if (!ci) return '';
  const checks = pr?.checks && typeof pr.checks === 'object' ? pr.checks : {};
  const parts = [pullRequestStatusBadgeHtml('', ci.text, ci.className, {variant: 'meta'})];
  const checkLinks = items => (items || []).map(item => (
    item?.name ? linkHtml(item.url || '', item.name, item.state || '') : ''
  )).filter(Boolean).join(', ');
  const failing = checkLinks(checks.failing);
  const pending = checkLinks(checks.pending);
  if (failing) parts.push(`<span class="meta-muted">${esc(t('pr.checks.failing'))}: ${failing}</span>`);
  if (pending) parts.push(`<span class="meta-muted">${esc(t('pr.checks.pending'))}: ${pending}</span>`);
  if (Number.isFinite(checks.total)) parts.push(`<span class="meta-muted">${esc(t('pr.checks.count', {count: checks.total}))}</span>`);
  return metaJoin(parts);
}

function activeWindowPaneForProjectMeta(session, info) {
  const panes = Array.isArray(info?.panes) ? info.panes : [];
  return panes.length ? terminalDisplayPane(info, session) : null;
}

function repoSummaryAsGit(repo) {
  return gitFromRepoSummary(repo);
}

function projectMetaContextOverridesPrimaryPullRequest(info, contextGit) {
  return Boolean(displayPullRequestForGit(info, contextGit)?.number);
}

function projectMetaSelection(session, info) {
  const explicitRoot = repoRootKey(sessionRepoDisplayRoot.get(session));
  const activePane = activeWindowPaneForProjectMeta(session, info);
  const activeTarget = String(activePane?.target || '');
  // The active TmuxWindow's PathObservation owns the Info Bar context. Browser-selected terminal
  // state and auto-approve status are presentation inputs only; neither may recreate a parallel
  // per-window Git owner or displace the active tmux window's canonical worktree.
  const workSummary = sessionWorkSummary(session, info, {tmuxTarget: explicitRoot ? '' : activeTarget});
  const repos = workSummary.repositories;
  const activePath = normalizeDirectoryPath(activePane?.current_path || workSummary.selectedPath || '');
  const hasActiveTmuxTarget = Boolean(activeTarget);
  const primaryRoot = repoRootKey(workSummary.git?.root);
  const primaryRepoIndex = primaryRoot ? repos.findIndex(repo => repoRootKey(repo.root) === primaryRoot) : -1;
  let repoIndex = selectedSessionRepoIndex(session, info);
  const hasPinnedRepoSelection = selectedSessionRepoIndex(session, info) >= 0 && Boolean(sessionRepoDisplayRoot.get(session));
  if (!explicitRoot && !hasPinnedRepoSelection && hasActiveTmuxTarget && primaryRepoIndex >= 0) {
    repoIndex = primaryRepoIndex;
  } else if (!explicitRoot && !hasPinnedRepoSelection && hasActiveTmuxTarget && activePath && repos.length) {
    const activeRepoIndex = repos.findIndex(repo => repo?.root && pathIsInsideDirectory(activePath, repo.root));
    const activeRepoGit = activeRepoIndex >= 0 ? repoSummaryAsGit(repos[activeRepoIndex]) : null;
    if (activeRepoIndex >= 0 && projectMetaContextOverridesPrimaryPullRequest(info, activeRepoGit)) repoIndex = activeRepoIndex;
  }
  let selectedRepo = repoIndex >= 0 ? repos[repoIndex] : null;
  let git = selectedRepo ? repoSummaryAsGit(selectedRepo) : displayedSessionGit(session, info);
  let repoSwitchRepos = repos;
  let fullPath = selectedRepo?.cwd || selectedRepo?.root || panelFullPath(session, info);
  if (!explicitRoot && activePane && git?.root && activePath && !pathIsInsideDirectory(activePath, git.root)) {
    git = null;
    selectedRepo = null;
    repoIndex = -1;
    repoSwitchRepos = [];
    fullPath = activePath;
  }
  return {repos: repoSwitchRepos, repoIndex, selectedRepo, git, fullPath};
}

function panelFullPath(session, info) {
  const summary = sessionWorkSummary(session, info);
  const git = summary.git;
  const activePane = activeWindowPaneForProjectMeta(session, info);
  if (activePane?.current_path) return activePane.current_path;
  const panes = Array.isArray(info?.panes) ? info.panes : [];
  const nonHomePane = panes.find(pane => pane?.current_path && pane.current_path !== homePath && !['claude', 'codex'].includes(String(pane.command || '').toLowerCase()));
  if (nonHomePane?.current_path) return nonHomePane.current_path;
  if (git?.cwd) return git.cwd;
  if (git?.root) return git.root;
  if (summary.selectedPath) return summary.selectedPath;
  if (info?.selected_pane?.current_path) return info.selected_pane.current_path;
  return '';
}

function compactHomePath(path) {
  const text = String(path || '').replace(/\/+$/, '');
  const home = String(homePath || '').replace(/\/+$/, '');
  if (!text || !home) return text;
  if (text === home) return '~';
  if (text.startsWith(`${home}/`)) return `~/${text.slice(home.length + 1)}`;
  return text;
}

function projectMetaParts(session, info, options = {}) {
  const summary = sessionWorkSummary(session, info);
  const {repos, repoIndex, selectedRepo, git, fullPath} = projectMetaSelection(session, info);
  const showingPrimaryGit = !selectedRepo || repoRootKey(git?.root) === repoRootKey(selectedRepo.root);
  const metadataParts = [];
  const fullText = options.fullText === true;
  const repoSwitchHtml = repos.length > 1 ? (() => {
    const position = Math.max(0, repoIndex) + 1;
    const switchLabel = `${position}/${repos.length}`;
    return `<span class="meta-repo-switch" aria-label="${esc(t('detail.repos.switch', {position, count: repos.length}))}">
      <button type="button" class="btn-base meta-repo-cycle" data-repo-cycle="${esc(session)}" data-repo-cycle-dir="-1" title="${esc(t('detail.repos.previous'))}" aria-label="${esc(t('detail.repos.previous'))}">&lt;</button>
      <button type="button" class="btn-base meta-repo-chip" data-repo-chip="${esc(session)}" title="${esc(t('detail.repos.more', {count: repos.length - 1}))}" aria-label="${esc(t('detail.repos.switch', {position, count: repos.length}))}">${esc(switchLabel)}</button>
      <button type="button" class="btn-base meta-repo-cycle" data-repo-cycle="${esc(session)}" data-repo-cycle-dir="1" title="${esc(t('detail.repos.next'))}" aria-label="${esc(t('detail.repos.next'))}">&gt;</button>
    </span>`;
  })() : '';
  if (!git) {
    if (fullPath) metadataParts.push(`<span class="meta-path">${esc(compactHomePath(fullPath))}</span>`);
    metadataParts.push(`<span class="meta-muted">${esc(t('git.noCheckout'))}</span>`);
    return {repoSwitchHtml, metadataParts};
  }
  const prGit = selectedRepo ? gitFromRepoSummary(selectedRepo) : git;
  const pr = displayPullRequestForGit(info, prGit);
  if (pr?.number) metadataParts.push(pullRequestLinkHtml(pr));
  if (showingPrimaryGit && (!selectedRepo || repoRootKey(selectedRepo.root) === repoRootKey(summary.git?.root))) {
    for (const issue of summary.linearIssues) {
      const state = issue.state ? ` ${issue.state}` : '';
      metadataParts.push(linkHtml(issue.url, `${issue.identifier}${state}`, issue.title || ''));
    }
  }
  if (git.branch) metadataParts.push(`<span class="meta-branch">${esc(fullText ? git.branch : shortBranch(git.branch))}</span>`);
  if (fullPath) metadataParts.push(`<span class="meta-path">${esc(compactHomePath(fullPath))}</span>`);
  if (Number.isFinite(git.behind) && git.behind > 0) metadataParts.push(`<span class="meta-muted">${esc(t('git.behind', {count: git.behind}))}</span>`);
  if (Number.isFinite(git.ahead) && git.ahead > 0) metadataParts.push(`<span class="meta-muted">${esc(t('git.ahead', {count: git.ahead}))}</span>`);
  if (Number.isFinite(git.dirty_count)) metadataParts.push(`<span class="meta-muted">${esc(t('git.dirty', {count: git.dirty_count}))}</span>`);
  if (pr?.number) {
    const ci = pullRequestCiStatus(pr);
    if (ci) metadataParts.push(pullRequestStatusBadgeHtml('', ci.text, ci.className, {variant: 'meta'}));
  }
  const desc = pr?.title || pr?.description || (showingPrimaryGit ? summary.linearIssues.find(issue => issue.title)?.title : '');
  if (desc) {
    const descText = fullText ? String(desc || '').replace(/\s+/g, ' ').trim() : shortText(desc, 160);
    if (descText) metadataParts.push(`<span class="meta-desc">${esc(descText)}</span>`);
  }
  if (!metadataParts.length) metadataParts.push(`<span class="meta-muted">${esc(t('git.checkoutDetected'))}</span>`);
  return {repoSwitchHtml, metadataParts};
}

function projectMetaHtml(session, info, options = {}) {
  const {repoSwitchHtml, metadataParts} = projectMetaParts(session, info, options);
  return metaJoin([repoSwitchHtml, ...metadataParts]);
}

function paneInfoBarMetaParts(session, info) {
  const {repoSwitchHtml, metadataParts} = projectMetaParts(session, info, {fullText: true});
  const scrollHtml = metaJoin(metadataParts);
  return {
    controlsHtml: repoSwitchHtml,
    metadataHtml: scrollHtml
    ? `<span class="pane-info-bar-scroll-viewport"><span class="pane-info-bar-scroll-text">${scrollHtml}</span></span>`
    : '',
  };
}

function paneInfoBarMetaHtml(session, info) {
  return paneInfoBarMetaParts(session, info).metadataHtml;
}

const repoSelectorControlSelector = '[data-repo-cycle], [data-repo-chip]';

function refreshSessionRepoDisplay(session) {
  updatePanelHeader(session, transcriptMetadataState.payload.sessions?.[session]);
  renderSessionButtons();
  renderPaneTabStrips();
}

function activateRepoSelectorControl(event, button, panelSession) {
  event.preventDefault();
  event.stopPropagation();
  const cycleSession = button.dataset.repoCycle;
  if (cycleSession !== undefined) {
    const session = cycleSession || panelSession;
    cycleSessionRepoDisplay(session, transcriptMetadataState.payload.sessions?.[session], button.dataset.repoCycleDir || 1);
    refreshSessionRepoDisplay(session);
    return;
  }
  const session = button.dataset.repoChip || panelSession;
  showRepoChipMenu(session, event.clientX, event.clientY);
}

// C9: popover listing every repo a session touches (focused first), each row: path, branch, dirty,
// ahead/behind. Clicking a row scopes the Finder to that repo. Reuses the shared context-menu controller.
function repoChipMenuRowHtml(repo) {
  const label = compactHomePath(repo.root || '');
  const status = [];
  if (Number.isFinite(repo.dirty_count) && repo.dirty_count > 0) status.push(`<span class="meta-muted">${esc(t('git.dirty', {count: repo.dirty_count}))}</span>`);
  if (Number.isFinite(repo.ahead) && repo.ahead > 0) status.push(`<span class="meta-muted">${esc(t('git.ahead', {count: repo.ahead}))}</span>`);
  if (Number.isFinite(repo.behind) && repo.behind > 0) status.push(`<span class="meta-muted">${esc(t('git.behind', {count: repo.behind}))}</span>`);
  const primary = repo.primary ? ' repo-chip-row-primary' : '';
  return `<button type="button" class="repo-chip-row${primary}" data-repo-chip-open="${esc(repo.root || '')}">
    <span class="repo-chip-path">${esc(label)}</span>
    <span class="repo-chip-branch meta-branch">${esc(shortBranch(repo.branch || ''))}</span>
    <span class="repo-chip-status">${status.join('')}</span>
  </button>`;
}

function showRepoChipMenu(session, x, y) {
  const info = transcriptMetadataState.payload.sessions?.[session];
  const repos = sessionRepoSummaries(info);
  if (repos.length < 2) return;
  const menu = document.createElement('div');
  menu.className = 'terminal-context-menu repo-chip-menu';
  menu.setAttribute('role', 'menu');
  menu.innerHTML = repos.map(repoChipMenuRowHtml).join('');
  delegate(menu, 'click', '[data-repo-chip-open]', (event, row) => {
    const root = row.dataset.repoChipOpen || '';
    repoChipContextMenu.close();
    if (!root) return;
    // Pick this repo as the Info Bar's displayed repo (the <N/M>) and refresh — same effect as
    // cycling with the < / > arrows, but jumps straight to the chosen repo.
    sessionRepoDisplayRoot.set(session, root);
    refreshSessionRepoDisplay(session);
  });
  repoChipContextMenu.open(menu, x, y);
}

function summaryAgentContextText(agent) {
  const params = {
    agent: agent?.kind || t('common.agentLabel'),
    pid: agent?.pid || '',
    status: agent?.status || '',
  };
  return t(agent?.status ? 'summary.agentDetailsWithStatus' : 'summary.agentDetails', params);
}

function summaryContextHtml(session, info, agent) {
  const lines = [];
  const pane = info?.selected_pane;
  if (agent) {
    lines.push(summaryContextLine(t('common.agentLabel'), summaryAgentContextText(agent)));
    if (agent.transcript) lines.push(summaryContextLine(t('common.transcript'), agent.transcript));
    if (agent.error && !agent.transcript) lines.push(summaryContextLine(t('common.transcript'), agent.error));
  } else {
    lines.push(summaryContextLine(t('common.agentLabel'), t('agent.notDetected')));
  }
  if (pane) {
    lines.push(summaryContextLine(t('yoagent.action.row.pane'), t('summary.paneLocation', {
      command: pane.command || 'tmux',
      target: pane.target || session,
      path: pane.current_path || '',
    })));
  }

  const summary = sessionWorkSummary(session, info);
  const git = summary.git;
  if (git) {
    lines.push(summaryContextLine(t('common.field.branch'), `${repoBranchDisplayText(git)}${git.upstream ? ` -> ${git.upstream}` : ''}`));
    if (git.root) lines.push(summaryContextLine(t('popover.repo'), git.root));
    // S7: name a linked worktree vs its parent repo so the focused path isn't mistaken for the main checkout.
    if (git.worktree) lines.push(summaryContextLine(t('popover.worktree'), worktreeDisplayText(git.worktree)));
    if (git.head) lines.push(summaryContextLine(t('info.meta.gitCommit'), git.head));
  } else {
    lines.push(summaryContextLine(t('popover.repo'), t('git.noCheckout')));
  }
  const pr = displayPullRequest(info);
  if (pr?.number) {
    const label = pullRequestLinkLabel(pr);
    lines.push(summaryContextLine(t('pref.section.github'), `${label} ${pr.title || pr.description || ''}`, pr.url, label, pullRequestStatusClass(pr)));
  }
  for (const issue of summary.linearIssues) {
    const label = `${issue.identifier}${issue.state ? ` ${issue.state}` : ''}`;
    lines.push(summaryContextLine(t('info.field.linear'), `${label} ${issue.title || ''}`, issue.url, issue.identifier));
  }
  return lines.join('');
}

function summaryContextLine(label, text, url = '', linkLabel = '', linkClass = '') {
  const value = url && linkLabel
    ? `${linkHtml(url, linkLabel, text, linkClass)} ${esc(text.replace(linkLabel, '').trim())}`
    : esc(text);
  return `<div class="summary-context-line"><span class="summary-context-label">${esc(label)}:</span> ${value}</div>`;
}

async function ensureSession(session) {
  if (readOnlyMode) return true;
  const key = String(session || '');
  const existing = ensureSessionPromises.get(key);
  if (existing) return existing;
  const promise = (async () => {
    try {
      const payload = await apiFetchJson(`/api/ensure-session?session=${encodeURIComponent(session)}`, {method: 'POST'});
      statusEl.innerHTML = payload.created
        ? `<span class="ok">${localizedHtml('status.sessionCreatedWithAgent', {session: sessionLabel(session), agent: 'Claude'})}</span>`
        : `<span class="ok">${localizedHtml('status.sessionReady', {session: sessionLabel(session)})}</span>`;
      return true;
    } catch (error) {
      if (error?.status) {
        statusErr(esc(userMessageText(error, t('status.sessionCreateFailedDefault'))));
        return false;
      }
      statusErr(localizedHtml('status.sessionCheckFailed', {error}));
      return false;
    }
  })();
  ensureSessionPromises.set(key, promise);
  try {
    return await promise;
  } finally {
    if (ensureSessionPromises.get(key) === promise) ensureSessionPromises.delete(key);
  }
}

async function tmuxSessionExistsForReconnect(session) {
  try {
    const payload = await apiFetchJson(`/api/tmux-session-exists?session=${encodeURIComponent(session)}`, {cache: 'no-store'});
    if (payload?.exists === true) return true;
    if (payload?.exists === false) return false;
    return null;
  } catch (error) {
    if (error?.status === 404) return false;
    return null;
  }
}

async function createNextSession(agent, options = {}) {
  if (readOnlyMode) {
    statusErr(localizedHtml('status.readOnlyCreateSessions'));
    return;
  }
  const agentLabel = agentName(agent) || t('common.agentLabel');
  statusEl.textContent = t('status.sessionCreating', {agent: agentLabel});
  try {
    const dangerouslyYolo = options.dangerouslyYolo === true;
    const terminal = agent === 'term' ? String(options.terminal || '').trim() : '';
    const terminalQuery = terminal ? `&terminal=${encodeURIComponent(terminal)}` : '';
    const payload = await apiFetchJson(`/api/create-session?agent=${encodeURIComponent(agent)}&dangerously_yolo=${dangerouslyYolo ? '1' : '0'}${terminalQuery}`, {method: 'POST'});
    markPendingTmuxSession(payload.session);
    const previousActive = activeSessions.slice();
    updateSessionList(payload.sessions || []);
    renderSessionButtons();
    renderPanels(previousActive);
    await placeTmuxSession(payload.session);
    await ensureTerminalRunning(payload.session);
    refreshTranscripts({force: true});
    renderAutoApproveButtons();
    statusOk(localizedHtml('status.sessionCreated', {
      label: sessionLabel(payload.session),
      session: payload.session,
      agent: agentName(payload.agent) || agentLabel,
    }));
  } catch (error) {
    if (error?.status) {
      statusErr(esc(userMessageText(error, t('status.sessionCreateFailedDefault'))));
      return;
    }
    statusErr(localizedHtml('status.sessionCreateFailed', {error}));
  }
}

function tmuxSessionNameError(name) {
  const text = String(name || '').trim();
  if (!text) return t('rename.error.required');
  if (text.length > 64) return t('rename.error.tooLong');
  // Keep in sync with TMUX_SESSION_NAME_RE in yolomux_lib/app.py.
  if (!/^[A-Za-z0-9_. -]+$/.test(text)) return t('rename.error.invalidChars');
  return '';
}

function rekeyMap(map, oldKey, newKey) {
  if (!map.has(oldKey) || oldKey === newKey) return;
  if (!map.has(newKey)) map.set(newKey, map.get(oldKey));
  map.delete(oldKey);
}

function clearSessionEphemeralRuntimeState(session) {
  tmuxWindowNavigationRecords.delete(session);
  terminalTmuxInputStates.delete(session);
  terminalMobileAccessoryStates.delete(session);
  altScreenWheelRemainder.delete(session);
  clearAgentWindowActivityRecordsForSession(session);
  clearSessionAttentionAcknowledgementRecords(session);
}

function detachSessionUi(session) {
  stopTranscriptStream(session);
  stopSummaryStream(session);
  const item = terminals.get(session);
  if (item) closeTerminalItem(session, item);
  terminals.delete(session);
  pendingPaneViewStateCaptures.delete(session);
  const panel = panelNodes.get(session);
  if (panel) panel.remove();
  panelNodes.delete(session);
  clearSessionEphemeralRuntimeState(session);
  dismissSessionToasts(session);
}

function clearSessionUiState(session) {
  autoApproveStates.delete(session);
  paneViewState.delete(session);
  deleteUploadResultRecord(session);
  if (typeof clearWorkingAgentTransitionNotificationSession === 'function') clearWorkingAgentTransitionNotificationSession(session);
  sessionStatusRecords.delete(session);
  sessionRepoDisplayRoot.delete(session);
  tmuxStatusModes.delete(session);
  terminalAppClipboardText.delete(session);
  pasteCounters.delete(session);
  tabLastActivatedAt.delete(session);
}

function stopSessionUi(session) {
  detachSessionUi(session);
  clearSessionUiState(session);
}

function replaceSessionMetadata(oldSession, newSession) {
  if (typeof rekeyWorkingAgentTransitionNotificationSession === 'function') {
    rekeyWorkingAgentTransitionNotificationSession(oldSession, newSession);
  }
  for (const map of [
    autoApproveStates,
    sessionStatusRecords,
    sessionRepoDisplayRoot,
    tmuxStatusModes,
    terminalAppClipboardText,
    pasteCounters,
    paneViewState,
    // carry the per-pane LRU timestamp across a session rename too, or the renamed tab's
    // eviction ordering glitches (it reads as never-activated).
    tabLastActivatedAt,
  ]) {
    rekeyMap(map, oldSession, newSession);
  }
  const hasTranscriptSession = Boolean(transcriptMetadataState.payload.sessions?.[oldSession]);
  const hasTranscriptOrderEntry = Array.isArray(transcriptMetadataState.payload.session_order)
    && transcriptMetadataState.payload.session_order.includes(oldSession);
  if (hasTranscriptSession || hasTranscriptOrderEntry) {
    const nextSessions = {
      ...(transcriptMetadataState.payload.sessions || {}),
    };
    if (hasTranscriptSession) {
      nextSessions[newSession] = nextSessions[newSession] || nextSessions[oldSession];
      delete nextSessions[oldSession];
    }
    setTranscriptMetadataPayload({
      ...transcriptMetadataState.payload,
      sessions: nextSessions,
      session_order: Array.isArray(transcriptMetadataState.payload.session_order)
        ? transcriptMetadataState.payload.session_order.map(item => item === oldSession ? newSession : item)
        : transcriptMetadataState.payload.session_order,
    });
  }
}

function replaceTmuxSessionInClient(oldSession, newSession, nextSessions) {
  clearPendingTmuxSession(oldSession);
  markPendingTmuxSession(newSession);
  const next = normalizedSessionOrder(nextSessions) || sessions.map(item => item === oldSession ? newSession : item);
  moveUploadResultRecord(oldSession, newSession);
  detachSessionUi(oldSession);
  replaceSessionMetadata(oldSession, newSession);
  setSessionOrder(next);
  if (focusedTerminal === oldSession) focusedTerminal = newSession;
  if (focusedPanelItem === oldSession) focusedPanelItem = newSession;
  if (lastFocusedTmuxSession === oldSession) lastFocusedTmuxSession = newSession;
  applyLayoutSlots(layoutWithReplacedItem(oldSession, newSession), {focusSession: newSession, prune: false});
  renderUploadResult(newSession);
}

function closeSessionRenameDialog() {
  if (!sessionRenameDialog) return;
  sessionRenameDialog.remove();
  sessionRenameDialog = null;
  document.removeEventListener('keydown', sessionRenameDialogKeydown, true);
}

function sessionRenameDialogKeydown(event) {
  if (event.key === 'Escape') closeSessionRenameDialog();
}

function showSessionRenameDialog(session) {
  if (readOnlyMode) {
    statusErr(localizedHtml('status.readOnlyRenameSessions'));
    return false;
  }
  if (!isTmuxSession(session)) return false;
  closeContextMenus();
  closeAppMenus();
  closeSessionRenameDialog();
  const overlay = document.createElement('div');
  overlay.className = 'app-modal-overlay session-rename-backdrop';
  overlay.setAttribute('role', 'presentation');
  const titleName = sessionLabel(session);
  overlay.innerHTML = `
    <form class="session-rename-dialog" role="dialog" aria-modal="true" aria-label="${esc(t('common.renameTmuxSession'))}">
      <div class="session-rename-title">${esc(t('common.renameNamed', {name: titleName}))}</div>
      <input class="session-rename-input" name="sessionName" value="${esc(session)}" aria-label="${esc(t('rename.inputAria'))}" autocomplete="off">
      <div class="session-rename-error" hidden></div>
      <div class="session-rename-actions">
        <button type="button" class="session-rename-cancel">${esc(t('common.cancel'))}</button>
        <button type="submit" class="session-rename-submit">${esc(t('common.rename'))}</button>
      </div>
    </form>`;
  const form = overlay.querySelector('form');
  const input = overlay.querySelector('.session-rename-input');
  const errorNode = overlay.querySelector('.session-rename-error');
  const cancel = overlay.querySelector('.session-rename-cancel');
  const showError = message => {
    errorNode.textContent = message;
    errorNode.hidden = false;
  };
  overlay.addEventListener('pointerdown', event => {
    if (event.target === overlay) closeSessionRenameDialog();
  });
  cancel.addEventListener('click', closeSessionRenameDialog);
  form.addEventListener('submit', async event => {
    event.preventDefault();
    const nextName = input.value.trim();
    const nameError = tmuxSessionNameError(nextName);
    if (nameError) {
      showError(nameError);
      input.focus();
      return;
    }
    errorNode.hidden = true;
    const renameResult = await renameTmuxSession(session, nextName);
    if (renameResult !== true) {
      showError(renameResult?.error || t('status.renameFailedSeeStatus'));
      input.focus();
    }
  });
  appOverlayRootElement().appendChild(overlay);
  sessionRenameDialog = overlay;
  document.addEventListener('keydown', sessionRenameDialogKeydown, true);
  setTimeout(() => {
    input.focus();
    input.select();
  }, 0);
  return true;
}

async function renameTmuxSession(session, proposedName) {
  if (readOnlyMode) {
    statusErr(localizedHtml('status.readOnlyRenameSessions'));
    return false;
  }
  if (!isTmuxSession(session)) return false;
  if (proposedName === undefined) return showSessionRenameDialog(session);
  const rawName = proposedName;
  const newName = String(rawName || '').trim();
  const nameError = tmuxSessionNameError(newName);
  if (nameError) {
    statusErr(`${esc(nameError)}`);
    return false;
  }
  if (newName === session) {
    closeSessionRenameDialog();
    return true;
  }
  statusEl.textContent = t('status.sessionRenaming', {session: sessionLabel(session)});
  try {
    const payload = await apiFetchJson(`/api/rename-session?session=${encodeURIComponent(session)}&new_name=${encodeURIComponent(newName)}`, {method: 'POST'});
    const renamed = payload.new_session || newName;
    replaceTmuxSessionInClient(session, renamed, payload.sessions);
    closeSessionRenameDialog();
    await ensureTerminalRunning(renamed);
    refreshTranscripts({force: true});
    renderAutoApproveButtons();
    statusOk(localizedHtml('common.renamed', {oldName: session, newName: renamed}));
    return true;
  } catch (error) {
    const errorText = error?.status
      ? userMessageText(error, t('status.sessionRenameFailedDefault'))
      : t('status.sessionRenameFailed', {error: error?.message || String(error)});
    statusErr(esc(errorText));
    return {error: errorText};
  }
}

async function killTmuxSession(session) {
  if (readOnlyMode) {
    statusErr(localizedHtml('status.readOnlyKillSessions'));
    return false;
  }
  if (!isTmuxSession(session)) return false;
  if (!window.confirm(t('dialog.sessionKill', {session: sessionLabel(session)}))) return false;
  statusEl.textContent = t('status.sessionKilling', {session: sessionLabel(session)});
  try {
    const payload = await apiFetchJson(`/api/kill-session?session=${encodeURIComponent(session)}`, {method: 'POST'});
    const previousActive = activeSessions.slice();
    clearPendingTmuxSession(session);
    stopSessionUi(session);
    const sessionsChanged = updateSessionList(payload.sessions || []);
    updateDocumentTitle();
    renderSessionButtons();
    renderPanels(previousActive);
    if (sessionsChanged) renderPaneTabStrips();
    refreshTranscripts({force: true});
    renderAutoApproveButtons();
    statusOk(localizedHtml('status.sessionKilled', {session: sessionLabel(session)}));
    return true;
  } catch (error) {
    if (error?.status) {
      statusErr(esc(userMessageText(error, t('status.sessionKillFailedDefault'))));
      return false;
    }
    statusErr(localizedHtml('status.sessionKillFailed', {error}));
    return false;
  }
}

function focusPanel(session, options = {}) {
  const panel = document.getElementById(panelDomId(session));
  if (!panel) return;
  if (options.userInitiated === true) {
    dismissSessionToasts(session);
    acknowledgeNotificationTarget(session);
  }
  if (options.scrollIntoView === true) {
    panel.scrollIntoView({block: 'nearest', inline: 'nearest'});
  }
  if (isFileEditorItem(session)) {
    focusedTerminal = null;
    setFocusedPanelItem(session, {userInitiated: options.userInitiated === true});
    if (autoFocusCanFollowCursor()) {
      requestFileEditorPanelFocus(session);
      focusFileEditorPanelIfReady(panel, session);
    }
    return;
  }
  if (isVirtualItem(session)) {
    focusedTerminal = null;
    setFocusedPanelItem(session, {userInitiated: options.userInitiated === true});
    return;
  }
  activateTab(session, 'terminal', {userInitiated: options.userInitiated === true});
}

function shareHostTerminalSize(session) {
  if (!shareViewMode) return null;
  const dims = shareSenderRecord(session, {create: false})?.dimensions;
  const rawRows = Math.floor(Number(dims?.rows) || 0);
  const rawCols = Math.floor(Number(dims?.cols) || 0);
  if (rawRows <= 0 || rawCols <= 0) return null;
  return {rows: Math.max(10, rawRows), cols: Math.max(40, rawCols)};
}

function updateShareHostTerminalSize(session, rows, cols) {
  if (!shareViewMode || !session) return;
  shareSenderRecord(session).dimensions = {
    rows: Math.max(10, Math.floor(Number(rows) || 0)),
    cols: Math.max(40, Math.floor(Number(cols) || 0)),
  };
  fitTerminal(session);
}

function terminalFitMetricKey(value, scale = 1000) {
  const number = Number(value);
  if (!Number.isFinite(number)) return 0;
  return Math.round(number * scale) / scale;
}

function terminalFitSignature(size) {
  if (!size) return '';
  return [
    Math.round(Number(size.contentWidth) || 0),
    Math.round(Number(size.contentHeight) || 0),
    terminalFitMetricKey(size.cellWidth),
    terminalFitMetricKey(size.cellHeight),
    size.cols,
    size.rows,
    terminalFitMetricKey(terminalFontSize),
    terminalFontFamily,
  ].join(':');
}

function terminalFitIsUnchanged(item, size) {
  if (!item?.term || !size) return false;
  return item.lastFitSignature === terminalFitSignature(size)
    && item.term.cols === size.cols
    && item.term.rows === size.rows;
}

function terminalCanPublishRemoteSize() {
  return !shareViewMode && document.visibilityState !== 'hidden';
}

let lastTerminalResizeAuthoritySignature = '';
let terminalResizeAuthorityHandlersInstalled = false;

function visibleTerminalResizeAuthorityEntries() {
  if (!terminalCanPublishRemoteSize()) return [];
  return activeSessions
    .filter(isTmuxSession)
    .map(session => ({session, item: terminals.get(session)}))
    .filter(entry => entry.item?.term && entry.item?.socket?.readyState === WebSocket.OPEN && terminalIsVisible(entry.session, entry.item.container));
}

function terminalResizeAuthoritySignature(entries) {
  return entries
    .map(({session, item}) => `${session}:${terminalFitSignature(estimateTerminalSize(item.container, item.term))}`)
    .join('|');
}

function claimVisibleTerminalResizeAuthority(reason = '', options = {}) {
  const entries = visibleTerminalResizeAuthorityEntries();
  if (!entries.length) return;
  const signature = terminalResizeAuthoritySignature(entries);
  if (options.force !== true && signature === lastTerminalResizeAuthoritySignature) return;
  lastTerminalResizeAuthoritySignature = signature;
  for (const {session} of entries) {
    fitTerminal(session, {claim: true});
  }
}

function installTerminalResizeAuthorityHandlers() {
  if (terminalResizeAuthorityHandlersInstalled || shareViewMode) return;
  terminalResizeAuthorityHandlersInstalled = true;
  window.addEventListener('focus', () => claimVisibleTerminalResizeAuthority('window-focus', {force: true}));
  window.addEventListener('pointerdown', () => claimVisibleTerminalResizeAuthority('pointerdown'), {capture: true});
  document.addEventListener('visibilitychange', () => {
    if (document.visibilityState === 'visible') claimVisibleTerminalResizeAuthority('visible', {force: true});
  });
}

function fitTerminal(session, options = {}) {
  const item = terminals.get(session);
  if (!item || !item.term || !item.container) return;
  const hostSize = shareHostTerminalSize(session);
  if (shareViewMode) {
    if (!hostSize) return;
    const changed = item.term.cols !== hostSize.cols || item.term.rows !== hostSize.rows;
    item.term.resize(hostSize.cols, hostSize.rows);
    if (changed && item.shareTerminalBytesReceived === true) {
      item.shareTerminalSkippedResetCount = Math.max(0, Math.round(Number(item.shareTerminalSkippedResetCount) || 0)) + 1;
    } else if (changed) {
      item.shareTerminalLastResetAt = Date.now();
      try { item.term.reset(); } catch (_) {}
    }
    refreshTerminal(session);
    return;
  }
  if (!terminalIsVisible(session, item.container)) return;
  const size = estimateTerminalSize(item.container, item.term);
  const signature = terminalFitSignature(size);
  const claim = options.claim === true;
  if (options.force !== true && !claim && terminalFitIsUnchanged(item, size)) return;
  item.lastFitSignature = signature;
  const changed = item.term.cols !== size.cols || item.term.rows !== size.rows;
  if (changed) item.term.resize(size.cols, size.rows);
  if (claim) sendRemoteResize(session, {activate: true});
  else if (changed) scheduleRemoteResize(session);
  refreshTerminal(session);
}

function sendRemoteResize(session, options = {}) {
  if (!terminalCanPublishRemoteSize()) return false;
  const item = terminals.get(session);
  if (!item?.term || item?.socket?.readyState !== WebSocket.OPEN) return false;
  const message = {type: 'resize', cols: item.term.cols, rows: item.term.rows, foreground: true};
  if (options.activate === true) message.activate = true;
  if (shareClientId) message.client = shareClientId;
  item.socket.send(JSON.stringify(message));
  item.remoteResizePending = false;
  return true;
}

function scheduleRemoteResize(session, delay = remoteResizeDelayMs, options = {}) {
  const item = terminals.get(session);
  if (!item) return;
  if (item.resizeTimer) clearTimeout(item.resizeTimer);
  if (!terminalCanPublishRemoteSize()) {
    item.remoteResizePending = true;
    item.resizeTimer = null;
    return;
  }
  item.resizeTimer = setTimeout(() => {
    item.resizeTimer = null;
    sendRemoteResize(session, options);
  }, delay);
}

function forceRemoteResize(session) {
  const item = terminals.get(session);
  if (!item) return false;
  if (item.resizeTimer) {
    clearTimeout(item.resizeTimer);
    item.resizeTimer = null;
  }
  return sendRemoteResize(session);
}

function refreshTerminal(session) {
  const item = terminals.get(session);
  if (!item?.term) return;
  requestAnimationFrame(() => {
    try { item.term.refresh(0, Math.max(0, item.term.rows - 1)); } catch (_) {}
    syncTerminalAttentionHighlight(session);
  });
}

function terminalIsVisible(session, container) {
  const pane = document.getElementById(`terminal-pane-${session}`);
  return Boolean(
    pane?.classList.contains(CLS.active)
    && container.clientWidth > 40
    && container.clientHeight > 40
  );
}

const terminalAttentionQuestionRowClass = 'terminal-attention-question-row';
const terminalAttentionQuestionOverlayClass = 'terminal-attention-question-overlay';

function terminalAttentionRawText(value) {
  return String(value || '').replace(/\u00a0/g, ' ');
}

function terminalAttentionQuestionChromeHintText(value) {
  const text = singleLineText(value).replace(/^[>❯$#\s]+/, '').trim();
  return /^[?？]\s+for\s+(?:shortcuts|help|commands)\b/i.test(text);
}

function terminalAttentionQuestionTexts(session) {
  const state = sessionState(session, transcriptMetadataState.payload.sessions?.[session]);
  if (![STATE_KEY.needsInput, STATE_KEY.needsApproval].includes(String(state?.key || '')) || state?.attention === false) return [];
  const payload = autoApproveStates.get(session) || {};
  const candidates = [
    payload.display?.question_text,
    payload.screen?.question_text,
    payload.prompt?.question_text,
    payload.screen?.text,
    payload.prompt?.text,
    payload.prompt?.rule_input_text,
    payload.prompt?.command,
  ];
  for (const agentWindow of Array.isArray(payload.agent_windows) ? payload.agent_windows : []) {
    candidates.push(
      agentWindow?.question_text,
      agentWindow?.screen_text,
      agentWindow?.display?.question_text,
      agentWindow?.screen?.question_text,
      agentWindow?.screen?.text,
    );
  }
  candidates.push(state.reason);
  const seen = new Set();
  const texts = [];
  for (const candidate of candidates) {
    const text = singleLineText(candidate);
    if (!text || terminalAttentionQuestionChromeHintText(text) || seen.has(text)) continue;
    seen.add(text);
    texts.push(text);
  }
  return texts;
}

function terminalAttentionRowTexts(item) {
  const rows = Array.from(item?.container?.querySelector?.('.xterm-rows')?.children || [])
    .map((row, index) => {
      const rawText = terminalAttentionRawText(row?.textContent || '');
      return {index, row, rawText, text: singleLineText(rawText)};
    })
    .filter(record => record.text);
  if (rows.length) return rows;
  const buffer = item?.term?.buffer?.active;
  const bufferLength = Number(buffer?.length);
  if (!Number.isFinite(bufferLength) || typeof buffer?.getLine !== 'function') return [];
  const visibleRows = Math.max(1, Number(item.term.rows || 0));
  const start = Math.max(0, Number(buffer.viewportY || 0));
  const end = Math.min(bufferLength, start + visibleRows);
  const records = [];
  for (let lineIndex = start; lineIndex < end; lineIndex += 1) {
    const line = buffer.getLine(lineIndex);
    const rawText = terminalAttentionRawText(typeof line?.translateToString === 'function' ? line.translateToString(true) : '');
    const text = singleLineText(rawText);
    if (text) records.push({index: lineIndex - start, row: null, rawText, text});
  }
  return records;
}

function terminalAttentionNormalizeMappedText(rawText, rawMap = []) {
  const raw = terminalAttentionRawText(rawText);
  let text = '';
  const map = [];
  let hasPendingSpace = false;
  let pendingSpaceSource = null;
  for (let index = 0; index < raw.length; index += 1) {
    const char = raw[index];
    if (/\s/.test(char)) {
      if (text && !hasPendingSpace) {
        hasPendingSpace = true;
        pendingSpaceSource = rawMap[index] || null;
      }
      continue;
    }
    if (hasPendingSpace && text) {
      text += ' ';
      map.push(pendingSpaceSource);
      hasPendingSpace = false;
      pendingSpaceSource = null;
    }
    text += char;
    map.push(rawMap[index] || null);
  }
  return {text, map};
}

function terminalAttentionJoinedContext(rows, separator = '') {
  let rawText = '';
  const rawMap = [];
  rows.forEach((record, rowIndex) => {
    if (rowIndex > 0 && separator) {
      for (let index = 0; index < separator.length; index += 1) {
        rawText += separator[index];
        rawMap.push(null);
      }
    }
    const rowText = terminalAttentionRawText(record?.rawText || record?.text || '');
    for (let index = 0; index < rowText.length; index += 1) {
      rawText += rowText[index];
      rawMap.push({record, column: index});
    }
  });
  return terminalAttentionNormalizeMappedText(rawText, rawMap);
}

function terminalAttentionRowsLikelyWrapped(previous, item) {
  const rawText = terminalAttentionRawText(previous?.rawText || previous?.text || '').replace(/\s+$/g, '');
  if (!rawText) return false;
  if (/[A-Za-z0-9)]-$/.test(rawText)) return true;
  const cols = Math.floor(Number(item?.term?.cols || 0));
  return cols > 0 && rawText.length >= Math.max(1, cols - 2);
}

function terminalAttentionSegmentsForRange(context, start, length, highlightText) {
  const end = start + length;
  const segments = [];
  for (let index = start; index < end; index += 1) {
    const source = context.map[index];
    if (!source?.record) continue;
    let segment = segments.find(item => item.record === source.record);
    if (!segment) {
      segment = {
        record: source.record,
        highlightStart: source.column,
        highlightEnd: source.column + 1,
      };
      segments.push(segment);
    } else {
      segment.highlightStart = Math.min(segment.highlightStart, source.column);
      segment.highlightEnd = Math.max(segment.highlightEnd, source.column + 1);
    }
  }
  return segments
    .sort((a, b) => Number(a.record.index || 0) - Number(b.record.index || 0))
    .map(segment => ({
      ...segment.record,
      highlightStart: Math.max(0, segment.highlightStart),
      highlightLength: Math.max(1, segment.highlightEnd - segment.highlightStart),
      highlightText,
    }));
}

function terminalAttentionCharIsAlphaNumeric(char) {
  return /[A-Za-z0-9]/.test(String(char || ''));
}

function terminalAttentionDotIsSentenceBoundary(source, index) {
  return !(
    terminalAttentionCharIsAlphaNumeric(source[index - 1])
    && terminalAttentionCharIsAlphaNumeric(source[index + 1])
  );
}

function terminalAttentionCharIsQuestionSentenceBoundary(source, index) {
  const char = source[index];
  if (char === '.') return terminalAttentionDotIsSentenceBoundary(source, index);
  return /[!?？|│—–]/.test(char);
}

function terminalAttentionCharIsHardQuestionSentenceBoundary(source, index) {
  const char = source[index];
  if (char === '.') return terminalAttentionDotIsSentenceBoundary(source, index);
  return /[!?？|│]/.test(char);
}

function terminalAttentionDashContinuesNoteSentence(source, index) {
  let sentenceStart = 0;
  for (let scan = index - 1; scan >= 0; scan -= 1) {
    if (terminalAttentionCharIsHardQuestionSentenceBoundary(source, scan)) {
      sentenceStart = scan + 1;
      break;
    }
  }
  return /^Note:\s+\S/i.test(source.slice(sentenceStart, index).trimStart());
}

function terminalAttentionSkipPromptPrefix(source, start) {
  let index = Math.max(0, Number(start) || 0);
  while (/\s/.test(source[index] || '')) index += 1;
  while (/[>❯]/.test(source[index] || '')) {
    index += 1;
    while (/\s/.test(source[index] || '')) index += 1;
  }
  if (/[$#]/.test(source[index] || '') && /\s/.test(source[index + 1] || '')) {
    index += 1;
    while (/\s/.test(source[index] || '')) index += 1;
  }
  return index;
}

function terminalAttentionQuestionSentenceStart(source, questionIndex) {
  let start = 0;
  for (let index = questionIndex - 1; index >= 0; index -= 1) {
    if (terminalAttentionCharIsQuestionSentenceBoundary(source, index)) {
      if (/[—–]/.test(source[index] || '') && terminalAttentionDashContinuesNoteSentence(source, index)) continue;
      start = index + 1;
      break;
    }
  }
  return terminalAttentionSkipPromptPrefix(source, start);
}

function terminalAttentionQuestionSentenceRanges(text) {
  const source = singleLineText(text);
  if (!source || !/[?？]/.test(source)) return [];
  const ranges = [];
  for (let questionIndex = 0; questionIndex < source.length; questionIndex += 1) {
    if (!/[?？]/.test(source[questionIndex])) continue;
    const end = questionIndex + 1;
    const start = terminalAttentionQuestionSentenceStart(source, questionIndex);
    const rawSentence = source.slice(start, end);
    const trimOffset = rawSentence.length - rawSentence.trimStart().length;
    const sentence = rawSentence.trim();
    if (terminalAttentionQuestionChromeHintText(sentence)) continue;
    const content = sentence.replace(/[?？]/g, '').replace(/^[>❯$#\s]+/, '').trim();
    if (content) {
      ranges.push({
        start: start + trimOffset,
        length: sentence.length,
        text: sentence,
      });
    }
  }
  return ranges;
}

function terminalAttentionContainingQuestionRange(context, start, length) {
  const matchStart = Math.max(0, Number(start) || 0);
  const matchEnd = matchStart + Math.max(0, Number(length) || 0);
  return terminalAttentionQuestionSentenceRanges(context?.text || '')
    .filter(range => range.start <= matchStart && range.start + range.length >= matchEnd)
    .sort((left, right) => left.length - right.length)[0] || null;
}

function terminalAttentionShouldExpandQuestionFragment(item, rows, context, start) {
  const source = context?.map?.[start];
  if (!source?.record || Number(source.column || 0) !== 0) return false;
  const rowIndex = rows.findIndex(record => record === source.record);
  if (rowIndex <= 0) return false;
  return terminalAttentionRowsLikelyWrapped(rows[rowIndex - 1], item);
}

function terminalAttentionQuestionRangeStartsOnMatchRow(context, range, start) {
  const rangeSource = context?.map?.[range?.start];
  const matchSource = context?.map?.[start];
  return Boolean(rangeSource?.record && rangeSource.record === matchSource?.record);
}

function terminalAttentionQuestionRangeHasNoteLead(context, range, start) {
  if (!context || !range || range.start >= start) return false;
  const lead = String(context.text || '').slice(range.start, start);
  return /^Note:\s+\S/i.test(lead.trimStart()) && /[—–]\s*$/.test(lead);
}

function terminalAttentionQuestionCandidateTexts(questionTexts) {
  const seen = new Set();
  const candidates = [];
  const add = value => {
    const text = singleLineText(value);
    if (!text || terminalAttentionQuestionChromeHintText(text) || seen.has(text)) return;
    seen.add(text);
    candidates.push(text);
  };
  for (const candidate of questionTexts) {
    const text = singleLineText(candidate);
    for (const range of terminalAttentionQuestionSentenceRanges(text)) add(range.text);
    add(text);
  }
  return candidates;
}

function terminalAttentionSingleRowSpan(record, candidate) {
  const needle = singleLineText(candidate);
  if (!needle) return null;
  const rawText = terminalAttentionRawText(record?.rawText || record?.text || '');
  const directStart = rawText.indexOf(needle);
  if (directStart >= 0) return {highlightStart: directStart, highlightLength: needle.length, highlightText: needle};
  const normalized = singleLineText(rawText);
  const normalizedStart = normalized.indexOf(needle);
  if (normalizedStart >= 0) {
    const leading = rawText.match(/^\s*/)?.[0]?.length || 0;
    return {highlightStart: leading + normalizedStart, highlightLength: needle.length, highlightText: needle};
  }
  if (normalized.length >= 8 && needle.includes(normalized)) {
    const leading = rawText.match(/^\s*/)?.[0]?.length || 0;
    return {highlightStart: leading, highlightLength: normalized.length, highlightText: normalized};
  }
  return null;
}

function terminalAttentionSpanSegments(item, rows, candidate) {
  const needle = singleLineText(candidate);
  if (!needle) return [];
  for (const separator of ['', ' ']) {
    const context = terminalAttentionJoinedContext(rows, separator);
    // A terminal viewport can retain an earlier copy of the same prompt. The active prompt is the
    // latest matching sentence, not the first one left in scrollback above it.
    const start = context.text.lastIndexOf(needle);
    if (start < 0) continue;
    const containingRange = terminalAttentionContainingQuestionRange(context, start, needle.length);
    const expandsWrappedFragment = terminalAttentionShouldExpandQuestionFragment(item, rows, context, start);
    const expandsNoteLead = terminalAttentionQuestionRangeHasNoteLead(context, containingRange, start);
    const mayExpandRange = containingRange && (
      terminalAttentionQuestionRangeStartsOnMatchRow(context, containingRange, start)
      || expandsWrappedFragment
      || expandsNoteLead
    );
    const expandsRange = containingRange && (
      containingRange.start < start
      || containingRange.length > needle.length
      || expandsWrappedFragment
      || expandsNoteLead
    );
    const range = containingRange && mayExpandRange && expandsRange ? containingRange : null;
    const highlightStart = range?.start ?? start;
    const highlightLength = range?.length ?? needle.length;
    const highlightText = range?.text ?? needle;
    const segments = terminalAttentionSegmentsForRange(context, highlightStart, highlightLength, highlightText);
    if (segments.length) return segments;
  }
  for (const record of rows) {
    const span = terminalAttentionSingleRowSpan(record, candidate);
    if (span) return [{...record, ...span}];
  }
  return [];
}

function terminalAttentionQuestionSegments(item, questionTexts = []) {
  const rows = terminalAttentionRowTexts(item);
  if (!rows.length) return [];
  const candidates = terminalAttentionQuestionCandidateTexts(questionTexts);
  for (const candidate of candidates) {
    const segments = terminalAttentionSpanSegments(item, rows, candidate);
    if (segments.length) return segments;
  }
  return [];
}

function terminalAttentionQuestionRow(item, questionTexts = []) {
  const segments = terminalAttentionQuestionSegments(item, questionTexts);
  if (!segments.length) return null;
  return {...segments[0], segments};
}

function terminalAttentionOverlay(session, item, index = 0) {
  if (!item?.container) return null;
  const overlay = document.createElement('div');
  overlay.className = terminalAttentionQuestionOverlayClass;
  overlay.dataset.session = String(session);
  overlay.dataset.attentionIndex = String(index);
  item.container.appendChild(overlay);
  return overlay;
}

function clearTerminalAttentionHighlight(session, item = terminals.get(session)) {
  const container = item?.container;
  if (!container) return;
  for (const row of container.querySelectorAll?.(`.${terminalAttentionQuestionRowClass}`) || []) {
    row.classList.remove(terminalAttentionQuestionRowClass);
  }
  for (const overlay of container.querySelectorAll?.(`.${terminalAttentionQuestionOverlayClass}[data-session="${cssEscape(session)}"]`) || []) {
    overlay.remove();
  }
}

function placeTerminalAttentionOverlay(session, item, record, index = 0) {
  const overlay = terminalAttentionOverlay(session, item, index);
  if (!overlay) return;
  const containerRect = item.container.getBoundingClientRect?.() || {};
  const rowRect = record.row?.getBoundingClientRect?.();
  const screenRect = terminalScreenElement(item.container)?.getBoundingClientRect?.() || containerRect;
  const cell = terminalCellDimensions(item.term, item.container);
  const cellWidth = Math.max(1, Number(cell.width || 0) || 0);
  const top = rowRect?.height
    ? rowRect.top - Number(containerRect.top || 0)
    : Number(screenRect.top || 0) - Number(containerRect.top || 0) + Math.max(0, Number(record.index || 0)) * Math.max(1, Number(cell.height || 0));
  const height = rowRect?.height || Math.max(1, Number(cell.height || 0));
  const leftBase = Number((rowRect || screenRect)?.left || 0) - Number(containerRect.left || 0);
  const start = Math.max(0, Number(record.highlightStart || 0));
  const length = Math.max(1, Number(record.highlightLength || singleLineText(record.text).length || 1));
  const left = Math.max(0, leftBase + start * cellWidth);
  const maxWidth = Math.max(cellWidth, Number(containerRect.width || 0) - left);
  const width = Math.max(cellWidth, Math.min(maxWidth, length * cellWidth));
  overlay.style.top = `${Math.max(0, top)}px`;
  overlay.style.height = `${height}px`;
  overlay.style.left = `${left}px`;
  overlay.style.width = `${width}px`;
  overlay.title = record.highlightText || record.text;
}

function syncTerminalAttentionHighlight(session) {
  const perf = clientPerfStart('terminalAttentionScan');
  try {
    return syncTerminalAttentionHighlightMeasured(session);
  } finally {
    const item = terminals.get(session);
    clientPerfEnd(perf, {rows: Math.max(0, Number(item?.term?.rows || 0))});
  }
}

function syncTerminalAttentionHighlightMeasured(session) {
  const item = terminals.get(session);
  if (!item?.container || !item?.term) return false;
  clearTerminalAttentionHighlight(session, item);
  const texts = terminalAttentionQuestionTexts(session);
  if (!texts.length) return false;
  const record = terminalAttentionQuestionRow(item, texts);
  if (!record) return false;
  const segments = Array.isArray(record.segments) && record.segments.length ? record.segments : [record];
  segments.forEach((segment, index) => {
    segment.row?.classList?.add(terminalAttentionQuestionRowClass);
    placeTerminalAttentionOverlay(session, item, segment, index);
  });
  return true;
}

function scheduleTerminalAttentionHighlight(session) {
  const item = terminals.get(session);
  if (!item) {
    requestAnimationFrame(() => syncTerminalAttentionHighlight(session));
    return;
  }
  if (item.attentionHighlightFrame) return;
  item.attentionHighlightFrame = requestAnimationFrame(() => {
    item.attentionHighlightFrame = 0;
    if (terminals.get(session) === item) syncTerminalAttentionHighlight(session);
  });
}

function syncTerminalAttentionHighlights() {
  for (const session of sessions.filter(isTmuxSession)) syncTerminalAttentionHighlight(session);
}

const terminalBlankScreenRefreshDelaysMs = Object.freeze([220, 650, 1400, 2800]);
const terminalBlankScreenRefreshRiskReasons = Object.freeze(new Set([
  'socket-open',
  'fit',
  'first-output',
  'terminal-tab',
  'tmux-window',
  'blank-risk',
]));

function terminalBlankScreenRefreshAllowed(reason) {
  return terminalBlankScreenRefreshRiskReasons.has(String(reason || 'blank-risk'));
}

function terminalRenderedContentPresent(session, item = terminals.get(session)) {
  const perf = clientPerfStart('terminalBlankProbe');
  try {
    return terminalRenderedContentPresentMeasured(session, item);
  } finally {
    clientPerfEnd(perf, {rows: Math.max(0, Number(item?.term?.rows || 0))});
  }
}

function terminalRenderedContentPresentMeasured(session, item = terminals.get(session)) {
  if (!item?.term) return false;
  const buffer = item.term.buffer?.active;
  const bufferLength = Number(buffer?.length);
  const visibleRows = Math.max(1, Number(item.term.rows || 0));
  if (Number.isFinite(bufferLength) && typeof buffer?.getLine === 'function') {
    const start = Math.max(0, Number(buffer.viewportY || 0));
    const end = Math.min(bufferLength, start + visibleRows);
    for (let index = start; index < end; index += 1) {
      const line = buffer.getLine(index);
      const text = typeof line?.translateToString === 'function' ? line.translateToString(true) : '';
      if (String(text || '').trim()) return true;
    }
  }
  const rows = item.container?.querySelectorAll?.('.xterm-rows > div, .xterm-rows div') || [];
  for (const row of rows) {
    if (String(row?.textContent || '').trim()) return true;
  }
  return false;
}

function requestTerminalScreenRefresh(session, item = terminals.get(session), reason = 'terminal-refresh') {
  if (shareViewMode || item?.socket?.readyState !== WebSocket.OPEN) return false;
  try {
    const refreshReason = String(reason || 'terminal-refresh');
    item.socket.send(JSON.stringify({type: 'refresh', reason: refreshReason}));
    return true;
  } catch (_) {
    return false;
  }
}

function refreshVisibleTerminalScreens(reason = 'manual-refresh') {
  for (const session of activeSessions.filter(isTmuxSession)) {
    const item = terminals.get(session);
    if (!item?.term || !terminalIsVisible(session, item.container)) continue;
    refreshTerminal(session);
    requestTerminalScreenRefresh(session, item, reason);
  }
}

function runTerminalBlankScreenRefresh(session) {
  const item = terminals.get(session);
  if (!item) return;
  item.blankScreenRefreshTimer = 0;
  if (!terminalIsVisible(session, item.container)) return;
  if (terminalRenderedContentPresent(session, item)) {
    item.blankScreenRefreshAttempts = 0;
    return;
  }
  const attempts = Math.max(0, Number(item.blankScreenRefreshAttempts || 0));
  if (attempts >= terminalBlankScreenRefreshDelaysMs.length) return;
  item.blankScreenRefreshAttempts = attempts + 1;
  if (requestTerminalScreenRefresh(session, item)) scheduleTerminalBlankScreenRefresh(session);
}

function scheduleTerminalBlankScreenRefresh(session, options = {}) {
  const item = terminals.get(session);
  if (!item || shareViewMode || !terminalIsVisible(session, item.container)) return;
  const reason = String(options.reason || 'blank-risk');
  if (!terminalBlankScreenRefreshAllowed(reason)) return;
  if (item.socket?.readyState !== WebSocket.OPEN) return;
  if (item.blankScreenRefreshTimer && options.reset !== true) return;
  if (terminalRenderedContentPresent(session, item)) {
    item.blankScreenRefreshAttempts = 0;
    if (item.blankScreenRefreshTimer) {
      clearTimeout(item.blankScreenRefreshTimer);
      item.blankScreenRefreshTimer = 0;
    }
    return;
  }
  const attempts = Math.max(0, Number(item.blankScreenRefreshAttempts || 0));
  if (attempts >= terminalBlankScreenRefreshDelaysMs.length) return;
  if (item.blankScreenRefreshTimer) clearTimeout(item.blankScreenRefreshTimer);
  const delayMs = Number.isFinite(Number(options.delayMs))
    ? Math.max(1, Number(options.delayMs))
    : terminalBlankScreenRefreshDelaysMs[attempts];
  item.blankScreenRefreshTimer = setTimeout(() => runTerminalBlankScreenRefresh(session), delayMs);
}

function scheduleFit(session) {
  const item = terminals.get(session);
  if (item) {
    if (item.fitFrame) cancelAnimationFrame(item.fitFrame);
    if (item.fitTimer) clearTimeout(item.fitTimer);
    // C12 F3: one rAF fit for the common fast case + a SINGLE trailing fit to catch a late layout settle
    // (was rAF + 80ms + 250ms = three fits per resize). fitTerminal already skips the remote resize when
    // cols/rows are unchanged, so the trailing fit is a cheap no-op when nothing actually moved.
    item.fitFrame = requestAnimationFrame(() => {
      item.fitFrame = 0;
      fitTerminal(session);
      scheduleTerminalBlankScreenRefresh(session, {reason: 'fit'});
    });
    item.fitTimer = setTimeout(() => {
      item.fitTimer = 0;
      fitTerminal(session);
      scheduleTerminalBlankScreenRefresh(session, {reason: 'fit'});
    }, 250);
    return;
  }
  requestAnimationFrame(() => fitTerminal(session));
}

function observeTerminalResize(session, container) {
  const oldObserver = resizeObservers.get(session);
  if (oldObserver) oldObserver.disconnect();
  if (!window.ResizeObserver) return;
  const observer = new ResizeObserver(() => scheduleFit(session));
  observer.observe(container);
  resizeObservers.set(session, observer);
}

// Carries the synthetic wheel events we re-dispatch at xterm (see forwardAltScreenWheel) so the
// capture-phase handler below lets them through to xterm instead of re-processing them.
let dispatchingSyntheticWheel = false;
// Per-session fractional remainder so small touchpad deltas still accumulate into whole lines.
const altScreenWheelRemainder = new Map();

function enableTerminalScroll(session, term, container) {
  container.addEventListener('wheel', event => {
    if (dispatchingSyntheticWheel) return;
    if (event.ctrlKey && event.deltaY !== 0) {
      event.preventDefault();
      event.stopPropagation();
      return;
    }
    const signedLines = terminalWheelSignedLines(event, term.rows);
    if (!signedLines) return;
    // Alt-screen TUIs (claude, codex, vim, less) own the mouse and keep their own scroll view,
    // and their tmux pane has no scrollback, so hijacking the wheel into tmux copy-mode scrolls
    // nothing. Forward the wheel to the app instead — but xterm emits only ONE mouse-wheel report
    // per accumulated cell regardless of delta magnitude, which feels like "several scrolls per
    // line". Drive it ourselves with the same line count the tmux path uses for consistent speed.
    if (sessionPaneIsAlternateScreen(session)) {
      event.preventDefault();
      event.stopPropagation();
      forwardAltScreenWheel(session, container, signedLines);
      return;
    }
    altScreenWheelRemainder.delete(session);
    event.preventDefault();
    event.stopPropagation();
    const item = terminals.get(session);
    if (!readOnlyMode && item?.socket?.readyState === WebSocket.OPEN) {
      queueTmuxScroll(item, signedLines);
      return;
    }
    queueLocalTerminalScroll(term, signedLines);
  }, {capture: true, passive: false});
}

// Re-emit `lines` worth of single-line wheel events at xterm's screen element. xterm encodes each
// one into the app's negotiated mouse protocol and sends it over the data stream, so the alt-screen
// app scrolls one line per synthetic event — i.e. our full computed line count, not xterm's capped one.
function forwardAltScreenWheel(session, container, signedLines) {
  if (typeof WheelEvent !== 'function') return;
  const node = terminalScreenElement(container);
  if (!node?.dispatchEvent) return;
  const accumulated = (altScreenWheelRemainder.get(session) || 0) + signedLines;
  const whole = Math.trunc(accumulated);
  altScreenWheelRemainder.set(session, accumulated - whole);
  if (!whole) return;
  const count = Math.min(terminalWheelMaxLinesPerEvent, Math.abs(whole));
  const deltaY = whole < 0 ? -1 : 1;
  dispatchingSyntheticWheel = true;
  try {
    for (let i = 0; i < count; i++) {
      node.dispatchEvent(new WheelEvent('wheel', {deltaY, deltaMode: 1, bubbles: true, cancelable: true}));
    }
  } finally {
    dispatchingSyntheticWheel = false;
  }
}

function terminalWheelSignedLines(event, rows = 0) {
  const deltaY = Number(event?.deltaY);
  if (!Number.isFinite(deltaY) || deltaY === 0 || event?.ctrlKey) return 0;
  const direction = deltaY < 0 ? -1 : 1;
  const pageLines = Math.max(1, Math.floor((Number(rows) || 0) * terminalWheelPageFraction));
  if (event?.shiftKey) return direction * pageLines;
  const magnitude = Math.abs(deltaY);
  let lines;
  if (event?.deltaMode === 1) lines = magnitude;
  else if (event?.deltaMode === 2) lines = magnitude * pageLines;
  else lines = magnitude / terminalWheelPixelLinePx;
  return direction * Math.min(terminalWheelMaxLinesPerEvent, lines);
}

function queueTmuxScroll(item, signedLines) {
  item.pendingScrollLines = (item.pendingScrollLines || 0) + signedLines;
  if (item.scrollTimer) return;
  item.scrollTimer = setTimeout(() => {
    item.scrollTimer = null;
    const signed = item.pendingScrollLines || 0;
    item.pendingScrollLines = 0;
    if (!signed || item.socket?.readyState !== WebSocket.OPEN) return;
    const direction = signed < 0 ? 'up' : 'down';
    const lines = Math.max(1, Math.min(80, Math.ceil(Math.abs(signed))));
    item.socket.send(JSON.stringify({type: 'tmux-scroll', direction, lines}));
  }, 30);
}

function queueLocalTerminalScroll(term, signedLines) {
  term.pendingWheelScrollLines = (term.pendingWheelScrollLines || 0) + signedLines;
  if (term.wheelScrollTimer) return;
  term.wheelScrollTimer = setTimeout(() => {
    term.wheelScrollTimer = null;
    const signed = term.pendingWheelScrollLines || 0;
    term.pendingWheelScrollLines = 0;
    if (!signed) return;
    const direction = signed < 0 ? -1 : 1;
    const lines = Math.max(1, Math.min(80, Math.ceil(Math.abs(signed))));
    term.scrollLines(direction * lines);
  }, 30);
}

function closeTerminalItem(session, item) {
  item.manualClose = true;
  if (item.reconnectTimer) clearTimeout(item.reconnectTimer);
  if (item.resizeTimer) clearTimeout(item.resizeTimer);
  if (item.scrollTimer) clearTimeout(item.scrollTimer);
  if (item.fitFrame) cancelAnimationFrame(item.fitFrame);
  if (item.fitTimer) clearTimeout(item.fitTimer);
  if (item.blankScreenRefreshTimer) clearTimeout(item.blankScreenRefreshTimer);
  if (item.attentionHighlightFrame) cancelAnimationFrame(item.attentionHighlightFrame);
  item.fileUnderlineController?.dispose?.();
  item.fitFrame = 0;
  item.fitTimer = 0;
  item.blankScreenRefreshTimer = 0;
  item.attentionHighlightFrame = 0;
  item.fileUnderlineController = null;
  const observer = resizeObservers.get(session);
  if (observer) {
    observer.disconnect();
    resizeObservers.delete(session);
  }
  try { item.socket.close(); } catch (_) {}
  try { item.term.dispose(); } catch (_) {}
}

function dismissTerminalConnectionToasts(session) {
  dismissSessionToasts(session, {kind: 'terminal-connection'});
}

function showTerminalConnectionToast(session, text, countdownMs = toastDurationMs) {
  dismissTerminalConnectionToasts(session);
  const node = emitNotification('terminalConnection', {
    session,
    title: compactNotificationTitle(sessionLabel(session), t('tab.terminal.short'), {inApp: true}),
    body: text,
    countdownMs,
    coalesceKey: `terminal-connection:${session}`,
    onClick: () => selectSession(session, {userInitiated: true}),
  }).inApp;
  if (node) {
    node.dataset.toastSession = session;
    node.dataset.toastKind = 'terminal-connection';
  }
}

function scheduleTerminalReconnect(session, item) {
  if (item.manualClose || terminals.get(session) !== item || !activeSessions.includes(session)) return;
  const delay = Math.min(8000, 1000 * 2 ** item.reconnectAttempt);
  const seconds = Math.round(delay / 1000);
  item.reconnectAttempt += 1;
  if (item.reconnectTimer) clearTimeout(item.reconnectTimer);
  statusErr(localizedHtml('terminal.connection.reconnectingStatus', {session: sessionLabel(session), seconds}));
  showTerminalConnectionToast(session, t('terminal.connection.reconnectingToast', {seconds}), delay);
  showTerminalConnectionState(session, 'reconnecting', t('terminal.connection.reconnectingToast', {seconds}));
  item.reconnectTimer = setTimeout(() => {
    if (item.manualClose || terminals.get(session) !== item || !activeSessions.includes(session)) return;
    item.reconnectTimer = null;
    connectTerminalSocket(session, item);
  }, delay);
}

// A tmux session that is absent from the live roster has been killed (vs a transient disconnect).
function sessionConfirmedGone(session, order) {
  return isTmuxSession(session) && !isPendingTmuxSession(session) && Array.isArray(order) && !order.includes(session);
}

function terminalSocketCloseLooksFinal(event = null) {
  const code = Number(event?.code || 0);
  return event?.wasClean === true || code === 1000 || code === 1001;
}

// Tear down a dead session's UI immediately (terminal, panel, metadata) — mirrors killSession's
// cleanup without the confirm/POST, for sessions that ended outside this client.
function pruneDeadSession(session) {
  const previousActive = activeSessions.slice();
  stopSessionUi(session);
  completeTerminalRemovalLatency('session', session, {reason: 'prune-dead-session'});
  if (sessions.includes(session)) updateSessionList(sessions.filter(item => item !== session));
  updateDocumentTitle();
  renderSessionButtons();
  renderPanels(previousActive);
  renderPaneTabStrips();
  renderAutoApproveButtons();
  statusOk(localizedHtml('status.sessionEnded', {session: sessionLabel(session)}));
}

// On a terminal WebSocket close, confirm via the roster whether the session is actually gone. If so,
// prune it from the UI immediately instead of reconnecting and waiting for the next poll to notice.
async function confirmSessionGoneOrReconnect(session, item, event = null) {
  if (item.manualClose || terminals.get(session) !== item) return;
  const closeDetails = {
    origin: 'ws-close',
    closeCode: Number(event?.code || 0),
    wasClean: event?.wasClean === true,
  };
  if (terminalSocketCloseLooksFinal(event) && isTmuxSession(session) && !isPendingTmuxSession(session)) {
    noteTerminalRemovalLatencyStart('session', session, closeDetails);
    pruneDeadSession(session);
    return;
  }
  // one in-flight confirmation per terminal. A flapping WS could otherwise run several
  // concurrent confirmations, each scheduling a reconnect and double-incrementing reconnectAttempt
  // (distorting the backoff).
  if (item.confirmingGone) return;
  noteTerminalRemovalLatencyStart('session', session, closeDetails);
  item.confirmingGone = true;
  try {
    const exists = await tmuxSessionExistsForReconnect(session);
    if (item.manualClose || terminals.get(session) !== item) return;
    if (exists === false) {
      pruneDeadSession(session);
      return;
    }
    if (exists === true) {
      scheduleTerminalReconnect(session, item);
      return;
    }
    scheduleTerminalReconnect(session, item);
  } finally {
    item.confirmingGone = false;
  }
}

function estimateTerminalSize(container, term = null) {
  const content = terminalContentSize(container);
  const measured = term?._core?._renderService?._renderer?.dimensions?.css?.cell
    || term?._core?._renderService?.dimensions?.css?.cell
    || null;
  if (measured?.width && measured?.height) {
    return {
      cols: Math.max(40, Math.floor((content.width - 2) / measured.width)),
      rows: Math.max(10, Math.floor((content.height - terminalFitBottomReservePx) / measured.height)),
      contentWidth: content.width,
      contentHeight: content.height,
      cellWidth: measured.width,
      cellHeight: measured.height,
      measuredCell: 'renderer',
    };
  }
  const probe = document.createElement('span');
  probe.textContent = 'W';
  probe.style.position = 'absolute';
  probe.style.visibility = 'hidden';
  probe.style.fontFamily = terminalProbeFontFamily(container);
  probe.style.fontSize = `${Math.max(6, Math.round(Number(terminalFontSize) || 13))}px`;
  probe.style.lineHeight = '1';
  document.body.appendChild(probe);
  const rect = probe.getBoundingClientRect();
  probe.remove();
  const charWidth = Math.max(7, rect.width || 8);
  const charHeight = Math.max(14, rect.height || 16);
  return {
    cols: Math.max(40, Math.floor((content.width - 2) / charWidth)),
    rows: Math.max(10, Math.floor((content.height - terminalFitBottomReservePx) / charHeight)),
    contentWidth: content.width,
    contentHeight: content.height,
    cellWidth: charWidth,
    cellHeight: charHeight,
    measuredCell: 'probe',
  };
}

function terminalProbeFontFamily(container) {
  const localToken = getComputedStyle(container || document.documentElement)?.getPropertyValue?.('--mono-font')?.trim();
  if (localToken) return localToken;
  const rootToken = getComputedStyle(document.documentElement)?.getPropertyValue?.('--mono-font')?.trim();
  return rootToken || terminalFontFamily;
}

function terminalContentSize(container) {
  const style = getComputedStyle(container);
  const horizontalPadding = px(style.paddingLeft) + px(style.paddingRight);
  const verticalPadding = px(style.paddingTop) + px(style.paddingBottom);
  return {
    width: Math.max(0, container.clientWidth - horizontalPadding),
    height: Math.max(0, container.clientHeight - verticalPadding),
  };
}

function px(value) {
  const number = Number.parseFloat(value);
  return Number.isFinite(number) ? number : 0;
}

function slotSide(slot) {
  return slotColumn(slot);
}

function slotForItem(item, slots = layoutSlots) {
  return layoutSlotKeys(slots).find(side => paneTabs(side, slots).includes(item)) || null;
}

function slotForSession(session) {
  return slotForItem(session);
}

function slotForDropEvent(event) {
  const rect = grid.getBoundingClientRect();
  return event.clientX < rect.left + rect.width / 2 ? 'left' : 'right';
}

function layoutBoundaryDropBandPx(size) {
  const scaled = Math.max(0, Number(size) || 0) * layoutBoundaryDropFraction;
  return Math.min(layoutBoundaryDropMaxPx, Math.max(layoutBoundaryDropMinPx, scaled));
}

function rootBoundaryDropZoneForEvent(event, rect, preferredZone = null) {
  if (!rect.width || !rect.height) return null;
  const insideX = event.clientX >= rect.left && event.clientX <= rect.right;
  const insideY = event.clientY >= rect.top && event.clientY <= rect.bottom;
  if (!insideX || !insideY) return null;
  const xBand = layoutBoundaryDropBandPx(rect.width);
  const yBand = layoutBoundaryDropBandPx(rect.height);
  const candidates = [
    {zone: 'left', distance: Math.abs(event.clientX - rect.left), active: event.clientX <= rect.left + xBand},
    {zone: 'right', distance: Math.abs(rect.right - event.clientX), active: event.clientX >= rect.right - xBand},
    {zone: 'top', distance: Math.abs(event.clientY - rect.top), active: event.clientY <= rect.top + yBand},
    {zone: 'bottom', distance: Math.abs(rect.bottom - event.clientY), active: event.clientY >= rect.bottom - yBand},
  ].filter(candidate => candidate.active);
  if (preferredZone) return candidates.find(candidate => candidate.zone === preferredZone)?.zone || null;
  candidates.sort((left, right) => left.distance - right.distance);
  return candidates[0]?.zone || null;
}

function rootBoundaryLayoutTarget(slots = layoutSlots) {
  const root = slots?.[layoutTreeKey];
  if (!root) return null;
  const docked = layoutSidePaneRootSplit(root, slots);
  const targetNode = docked ? root.children?.[docked.contentIndex] : root;
  if (!targetNode) return null;
  return {
    node: targetNode,
    rect: layoutNodeScreenRect(targetNode) || grid?.getBoundingClientRect?.() || null,
  };
}

function rootBoundaryDropIntentForEvent(event) {
  const target = rootBoundaryLayoutTarget();
  const targetRect = target?.rect || grid.getBoundingClientRect();
  const zone = rootBoundaryDropZoneForEvent(event, targetRect);
  if (!zone) return null;
  return {targetSlot: slotForDropEvent(event), zone, previewNode: grid, targetRect, targetNode: target?.node, boundary: 'root'};
}

function gutterDropZoneForEvent(event, node, rect) {
  if (!node?.children?.length || !rect.width || !rect.height) return null;
  if (node.split === 'column') return event.clientY < rect.top + rect.height / 2 ? 'top' : 'bottom';
  return event.clientX < rect.left + rect.width / 2 ? 'left' : 'right';
}

function gutterDropIntentForEvent(event) {
  const resizer = event.target?.closest?.('.layout-resizer');
  const splitPath = resizer?.dataset?.splitPath;
  if (!resizer || splitPath === undefined) return null;
  const targetRect = resizer.getBoundingClientRect();
  const node = layoutNodeAtPath(splitPath);
  const zone = gutterDropZoneForEvent(event, node, targetRect);
  if (!zone) return null;
  return {targetSlot: slotForDropEvent(event), zone, previewNode: grid, targetRect, boundary: 'gutter', splitPath};
}

function dropZoneForRect(event, rect) {
  if (!rect.width || !rect.height) return 'middle';
  const x = (event.clientX - rect.left) / rect.width;
  const y = (event.clientY - rect.top) / rect.height;
  if (y < 0.24) return rect.height / 2 >= minSplitPaneHeightPx() ? 'top' : 'middle';
  if (y > 0.76) return rect.height / 2 >= minSplitPaneHeightPx() ? 'bottom' : 'middle';
  if (x < 0.24) return rect.width / 2 >= minSplitPaneWidthPx() ? 'left' : 'middle';
  if (x > 0.76) return rect.width / 2 >= minSplitPaneWidthPx() ? 'right' : 'middle';
  return 'middle';
}

function dropIntentForEvent(event, options = {}) {
  if (narrowSingleColumnMode()) {
    const slotNode = event.target?.closest?.('.drop-slot');
    const targetSlot = slotNode?.dataset.slot || firstNonFinderPaneSlot() || layoutSlotKeys()[0] || slotForNewSession();
    const targetRect = slotNode?.getBoundingClientRect?.() || grid.getBoundingClientRect();
    return {targetSlot, zone: 'middle', previewNode: slotNode || grid, targetRect};
  }
  if (options.allowBoundary === true) {
    const rootIntent = rootBoundaryDropIntentForEvent(event);
    if (rootIntent) return rootIntent;
    const gutterIntent = gutterDropIntentForEvent(event);
    if (gutterIntent) return gutterIntent;
  }
  const slotNode = event.target?.closest?.('.drop-slot');
  if (slotNode?.dataset.slot) {
    const targetSlot = slotNode.dataset.slot;
    const targetRect = slotNode.getBoundingClientRect();
    return {targetSlot, zone: dropZoneForRect(event, targetRect), previewNode: slotNode, targetRect};
  }
  return {targetSlot: slotForDropEvent(event), zone: 'middle', previewNode: null, targetRect: grid.getBoundingClientRect()};
}

function slotIsFileExplorerPane(slot) {
  return slotIsSidePane(slot);
}

function dropIntentTargetRect(intent) {
  if (!intent || typeof intent === 'string') return null;
  return intent.targetRect || intent.previewNode?.getBoundingClientRect?.() || null;
}

function minHeightForLayoutItem(_item) {
  return minSplitPaneHeightPx();
}

function dropIntentInlineSize(intent) {
  if (!intent || typeof intent === 'string') return 0;
  const rect = dropIntentTargetRect(intent);
  return Math.max(0, Number(rect?.width) || 0);
}

function dropItemCanBeDragged(item, options = {}) {
  if (isLayoutItem(item)) return true;
  return options.allowCandidate === true && isFileEditorItem(item);
}

function rectCanShowLayoutItem(rect, item) {
  if (!rect) return true;
  return (Number(rect.width) || 0) >= minWidthForLayoutItem(item)
    && (Number(rect.height) || 0) >= minHeightForLayoutItem(item);
}

function rectCanShowPaneTabs(rect, tabs) {
  if (!rect) return true;
  const items = (tabs || []).filter(isLayoutItem);
  if (!items.length) return false;
  const minWidth = Math.max(...items.map(minWidthForLayoutItem));
  const minHeight = Math.max(...items.map(minHeightForLayoutItem));
  return (Number(rect.width) || 0) >= minWidth
    && (Number(rect.height) || 0) >= minHeight;
}

function paneSwapAllowed(sourceSlot, targetSlot, slots = layoutSlots) {
  if (!sourceSlot || !targetSlot || sourceSlot === targetSlot) return false;
  const keys = layoutSlotKeys(slots);
  if (!keys.includes(sourceSlot) || !keys.includes(targetSlot)) return false;
  if (paneIsPlaceholder(sourceSlot, slots) || paneIsPlaceholder(targetSlot, slots)) return false;
  if (slotIsSidePane(sourceSlot, slots) || slotIsSidePane(targetSlot, slots)) return false;
  const sourceTabs = paneTabs(sourceSlot, slots);
  const targetTabs = paneTabs(targetSlot, slots);
  if (!sourceTabs.length || !targetTabs.length) return false;
  return rectCanShowPaneTabs(layoutSlotScreenRect(targetSlot), sourceTabs)
    && rectCanShowPaneTabs(layoutSlotScreenRect(sourceSlot), targetTabs);
}

function paneSwapTargetForEvent(event) {
  const slotNode = event.target?.closest?.('.drop-slot');
  if (slotNode?.dataset.slot) return {slot: slotNode.dataset.slot, previewNode: slotNode};
  const panel = event.target?.closest?.('.panel');
  if (panel?.dataset.slot) return {slot: panel.dataset.slot, previewNode: panel.closest?.('.drop-slot') || panel};
  if (typeof dockviewSlotForGroupElement === 'function') {
    const group = event.target?.closest?.('.dv-groupview');
    const slot = group ? dockviewSlotForGroupElement(group) : null;
    if (slot) return {slot, previewNode: group};
  }
  return {slot: null, previewNode: null};
}

function paneSwapIntentForEvent(event, sourceSlot) {
  const target = paneSwapTargetForEvent(event);
  if (!target.slot || target.slot === sourceSlot) return null;
  return {
    sourceSlot,
    targetSlot: target.slot,
    zone: 'middle',
    swap: true,
    previewNode: target.previewNode,
    targetRect: layoutSlotScreenRect(target.slot),
  };
}

function paneSwapIntentAllowed(intent) {
  return Boolean(intent?.swap && paneSwapAllowed(intent.sourceSlot, intent.targetSlot));
}

function swapPaneSlots(sourceSlot, targetSlot) {
  if (!paneSwapAllowed(sourceSlot, targetSlot)) return false;
  const next = cloneLayoutSlots(layoutSlots);
  const sourceState = paneStateForLayoutSlot(sourceSlot);
  const targetState = paneStateForLayoutSlot(targetSlot);
  next[sourceSlot] = targetState;
  next[targetSlot] = sourceState;
  applyLayoutSlots(next, {
    focusSession: activeItemForSide(targetSlot, next) || activeItemForSide(sourceSlot, next),
    prune: false,
    forceFull: dockviewLayoutActive(),
    message: t('layout.status.swapped'),
  });
  return true;
}

function dropIntentHasRoomForItem(item, intent) {
  if (!intent || typeof intent === 'string') return true;
  if (intent.boundary === 'root' || intent.boundary === 'gutter') return true;
  const rect = dropIntentTargetRect(intent);
  if (!rect) return true;
  const zone = intent.zone || 'middle';
  if (!layoutSplitZone(zone)) return rectCanShowLayoutItem(rect, item);
  const targetItem = activeItemForSide(intent.targetSlot);
  const targetMinWidth = minWidthForLayoutItem(targetItem);
  const itemMinWidth = minWidthForLayoutItem(item);
  const targetMinHeight = minHeightForLayoutItem(targetItem);
  const itemMinHeight = minHeightForLayoutItem(item);
  // A Vertical Side Pane intentionally uses a narrower role-specific width than these items use in
  // Generic Panes. Top/bottom splitting preserves that width, so only the combined height can make
  // the drop impossible; applying the Generic Pane item width here shows an overlay that can never
  // commit for dual-role YO!* tabs.
  if (slotIsSidePane(intent.targetSlot) && (zone === 'top' || zone === 'bottom')) {
    return (Number(rect.height) || 0) >= targetMinHeight + itemMinHeight;
  }
  if (zone === 'left' || zone === 'right') {
    return (Number(rect.width) || 0) >= targetMinWidth + itemMinWidth
      && (Number(rect.height) || 0) >= Math.max(targetMinHeight, itemMinHeight);
  }
  return (Number(rect.width) || 0) >= Math.max(targetMinWidth, itemMinWidth)
    && (Number(rect.height) || 0) >= targetMinHeight + itemMinHeight;
}

function itemCanSplitSinglePurposePane(item, intent) {
  const zone = typeof intent === 'string' ? intent : intent?.zone;
  if (zone !== 'top' && zone !== 'bottom') return false;
  if (!layoutIsFileSurfaceItem(item)) return false;
  if (!dropIntentTargetRect(intent)) return false;
  return dropIntentHasRoomForItem(item, intent);
}

function dropIntentAllowsSession(session, intent, options = {}) {
  if (!dropItemCanBeDragged(session, options)) return false;
  const sourceSlot = options.sourceSlot || slotForItem(session);
  if (narrowSingleColumnMode()) {
    return Boolean(intent?.targetSlot)
      && intent.zone === 'middle'
      && paneRoleAllowsItemTransfer(session, sourceSlot, intent.targetSlot, layoutSlots, {
        allowRequiredInGeneric: true,
        allowCandidate: options.allowCandidate === true,
      });
  }
  if (intent?.boundary === 'root' && layoutSplitZone(intent.zone)) {
    const sourceRole = sourceSlot ? paneRoleForSlot(sourceSlot) : paneRoleDefinition(paneRoleGeneric);
    if (sourceRole.kind === paneRoleSide) {
      if (!['left', 'right'].includes(intent.zone) || sourceRole.side === intent.zone) return false;
      return paneRoleAllowsItemTransfer(session, sourceSlot, null, layoutSlots, {
        targetRole: paneRoleDefinition(paneRoleSide, intent.zone),
        allowCandidate: options.allowCandidate === true,
      });
    }
    return paneRoleAllowsItemTransfer(session, sourceSlot, null, layoutSlots, {
      targetRole: paneRoleDefinition(paneRoleGeneric),
      allowCandidate: options.allowCandidate === true,
    });
  }
  if (intent?.boundary === 'gutter' && layoutSplitZone(intent.zone)) {
    const targetNode = layoutNodeAtPath(intent.splitPath || '', layoutSlots[layoutTreeKey]);
    return !layoutNodeContainsSidePane(targetNode)
      && paneRoleAllowsItemTransfer(session, sourceSlot, null, layoutSlots, {
        targetRole: paneRoleDefinition(paneRoleGeneric),
        allowCandidate: options.allowCandidate === true,
      });
  }
  if (!intent?.targetSlot) return false;
  if (!paneRoleAllowsItemTransfer(session, sourceSlot, intent.targetSlot, layoutSlots, {
    allowCandidate: options.allowCandidate === true,
  })) return false;
  if (!dropIntentCapacityAllowsSession(session, intent, sourceSlot)) return false;
  if (slotIsSidePane(intent.targetSlot)) {
    return intent.zone === 'middle'
      || (['top', 'bottom'].includes(intent.zone) && dropIntentHasRoomForItem(session, intent));
  }
  return dropIntentHasRoomForItem(session, intent);
}

function fileDragLayoutItem(payload) {
  const path = payload?.path || payload?.paths?.find?.(Boolean) || '';
  if (!path || payload?.kind === 'dir') return null;
  return fileEditorItemFor(path);
}

function fileDropIntentAllowsPayload(payload, intent) {
  const item = fileDragLayoutItem(payload);
  return Boolean(item && dropIntentAllowsSession(item, intent, {allowCandidate: true}));
}

function pathDropIntentAllowsPayload(payload, intent) {
  const path = payload?.path || payload?.paths?.find?.(Boolean) || '';
  const item = path ? fileEditorItemFor(path) : null;
  return Boolean(item && dropIntentAllowsSession(item, intent, {allowCandidate: true}));
}

function clearDropPreview() {
  const nodes = new Set([grid]);
  for (const className of DROP_PREVIEW_CLASSES) {
    grid.querySelectorAll(`.${className}`).forEach(node => nodes.add(node));
  }
  nodes.forEach(node => {
    node.classList.remove(...DROP_PREVIEW_CLASSES);
    node.style?.removeProperty('--tab-drop-x');
    node.style?.removeProperty('--tab-drop-y');
    node.style?.removeProperty('--tab-drop-height');
    node.style?.removeProperty('--drop-preview-left');
    node.style?.removeProperty('--drop-preview-top');
    node.style?.removeProperty('--drop-preview-width');
    node.style?.removeProperty('--drop-preview-height');
    if (node.dataset) delete node.dataset.dropLabel;
  });
}

function applyGutterDropPreviewGeometry(node, intent) {
  if (intent?.boundary !== 'gutter' || node !== grid) return;
  const gridRect = grid.getBoundingClientRect();
  const targetRect = intent.targetRect || gridRect;
  const isHorizontalBand = intent.zone === 'left' || intent.zone === 'right';
  const inlineSize = isHorizontalBand ? gridRect.width : gridRect.height;
  const bandSize = Math.max(layoutBoundaryDropMinPx * 2, Math.min(layoutBoundaryDropMaxPx * 3, inlineSize * 0.24));
  if (isHorizontalBand) {
    const center = targetRect.left + targetRect.width / 2 - gridRect.left;
    const left = Math.max(6, Math.min(gridRect.width - bandSize - 6, center - bandSize / 2));
    node.style.setProperty('--drop-preview-left', `${Math.round(left)}px`);
    node.style.setProperty('--drop-preview-top', '6px');
    node.style.setProperty('--drop-preview-width', `${Math.round(bandSize)}px`);
    node.style.setProperty('--drop-preview-height', 'calc(100% - 12px)');
  } else {
    const center = targetRect.top + targetRect.height / 2 - gridRect.top;
    const top = Math.max(6, Math.min(gridRect.height - bandSize - 6, center - bandSize / 2));
    node.style.setProperty('--drop-preview-left', '6px');
    node.style.setProperty('--drop-preview-top', `${Math.round(top)}px`);
    node.style.setProperty('--drop-preview-width', 'calc(100% - 12px)');
    node.style.setProperty('--drop-preview-height', `${Math.round(bandSize)}px`);
  }
}

function layoutNodeScreenRect(layoutNode) {
  const rects = layoutLeafSlots(layoutNode)
    .map(slot => layoutSlotScreenRect(slot))
    .filter(rect => rect && rect.width > 0 && rect.height > 0);
  if (!rects.length) return null;
  const left = Math.min(...rects.map(rect => rect.left));
  const top = Math.min(...rects.map(rect => rect.top));
  const right = Math.max(...rects.map(rect => rect.right));
  const bottom = Math.max(...rects.map(rect => rect.bottom));
  return {left, top, right, bottom, width: right - left, height: bottom - top};
}

function layoutSlotScreenRect(slot) {
  const column = layoutColumnNode(slot);
  const columnRect = column?.getBoundingClientRect?.();
  if (columnRect?.width > 0 && columnRect?.height > 0) return columnRect;
  const panel = grid?.querySelector(`.dockview-panel-content > .panel[data-slot="${cssEscape(slot)}"]`);
  const panelGroup = panel?.closest?.('.dv-groupview');
  const panelGroupRect = panelGroup?.getBoundingClientRect?.();
  if (panelGroupRect?.width > 0 && panelGroupRect?.height > 0) return panelGroupRect;
  const item = activeItemForSide(slot) || paneTabs(slot)[0] || '';
  const tabGroup = item
    ? grid?.querySelector(`.dockview-pane-tab[data-pane-tab="${cssEscape(item)}"]`)?.closest?.('.dv-groupview')
    : null;
  const tabGroupRect = tabGroup?.getBoundingClientRect?.();
  return tabGroupRect?.width > 0 && tabGroupRect?.height > 0 ? tabGroupRect : null;
}

function applyRootBoundaryPreviewGeometry(node, intent) {
  if (intent?.boundary !== 'root' || node !== grid) return;
  const gridRect = grid.getBoundingClientRect();
  const target = rootBoundaryLayoutTarget();
  const targetRect = intent.targetRect || target?.rect || gridRect;
  const targetNode = intent.targetNode || target?.node;
  if (!gridRect || !targetRect || !targetNode) return;
  const zone = intent.zone || 'middle';
  const splitPct = rootBoundarySplitPercent(targetNode, zone, null, layoutSlots, intent.item || null);
  const splitX = targetRect.left + targetRect.width * splitPct / 100;
  const splitY = targetRect.top + targetRect.height * splitPct / 100;
  let left = targetRect.left - gridRect.left + 6;
  let top = targetRect.top - gridRect.top + 6;
  let right = targetRect.right - gridRect.left - 6;
  let bottom = targetRect.bottom - gridRect.top - 6;
  if (zone === 'left') right = splitX - gridRect.left - 3;
  else if (zone === 'right') left = splitX - gridRect.left + 3;
  else if (zone === 'top') bottom = splitY - gridRect.top - 3;
  else if (zone === 'bottom') top = splitY - gridRect.top + 3;
  node.style.setProperty('--drop-preview-left', `${Math.round(left)}px`);
  node.style.setProperty('--drop-preview-top', `${Math.round(top)}px`);
  node.style.setProperty('--drop-preview-width', `${Math.round(Math.max(0, right - left))}px`);
  node.style.setProperty('--drop-preview-height', `${Math.round(Math.max(0, bottom - top))}px`);
}

function dropPreviewLabel(intent = {}) {
  const zone = intent.zone || 'middle';
  if (intent.swap === true) return t('layout.drop.swap');
  if (intent.boundary === 'root') return t('layout.drop.fullZone', {zone: t(`layout.zone.${zone}`)});
  if (intent.boundary === 'gutter') return t('layout.drop.fullSpan');
  if (zone === 'middle') return t('layout.drop.takeOver');
  return t(`layout.zone.${zone}`);
}

function showDropPreview(intent) {
  clearDropPreview();
  const node = intent?.boundary ? grid : intent?.previewNode;
  if (!node) return;
  const zone = intent.zone || 'middle';
  node.classList.add(CLS.dragOver, CLS.dropPreview, `drop-preview-${zone}`);
  if (intent.boundary) node.classList.add(`drop-preview-${intent.boundary}`);
  node.dataset.dropLabel = dropPreviewLabel(intent);
  applyGutterDropPreviewGeometry(node, intent);
  applyRootBoundaryPreviewGeometry(node, intent);
}

// Grid and Dockview use different hit testing, not different drag semantics. Classify the payload
// once, then let each surface supply only its target-intent resolver.
function classifyLayoutDrag(event, {intentForFile, intentForSession, suppressSession = () => false, ignoreMissingIntent = false} = {}) {
  const pane = paneDragPayload(event);
  if (pane?.slot) {
    const intent = paneSwapIntentForEvent(event, pane.slot);
    return {kind: 'pane', payload: pane, intent, allowed: paneSwapIntentAllowed(intent), dropEffect: 'move'};
  }
  const file = fileDragPayload(event);
  if (file?.path) {
    const intent = intentForFile?.(event) || null;
    if (ignoreMissingIntent && !intent) return null;
    return {kind: 'file', payload: file, intent, allowed: Boolean(intent?.targetSlot && fileDropIntentAllowsPayload(file, intent)), dropEffect: 'copy'};
  }
  const session = dragPayload(event);
  if (!session?.session) return null;
  if (suppressSession(event)) return {kind: 'session', payload: session, intent: null, allowed: false, dropEffect: 'none'};
  const intent = intentForSession?.(event) || null;
  if (intent) intent.item = session.session;
  if (ignoreMissingIntent && !intent) return null;
  return {kind: 'session', payload: session, intent, allowed: dropIntentAllowsSession(session.session, intent, {sourceSlot: session.sourceSlot}), dropEffect: 'move'};
}

function applyLayoutDragIntent(event, drag, {phase = 'over'} = {}) {
  if (!drag) return false;
  event.preventDefault();
  event.stopPropagation();
  if (phase === 'over') {
    event.dataTransfer.dropEffect = drag.allowed ? drag.dropEffect : 'none';
    if (drag.allowed) showDropPreview(drag.intent);
    else clearDropPreview();
    return true;
  }
  clearDropPreview();
  if (!drag.allowed) return true;
  if (drag.kind === 'pane') swapPaneSlots(drag.intent.sourceSlot, drag.intent.targetSlot);
  else if (drag.kind === 'file') openDraggedFilesInEditor(drag.payload, {targetSlot: drag.intent.targetSlot, targetZone: drag.intent.zone});
  else dropSessionWithIntent(drag.payload.session, drag.intent, drag.payload.sourceSlot || slotForSession(drag.payload.session));
  return true;
}

function dropSessionAtEvent(event) {
  applyLayoutDragIntent(event, classifyLayoutDrag(event, {
    intentForFile: candidate => dropIntentForEvent(candidate, {allowBoundary: false}),
    intentForSession: candidate => dropIntentForEvent(candidate, {allowBoundary: true}),
    suppressSession: candidate => Boolean(candidate.target?.closest?.('.panel-head')),
  }), {phase: 'drop'});
}

function handleDropDragOver(event) {
  applyLayoutDragIntent(event, classifyLayoutDrag(event, {
    intentForFile: candidate => dropIntentForEvent(candidate, {allowBoundary: false}),
    intentForSession: candidate => dropIntentForEvent(candidate, {allowBoundary: true}),
    suppressSession: candidate => Boolean(candidate.target?.closest?.('.panel-head')),
  }));
}

function handleDropDragLeave(event) {
  const current = event.currentTarget;
  if (current?.contains(event.relatedTarget)) return;
  clearDropPreview();
}
const dockviewContentComponentName = 'yolomux-panel';
const dockviewTabComponentName = 'yolomux-tab';
const dockviewPanelRenderer = 'onlyWhenVisible';
const dockviewRootId = 'dockviewRoot';
const dockviewEmptyPaneItemPrefix = '__dockview-empty-pane__:';
// named geometry/timing constants for the Dockview layer (were repeated unnamed literals).
const DRAG_HYSTERESIS_PX = 8;            // px a pointer must move before a header drag is treated as a drag
const PANE_DRAG_SUPPRESS_MS = 500;       // window after a pane drag during which pointer events are ignored
const SPLIT_PCT_EPSILON = 0.01;          // split-percent diffs below this are treated as equal (no re-layout)
const SERIALIZED_WEIGHT_BASE = 1000;     // Dockview gridview node weight base for serialization
const DOCKVIEW_MIN_LAYOUT_WIDTH = 640;   // enough room for a serialized Finder + content pane snapshot
const DOCKVIEW_MIN_LAYOUT_HEIGHT = 240;  // prevents sleep/hidden-tab 1px layouts from serializing
const dockviewLayoutState = {
  api: null,
  host: null,
  disposables: [],
  applyingFromLayout: false,
  adoptingFromDockview: false,
  syncQueued: false,
  hostLayoutFrame: 0,
  lastHostLayoutSignature: '',
  lastAppliedLayoutSignature: '',
  lastAppliedActiveOnlySignature: '',
  groupSlots: new Map(),
  pendingRootBoundaryDrop: null,
  reloadAfterAdoption: false,
  tabPointerDrag: null,
  tabContentInteractionSuppressedUntil: 0,
  tabDropHandledAt: 0,
  panePointerDrag: null,
  panePointerDragSuppressedUntil: 0,
  tabActivationPerf: null,
  pendingUserPanelActivation: '',
};

function dockviewEmptyPaneItem(slot) {
  return `${dockviewEmptyPaneItemPrefix}${encodeURIComponent(String(slot || ''))}`;
}

function dockviewEmptyPaneSlot(item) {
  const text = String(item || '');
  if (!text.startsWith(dockviewEmptyPaneItemPrefix)) return null;
  try {
    return decodeURIComponent(text.slice(dockviewEmptyPaneItemPrefix.length)) || null;
  } catch (_) {
    return null;
  }
}

function dockviewBeginTabActivationPerf(item) {
  const previous = dockviewLayoutState.tabActivationPerf;
  if (previous?.frame) cancelAnimationFrame(previous.frame);
  dockviewLayoutState.tabActivationPerf = {
    item: String(item || ''),
    token: clientPerfStart('tabActivationPaint'),
    frame: 0,
  };
}

function dockviewFinishTabActivationPerf(item) {
  const state = dockviewLayoutState.tabActivationPerf;
  if (!state || state.item !== String(item || '') || state.frame) return;
  state.frame = requestAnimationFrame(() => {
    if (dockviewLayoutState.tabActivationPerf !== state) return;
    const slot = slotForItem(state.item);
    if (slot && activeItemForSide(slot) === state.item) {
      clientPerfEnd(state.token, {nodes: document.querySelectorAll?.('.file-tree-row[data-tabber-type]')?.length || 0});
    }
    dockviewLayoutState.tabActivationPerf = null;
  });
}

function dockviewCommitPanelActivation(item, options = {}) {
  const panelItem = String(item || '');
  if (!panelItem) return false;
  const pendingUserGesture = dockviewLayoutState.pendingUserPanelActivation === panelItem;
  if (pendingUserGesture) dockviewLayoutState.pendingUserPanelActivation = '';
  const userInitiated = options.userInitiated === true || pendingUserGesture;
  if (isTmuxSession(panelItem) && userInitiated && focusedPanelItem !== panelItem) {
    noteFileExplorerChangesSessionInteraction(panelItem);
  }
  setFocusedPanelItem(panelItem, {userInitiated});
  dockviewFinishTabActivationPerf(panelItem);
  return true;
}

function dockviewCore() {
  return window['dockview-core'] || null;
}

function dockviewLayoutAvailable() {
  return typeof dockviewCore()?.createDockview === 'function';
}

function dockviewLayoutEnabled() {
  return dockviewLayoutAvailable();
}

function dockviewLayoutActive() {
  return Boolean(dockviewLayoutState.api && grid?.classList?.contains('dockview-grid'));
}

function dockviewOrientationForSplit(direction) {
  return direction === 'column' ? 'VERTICAL' : 'HORIZONTAL';
}

function dockviewSplitForOrientation(orientation) {
  return orientation === 'VERTICAL' ? 'column' : 'row';
}

function dockviewOppositeOrientation(orientation) {
  return orientation === 'VERTICAL' ? 'HORIZONTAL' : 'VERTICAL';
}

function dockviewThemeForApp() {
  const core = dockviewCore();
  if (!core) return undefined;
  return document.body?.classList?.contains(themeBodyClass('light')) ? core.themeLight : core.themeDark;
}

function dockviewSplitLayoutHasMinimumSize(zone, rect = dockviewLayoutState.host?.getBoundingClientRect?.()) {
  if (!layoutSplitZone(zone)) return false;
  if (!rect) return false;
  if (zone === 'left' || zone === 'right') {
    return (Number(rect.width) || 0) >= DOCKVIEW_MIN_LAYOUT_WIDTH;
  }
  return (Number(rect.height) || 0) >= DOCKVIEW_MIN_LAYOUT_HEIGHT;
}

function dockviewRootBoundaryDropIntent(event) {
  if (narrowSingleColumnMode()) return null;
  const tabPointerDrag = dockviewLayoutState.tabPointerDrag;
  if (event?.nativeEvent && tabPointerDrag?.item) {
    // Dockview labels the tab strip at the top of an outermost pane as a `top` edge. That is
    // useful for a deliberate root drop, but wrong for an ordinary tab move across that strip.
    // The pointer gesture owns the decision while it is live: it only returns a root intent when
    // the drag actually reaches an eligible root boundary. Falling through to Dockview's broad
    // overlay here would recreate the false top-root drop after the shared pointer resolver
    // rejected it.
    return dockviewTabPointerRootBoundaryIntentWithMemory(event.nativeEvent, tabPointerDrag);
  }
  if (!['content', 'edge', 'tab'].includes(event?.kind) || !layoutSplitZone(event.position)) return null;
  const data = event.getData?.();
  const item = resolveLayoutItem(data?.panelId || '');
  if (!isLayoutItem(item)) return null;
  const nativeEvent = event.nativeEvent;
  const target = rootBoundaryLayoutTarget();
  const rect = target?.rect || dockviewLayoutState.host?.getBoundingClientRect?.();
  if (!nativeEvent || !rect) return null;
  const zone = rootBoundaryDropZoneForEvent(nativeEvent, rect, event.position);
  if (!layoutSplitZone(zone)) return null;
  if (!dockviewSplitLayoutHasMinimumSize(zone, rect)) return null;
  return {
    item,
    zone,
    sourceSlot: slotForItem(item) || dockviewSlotForGroupId(data?.groupId || ''),
    targetRect: rect,
    targetNode: target?.node,
  };
}

function dockviewPaneContentDropInfo(event) {
  if (event?.kind !== 'content' || !event.group) return null;
  const targetSlot = dockviewSlotForGroupId(event.group.id || '');
  const targetRect = targetSlot ? layoutSlotScreenRect(targetSlot) : null;
  const fileSurfaceContent = event.nativeEvent?.target?.closest?.(
    '.file-explorer-tree-panel, .file-explorer-changes-panel, .file-tree-row',
  );
  // A real Finder/Differ row is a center-stack target. Dockview's broad edge overlay can classify
  // the same pointer as top/bottom; accepting that would turn a row drop into an accidental Side
  // split. Vertical Side splits remain available from the tab menu and actual pane-edge chrome.
  const zone = narrowSingleColumnMode() || fileSurfaceContent
    ? 'middle'
    : (event.nativeEvent && targetRect ? dropZoneForRect(event.nativeEvent, targetRect) : event.position);
  if (zone !== 'middle' && !layoutSplitZone(zone)) return null;
  const data = event.getData?.();
  const item = resolveLayoutItem(data?.panelId || '');
  if (!item || !targetSlot) return null;
  const sourceSlot = slotForItem(item) || dockviewSlotForGroupId(data?.groupId || '');
  const intent = {
    item,
    sourceSlot,
    targetSlot,
    targetRect,
    zone,
    createsPane: layoutSplitZone(zone),
  };
  return {item, intent};
}

function dockviewSideVerticalDropIntent(event, state = dockviewLayoutState.tabPointerDrag) {
  if (!state?.item || !state.slot) return null;
  const nativeEvent = event?.nativeEvent || event;
  const pointerX = Number(nativeEvent?.clientX);
  const pointerY = Number(nativeEvent?.clientY);
  if (!Number.isFinite(pointerX) || !Number.isFinite(pointerY)) return null;
  const dx = Math.abs(pointerX - (Number(state.x) || 0));
  const dy = Math.abs(pointerY - (Number(state.y) || 0));
  const explicitZone = ['top', 'bottom'].includes(event?.position) ? event.position : null;
  // A tab-strip reorder also lands in the pane's top quarter. Dockview's explicit edge position is
  // authoritative; the pointer fallback requires meaningful vertical travel. Horizontal travel is
  // irrelevant because compact tabs commonly start far from the center of a narrow edge pane.
  if (!explicitZone && dy < DRAG_HYSTERESIS_PX * 3) return null;
  const group = dockviewGroupForPoint(pointerX, pointerY);
  const targetSlot = dockviewSlotForGroupElement(group);
  const targetRect = group?.getBoundingClientRect?.();
  if (!targetSlot || !targetRect || !slotIsSidePane(targetSlot)) return null;
  const zone = explicitZone || dropZoneForRect(nativeEvent, targetRect);
  const verticalEdgeZone = ['top', 'bottom'].includes(zone);
  const hitNode = document.elementFromPoint?.(pointerX, pointerY) || nativeEvent?.target;
  const targetHeader = group.querySelector?.('.dv-tabs-and-actions-container, .dv-tabs-container')?.getBoundingClientRect?.();
  const overAnotherFileSurfaceBody = !verticalEdgeZone
    && targetSlot !== state.slot
    && isFileExplorerItem(activeItemForSide(targetSlot))
    && (!targetHeader || pointerY > targetHeader.bottom);
  if (overAnotherFileSurfaceBody) return null;
  if (!verticalEdgeZone && targetSlot !== state.slot && hitNode?.closest?.(
    '.file-explorer-tree-panel, .file-explorer-changes-panel, .file-tree-row',
  )) return null;
  const targetRole = paneRoleForSlot(targetSlot);
  if (targetRole.kind !== paneRoleSide) return null;
  const sourceRole = paneRoleForSlot(state.slot);
  // A Side-to-Side vertical split must stay on the same physical edge. Dual-role YO!* tabs may
  // also enter from a Generic Pane; in that case the target edge alone owns the new leaf.
  if (sourceRole.kind === paneRoleSide && sourceRole.side !== targetRole.side) return null;
  if (!verticalEdgeZone) return null;
  const intent = {
    item: state.item,
    sourceSlot: state.slot,
    targetSlot,
    targetRect,
    zone,
    createsPane: true,
  };
  return dropIntentAllowsSession(state.item, intent, {sourceSlot: state.slot}) ? intent : null;
}

function dockviewCommitSideVerticalDrop(intent) {
  return splitLayoutItemAtSlot(intent.item, intent.targetSlot, intent.zone, intent.sourceSlot, null, {
    forceSplitEmpty: true,
    preserveSourcePlaceholder: true,
  });
}

function dockviewPaneContentDropIntent(event) {
  const info = dockviewPaneContentDropInfo(event);
  return dockviewPaneContentSplitAllowed(info) ? info.intent : null;
}

function dockviewPaneContentDropAllowed(info) {
  return Boolean(
    info
      && !dockviewPinnedTabCrossPaneViolation(info.intent)
      && dropIntentAllowsSession(info.item, info.intent)
  );
}

function dockviewPaneContentSplitAllowed(info) {
  return Boolean(
    dockviewPaneContentDropAllowed(info)
      && layoutSplitZone(info.intent.zone)
      && dockviewSplitLayoutHasMinimumSize(info.intent.zone)
  );
}

function dockviewShouldSuppressPaneContentDrop(event) {
  const info = dockviewPaneContentDropInfo(event);
  return Boolean(info && (
    (narrowSingleColumnMode() && event.position !== 'center')
      ||
    !dockviewPaneContentDropAllowed(info)
      || (layoutSplitZone(info.intent.zone) && !dockviewPaneContentSplitAllowed(info))
  ));
}

function dockviewShouldSuppressReservedRootBoundary(event) {
  return false;
}

function dockviewClearRootBoundaryPreview() {
  if (!grid?.classList?.contains('drop-preview-root')) return;
  clearDropPreview();
}

function dockviewSetInvalidTabDropPreview(active) {
  dockviewLayoutState.host?.classList?.toggle('dockview-invalid-tab-drop-preview', Boolean(active));
}

function dockviewShowRootBoundaryPreview(intent) {
  if (!intent || typeof showDropPreview !== 'function') {
    dockviewClearRootBoundaryPreview();
    return;
  }
  showDropPreview({
    boundary: 'root',
    item: intent.item,
    previewNode: grid,
    sourceSlot: intent.sourceSlot,
    targetRect: intent.targetRect || dockviewLayoutState.host?.getBoundingClientRect?.(),
    targetNode: intent.targetNode,
    targetSlot: intent.sourceSlot,
    zone: intent.zone,
  });
}

function dockviewTrackRootBoundaryOverlay(event) {
  const invalidTabDrop = dockviewTabDropViolatesPinnedPartition(event);
  const paneInfo = dockviewPaneContentDropInfo(event);
  const capacityRefusal = dockviewTabCapacityRefusalStatus(event) || (paneInfo?.intent?.zone === 'middle'
    ? dropIntentCapacityRefusalStatus(paneInfo.item, paneInfo.intent, paneInfo.intent.sourceSlot)
    : '');
  dockviewSetInvalidTabDropPreview(invalidTabDrop || Boolean(capacityRefusal));
  if (invalidTabDrop || capacityRefusal) {
    dockviewLayoutState.pendingRootBoundaryDrop = null;
    dockviewClearRootBoundaryPreview();
    return;
  }
  const intent = dockviewRootBoundaryDropIntent(event);
  if (dockviewPinnedTabRootBoundaryViolation(intent)) {
    dockviewLayoutState.pendingRootBoundaryDrop = null;
    dockviewClearRootBoundaryPreview();
    event.preventDefault?.();
    return;
  }
  if (intent) {
    dockviewLayoutState.pendingRootBoundaryDrop = {
      ...intent,
      signature: layoutSlotsSignature(layoutSlots),
    };
    dockviewShowRootBoundaryPreview(intent);
    event.preventDefault?.();
    return;
  }
  if (dockviewTabDropWouldNoop(event)) {
    dockviewLayoutState.pendingRootBoundaryDrop = null;
    dockviewClearRootBoundaryPreview();
    event.preventDefault?.();
    return;
  }
  const paneIntent = dockviewPaneContentDropIntent(event);
  dockviewLayoutState.pendingRootBoundaryDrop = null;
  if (dockviewShouldSuppressPaneContentDrop(event) || (!paneIntent && dockviewShouldSuppressReservedRootBoundary(event))) {
    dockviewClearRootBoundaryPreview();
    event.preventDefault?.();
  } else {
    dockviewClearRootBoundaryPreview();
  }
}

function dockviewTabDropWouldNoop(event) {
  const stripEnd = dockviewTabStripEndDropInfoForEvent(event);
  if (stripEnd) return dockviewTabStripEndDropWouldNoop(stripEnd);
  if (dockviewTabEdgeReorderIntent(event)) return false;
  const info = dockviewTabInsertionInfo(event);
  return Boolean(info && info.sourceSlot === info.targetSlot && info.adjustedIndex === info.sourceIndex);
}

// Resolve the DROP TARGET tab for a dockview tab-drop event by POINTER COORDINATES, never by
// `nativeEvent.target` alone: with `dndStrategy: 'pointer'` the dragged tab smooth-reorders UNDER the
// cursor, so the element under the pointer at drop time is usually the dragged tab itself. Hit-testing
// that made every slow same-strip reorder look like a self-drop and the no-op veto silently swallowed
// it (the "drag first tab to second does nothing" bug). Excludes the dragged tab, picks the tab whose
// rect contains the pointer x (nearest rect when the pointer sits over the dragged tab's visual gap or
// past the strip ends), and recomputes left/right from the resolved tab's own rect.
function dockviewTabDropHit(event, item) {
  const nativeEvent = event.nativeEvent;
  const nativeTarget = nativeEvent?.target;
  const hoveredTab = nativeTarget?.closest?.('.dv-tab') || null;
  const tabStrip = nativeTarget?.closest?.('.dv-tabs-container') || hoveredTab?.parentElement || null;
  if (!tabStrip) return null;
  const tabs = Array.from(tabStrip.querySelectorAll?.('.dv-tab') || []);
  if (!tabs.length) return null;
  const tabItems = tabs.map(tab => tab.querySelector?.('.dockview-pane-tab')?.dataset?.paneTab || '');
  const sourceIndex = tabItems.indexOf(item);
  const pointerX = Number(nativeEvent?.clientX);
  const hoveredIsDragged = hoveredTab ? tabs.indexOf(hoveredTab) === sourceIndex && sourceIndex >= 0 : false;
  let targetTab = !hoveredIsDragged ? hoveredTab : null;
  if ((!targetTab || !tabs.includes(targetTab)) && Number.isFinite(pointerX)) {
    let best = null;
    for (let index = 0; index < tabs.length; index++) {
      if (index === sourceIndex) continue;   // never resolve to the dragged tab
      const rect = tabs[index].getBoundingClientRect();
      const distance = pointerX < rect.left ? rect.left - pointerX : (pointerX > rect.right ? pointerX - rect.right : 0);
      if (!best || distance < best.distance) best = {tab: tabs[index], distance};
    }
    targetTab = best?.tab || null;
  }
  if (!targetTab) return null;
  const targetIndex = tabs.indexOf(targetTab);
  if (targetIndex < 0) return null;
  let position = event.position === 'right' ? 'right' : 'left';
  if (Number.isFinite(pointerX)) {
    const rect = targetTab.getBoundingClientRect();
    position = pointerX >= rect.left + rect.width / 2 ? 'right' : 'left';
  }
  return {tabs, tabItems, sourceIndex, targetTab, targetIndex, position};
}

function dockviewTabInsertionInfo(event) {
  if (event?.kind !== 'tab') return null;
  const data = event.getData?.();
  const item = resolveLayoutItem(data?.panelId || '');
  const targetSlot = dockviewSlotForGroupId(event.group?.id || '');
  const sourceSlot = slotForItem(item) || dockviewSlotForGroupId(data?.groupId || '');
  if (!item || !targetSlot) return null;
  const hit = dockviewTabDropHit(event, item);
  if (!hit) return null;
  const {tabItems, sourceIndex, targetIndex, position} = hit;
  const insertionIndex = position === 'right' ? targetIndex + 1 : targetIndex;
  const adjustedIndex = insertionIndex - (sourceSlot === targetSlot && sourceIndex >= 0 && sourceIndex < insertionIndex ? 1 : 0);
  const targetItems = tabItems.filter(tab => tab && tab !== item);
  const pinnedBoundary = targetItems.filter(tabIsPinned).length;
  return {item, targetSlot, sourceSlot, sourceIndex, targetIndex, tabItems, targetItems, position, insertionIndex, adjustedIndex, pinnedBoundary};
}

function dockviewTabStripForPoint(x, y) {
  const node = document.elementFromPoint?.(x, y);
  return node?.closest?.('.dv-tabs-container') || null;
}

function dockviewTabStripEndDropInfo(options = {}) {
  const tabStrip = options.tabStrip;
  const item = options.item || '';
  const pointerX = Number(options.pointerX);
  if (!tabStrip || !item || !Number.isFinite(pointerX)) return null;
  const tabs = Array.from(tabStrip.querySelectorAll?.('.dv-tab') || []);
  if (!tabs.length) return null;
  const tabItems = tabs.map(tab => tab.querySelector?.('.dockview-pane-tab')?.dataset?.paneTab || '');
  const sourceIndex = tabItems.indexOf(item);
  const targetItems = tabItems.filter(tab => tab && tab !== item);
  const candidateTabs = tabs.filter((_, index) => index !== sourceIndex);
  if (!candidateTabs.length) return null;
  const stripRect = tabStrip.getBoundingClientRect?.();
  if (!stripRect) return null;
  const lastRect = candidateTabs
    .map(tab => tab.getBoundingClientRect())
    .filter(rect => rect && Number.isFinite(rect.right))
    .reduce((best, rect) => (!best || rect.right > best.right ? rect : best), null);
  if (!lastRect || pointerX < lastRect.right || pointerX > stripRect.right) return null;
  const adjustedIndex = targetItems.length;
  return {
    item,
    targetSlot: options.targetSlot || '',
    sourceSlot: options.sourceSlot || '',
    sourceIndex,
    tabItems,
    targetItems,
    position: 'right',
    insertionIndex: tabItems.length,
    adjustedIndex,
    insertIndex: adjustedIndex,
    pinnedBoundary: targetItems.filter(tabIsPinned).length,
  };
}

function dockviewTabStripEndDropInfoForEvent(event) {
  if (event?.kind !== 'tab') return null;
  const data = event.getData?.();
  const item = resolveLayoutItem(data?.panelId || '');
  const nativeEvent = event.nativeEvent;
  const nativeTarget = nativeEvent?.target;
  const tabStrip = nativeTarget?.closest?.('.dv-tabs-container') || null;
  const targetSlot = dockviewSlotForGroupId(event.group?.id || '') || dockviewSlotForGroupElement(tabStrip?.closest?.('.dv-groupview'));
  const sourceSlot = slotForItem(item) || dockviewSlotForGroupId(data?.groupId || '');
  return dockviewTabStripEndDropInfo({
    tabStrip,
    item,
    targetSlot,
    sourceSlot,
    pointerX: nativeEvent?.clientX,
  });
}

function dockviewTabStripEndDropInfoForPointer(event, state) {
  if (!state?.item || !state.slot) return null;
  const x = Number(event.clientX) || 0;
  const y = Number(event.clientY) || 0;
  const tabStrip = dockviewTabStripForPoint(x, y);
  const targetSlot = dockviewSlotForGroupElement(tabStrip?.closest?.('.dv-groupview'));
  return dockviewTabStripEndDropInfo({
    tabStrip,
    item: state.item,
    targetSlot,
    sourceSlot: state.slot,
    pointerX: x,
  });
}

function dockviewTabStripEndDropWouldNoop(info) {
  return Boolean(info?.sourceSlot && info.sourceSlot === info.targetSlot && info.sourceIndex === info.insertIndex);
}

function dockviewTabStripEndDropViolatesPinnedPartition(info) {
  if (!info || !isPinnableTab(info.item)) return false;
  if (dockviewPinnedTabCrossPaneViolation(info)) return true;
  return tabIsPinned(info.item)
    ? info.adjustedIndex > info.pinnedBoundary
    : info.adjustedIndex < info.pinnedBoundary;
}

function dockviewTabStripEndDropIntent(event) {
  const info = dockviewTabStripEndDropInfoForEvent(event);
  if (!info || !info.targetSlot || dockviewTabStripEndDropWouldNoop(info)) return null;
  if (dockviewTabStripEndDropViolatesPinnedPartition(info)) return null;
  return info;
}

function dockviewTabDropViolatesPinnedPartition(event) {
  const stripEnd = dockviewTabStripEndDropInfoForEvent(event);
  if (stripEnd) return dockviewTabStripEndDropViolatesPinnedPartition(stripEnd);
  if (dockviewTabEdgeReorderIntent(event)) return false;
  const info = dockviewTabInsertionInfo(event);
  if (!info || !isPinnableTab(info.item)) return false;
  if (dockviewPinnedTabCrossPaneViolation(info)) return true;
  return tabIsPinned(info.item)
    ? info.adjustedIndex > info.pinnedBoundary
    : info.adjustedIndex < info.pinnedBoundary;
}

function dockviewTabCapacityRefusalStatus(event) {
  const info = dockviewTabStripEndDropInfoForEvent(event) || dockviewTabInsertionInfo(event);
  if (!info || !info.targetSlot) return '';
  return dropIntentCapacityRefusalStatus(info.item, {targetSlot: info.targetSlot, zone: 'middle'}, info.sourceSlot);
}

function dockviewPinnedTabCrossPaneViolation(info) {
  if (!info?.item || !tabIsPinned(info.item) || !info.sourceSlot) return false;
  if (info.createsPane === true) return true;
  return Boolean(info.targetSlot && info.targetSlot !== info.sourceSlot);
}

function dockviewPinnedTabRootBoundaryViolation(intent) {
  return dockviewPinnedTabCrossPaneViolation({
    item: intent?.item || '',
    sourceSlot: intent?.sourceSlot || '',
    createsPane: true,
  });
}

function dockviewAdjacentEdgeTabInsertIndex(sourceIndex, targetIndex, tabCount) {
  if (sourceIndex < 0 || targetIndex < 0 || Math.abs(sourceIndex - targetIndex) !== 1) return null;
  if (sourceIndex !== 0 && sourceIndex !== tabCount - 1) return null;
  return targetIndex;
}

function dockviewTabEdgeReorderIntent(event) {
  if (event?.kind !== 'tab') return null;
  const data = event.getData?.();
  const item = resolveLayoutItem(data?.panelId || '');
  const targetSlot = dockviewSlotForGroupId(event.group?.id || '');
  const sourceSlot = slotForItem(item) || dockviewSlotForGroupId(data?.groupId || '');
  if (!item || !targetSlot || sourceSlot !== targetSlot) return null;
  const hit = dockviewTabDropHit(event, item);   // coordinate-resolved: never the dragged tab itself
  if (!hit) return null;
  const targetItem = hit.tabItems[hit.targetIndex] || '';
  if (!tabIsPinned(item) || !tabIsPinned(targetItem)) return null;
  const insertIndex = dockviewAdjacentEdgeTabInsertIndex(hit.sourceIndex, hit.targetIndex, hit.tabs.length);
  if (insertIndex === null) return null;
  if (!targetSlot || slotIsFileExplorerPane(targetSlot)) return null;
  return {item, targetSlot, sourceSlot, insertIndex};
}

function dockviewTabForPoint(x, y) {
  const node = document.elementFromPoint?.(x, y);
  const tab = node?.closest?.('.dv-tab');
  return tab?.querySelector?.('.dockview-pane-tab') || node?.closest?.('.dockview-pane-tab') || null;
}

function dockviewSuppressPanePointerDrag(ms = PANE_DRAG_SUPPRESS_MS) {
  dockviewLayoutState.panePointerDragSuppressedUntil = Math.max(
    Number(dockviewLayoutState.panePointerDragSuppressedUntil) || 0,
    Date.now() + ms,
  );
}

function dockviewPanePointerDragSuppressed() {
  return Boolean(
    dockviewLayoutState.tabPointerDrag
      || Date.now() < (Number(dockviewLayoutState.panePointerDragSuppressedUntil) || 0),
  );
}

function dockviewBeginTabPointerDrag(event, item) {
  if (event.button !== undefined && event.button !== 0) return;
  const slot = slotForItem(item);
  if (!slot) return;
  dockviewSuppressPanePointerDrag();
  dockviewLayoutState.tabPointerDrag = {
    item,
    slot,
    x: Number(event.clientX) || 0,
    y: Number(event.clientY) || 0,
    rootBoundaryStartEdges: dockviewRootBoundaryEdgesAtPoint(event),
    rootBoundaryExitedEdges: {},
    lastRootBoundaryIntent: null,
  };
}

function dockviewTabContentInteractionSuppressed() {
  return Boolean(
    dockviewLayoutState.tabPointerDrag
      || Date.now() < (Number(dockviewLayoutState.tabContentInteractionSuppressedUntil) || 0),
  );
}

function dockviewRootBoundaryEdgesAtPoint(event, rect = null) {
  const targetRect = rect || rootBoundaryLayoutTarget()?.rect || dockviewLayoutState.host?.getBoundingClientRect?.();
  if (!targetRect?.width || !targetRect?.height) return {};
  const x = Number(event?.clientX);
  const y = Number(event?.clientY);
  if (!Number.isFinite(x) || !Number.isFinite(y)) return {};
  const xBand = layoutBoundaryDropBandPx(targetRect.width);
  const yBand = layoutBoundaryDropBandPx(targetRect.height);
  return {
    left: x >= targetRect.left && x <= targetRect.left + xBand,
    right: x <= targetRect.right && x >= targetRect.right - xBand,
    top: y >= targetRect.top && y <= targetRect.top + yBand,
    bottom: y <= targetRect.bottom && y >= targetRect.bottom - yBand,
  };
}

function dockviewUpdateRootBoundaryExitEdges(event, state, rect) {
  if (!state) return;
  const startEdges = state.rootBoundaryStartEdges || {};
  const currentEdges = dockviewRootBoundaryEdgesAtPoint(event, rect);
  const exitedEdges = state.rootBoundaryExitedEdges || (state.rootBoundaryExitedEdges = {});
  for (const zone of ['left', 'right', 'top', 'bottom']) {
    if (startEdges[zone] && !currentEdges[zone]) exitedEdges[zone] = true;
  }
}

function dockviewTabPointerRootBoundaryIntent(event, state = dockviewLayoutState.tabPointerDrag) {
  if (!state?.item || narrowSingleColumnMode()) return null;
  const target = rootBoundaryLayoutTarget();
  const rect = target?.rect || dockviewLayoutState.host?.getBoundingClientRect?.();
  if (!rect) return null;
  dockviewUpdateRootBoundaryExitEdges(event, state, rect);
  const dx = (Number(event.clientX) || 0) - state.x;
  const dy = (Number(event.clientY) || 0) - state.y;
  const horizontalZone = Math.abs(dx) >= DRAG_HYSTERESIS_PX
    ? rootBoundaryDropZoneForEvent(event, rect, dx >= 0 ? 'right' : 'left')
    : null;
  const verticalZone = Math.abs(dy) >= DRAG_HYSTERESIS_PX
    ? rootBoundaryDropZoneForEvent(event, rect, dy >= 0 ? 'bottom' : 'top')
    : null;
  let zone = horizontalZone && verticalZone
    ? (Math.abs(dx) >= Math.abs(dy) ? horizontalZone : verticalZone)
    : (horizontalZone || verticalZone);
  // A deliberate edge gesture can return to the tab's original root band, making its final
  // start-to-end delta too small to identify an axis. The tracked exit proves it was not merely
  // released in the header; use the current boundary only for that re-entry case.
  if (!zone) {
    const reenteredZone = rootBoundaryDropZoneForEvent(event, rect);
    if (reenteredZone && state.rootBoundaryStartEdges?.[reenteredZone] && state.rootBoundaryExitedEdges?.[reenteredZone]) {
      zone = reenteredZone;
    }
  }
  // A tab header can itself live inside an outer root band's top/left/right/bottom hit area.
  // Require the pointer to leave that same band once before it can create a new outer pane there.
  // That preserves ordinary tab movement from the outermost pane while retaining an explicit,
  // intentional root-edge gesture: move into the content area, then back to the desired edge.
  if (zone && state.rootBoundaryStartEdges?.[zone] && !state.rootBoundaryExitedEdges?.[zone]) return null;
  if (!layoutSplitZone(zone) || !dockviewSplitLayoutHasMinimumSize(zone, rect)) return null;
  return {
    item: state.item,
    zone,
    sourceSlot: state.slot,
    targetRect: rect,
    targetNode: target?.node,
  };
}

function dockviewTabPointerRootBoundaryIntentWithMemory(event, state = dockviewLayoutState.tabPointerDrag) {
  if (!state) return null;
  const intent = dockviewTabPointerRootBoundaryIntent(event, state);
  if (intent) {
    state.lastRootBoundaryIntent = intent;
    return intent;
  }
  const x = Number(event?.clientX);
  const y = Number(event?.clientY);
  const hasUsableCoordinates = Number.isFinite(x) && Number.isFinite(y) && (x !== 0 || y !== 0);
  if (hasUsableCoordinates) state.lastRootBoundaryIntent = null;
  return hasUsableCoordinates ? null : state.lastRootBoundaryIntent;
}

function dockviewTrackTabPointerDrag(event) {
  const state = dockviewLayoutState.tabPointerDrag;
  if (!state?.item) return;
  const dx = Math.abs((Number(event.clientX) || 0) - state.x);
  const dy = Math.abs((Number(event.clientY) || 0) - state.y);
  if (Math.max(dx, dy) < DRAG_HYSTERESIS_PX) return;
  const intent = dockviewTabPointerRootBoundaryIntentWithMemory(event, state);
  if (intent && !dockviewPinnedTabRootBoundaryViolation(intent)) dockviewShowRootBoundaryPreview(intent);
  else dockviewClearRootBoundaryPreview();
}

function dockviewFinishTabPointerDrag(event) {
  const state = dockviewLayoutState.tabPointerDrag;
  dockviewLayoutState.tabPointerDrag = null;
  dockviewSetInvalidTabDropPreview(false);
  dockviewClearRootBoundaryPreview();
  if (state) dockviewSuppressPanePointerDrag();
  if (!state?.item || !state.slot) return;
  const dx = Math.abs((Number(event.clientX) || 0) - state.x);
  const dy = Math.abs((Number(event.clientY) || 0) - state.y);
  if (Math.max(dx, dy) < DRAG_HYSTERESIS_PX) return;
  dockviewLayoutState.tabContentInteractionSuppressedUntil = Date.now() + PANE_DRAG_SUPPRESS_MS;
  const sideIntent = dockviewSideVerticalDropIntent(event, state);
  if (sideIntent) {
    // This gesture belongs to the app layout, not Dockview's center-stack transaction. Commit it
    // before Dockview can flatten the tab back into one group. Keep propagation intact so Dockview
    // can remove its own drag ghost; preventDefault marks the release as app-owned.
    event.preventDefault?.();
    dockviewLayoutState.tabDropHandledAt = Date.now();
    void dockviewCommitSideVerticalDrop(sideIntent);
    return;
  }
  const rootIntent = dockviewTabPointerRootBoundaryIntentWithMemory(event, state);
  if (rootIntent && !dockviewPinnedTabRootBoundaryViolation(rootIntent)) {
    // The app owns the visible root-edge preview. Commit it before Dockview's generic tab-drop
    // stamp can make the pointer fallback stand down without producing the requested root split.
    event.preventDefault?.();
    dockviewLayoutState.tabDropHandledAt = Date.now();
    void splitSessionAtLayoutBoundary(rootIntent.item, rootIntent.zone, rootIntent.sourceSlot);
    return;
  }
  const stripEnd = dockviewTabStripEndDropInfoForPointer(event, state);
  if (stripEnd && !dockviewTabStripEndDropWouldNoop(stripEnd) && !dockviewTabStripEndDropViolatesPinnedPartition(stripEnd)) {
    window.setTimeout(() => {
      if (Date.now() - (Number(dockviewLayoutState.tabDropHandledAt) || 0) < 800) return;
      void moveSessionToSlot(stripEnd.item, stripEnd.targetSlot, stripEnd.sourceSlot, stripEnd.insertIndex);
    }, 0);
    return;
  }
  const targetGroup = dockviewGroupForPoint(Number(event.clientX) || 0, Number(event.clientY) || 0);
  const contentTargetSlot = dockviewSlotForGroupElement(targetGroup);
  const contentIntent = contentTargetSlot ? {
    item: state.item,
    sourceSlot: state.slot,
    targetSlot: contentTargetSlot,
    targetRect: layoutSlotScreenRect(contentTargetSlot),
    zone: 'middle',
    createsPane: false,
  } : null;
  if (
    contentTargetSlot
    && contentTargetSlot !== state.slot
    && !dockviewPinnedTabCrossPaneViolation(contentIntent)
    && dropIntentAllowsSession(state.item, contentIntent)
  ) {
    window.setTimeout(() => {
      // Dockview's onWillDrop may have committed an edge split after the document-level pointer
      // fallback queued this center move. Do not collapse that newer app-owned transaction.
      if (Date.now() - (Number(dockviewLayoutState.tabDropHandledAt) || 0) < 800) return;
      if (slotForItem(state.item) === contentTargetSlot) return;
      void moveSessionToSlot(state.item, contentTargetSlot, state.slot, paneTabs(contentTargetSlot).length);
    }, 0);
    return;
  }
  const target = dockviewTabForPoint(Number(event.clientX) || 0, Number(event.clientY) || 0);
  const targetItem = target?.dataset?.paneTab || '';
  if (!targetItem || targetItem === state.item) return;
  if (!tabIsPinned(state.item) || !tabIsPinned(targetItem)) return;
  const targetSlot = slotForItem(targetItem);
  if (!targetSlot || targetSlot !== state.slot || slotIsFileExplorerPane(targetSlot)) return;
  const tabs = paneTabs(targetSlot);
  const sourceIndex = tabs.indexOf(state.item);
  const targetIndex = tabs.indexOf(targetItem);
  const insertIndex = dockviewAdjacentEdgeTabInsertIndex(sourceIndex, targetIndex, tabs.length);
  if (insertIndex === null) return;
  window.setTimeout(() => {
    // The fallback only acts when dockview's own drop pipeline did NOT handle this gesture (onWillDrop
    // stamps tabDropHandledAt). Without this guard the fallback re-runs the swap AFTER the primary move
    // and, in a two-tab strip, computes the mirror swap — silently UNDOING the user's drag.
    if (Date.now() - (Number(dockviewLayoutState.tabDropHandledAt) || 0) < 800) return;
    const currentTabs = paneTabs(targetSlot);
    const currentSourceIndex = currentTabs.indexOf(state.item);
    const currentTargetIndex = currentTabs.indexOf(targetItem);
    const currentInsertIndex = dockviewAdjacentEdgeTabInsertIndex(currentSourceIndex, currentTargetIndex, currentTabs.length);
    if (currentInsertIndex === null) return;
    void moveSessionToSlot(state.item, targetSlot, targetSlot, currentInsertIndex);
  }, 0);
}

function dockviewGroupForPoint(x, y) {
  const direct = document.elementFromPoint?.(x, y)?.closest?.('.dv-groupview');
  const directRect = direct?.getBoundingClientRect?.();
  if (directRect && x >= directRect.left && x <= directRect.right && y >= directRect.top && y <= directRect.bottom) return direct;
  // Dockview's drop overlay can be the topmost hit-test node while a tab is being dragged, so
  // elementFromPoint may not have a group ancestor even though the pointer is visibly inside one.
  return Array.from(dockviewLayoutState.host?.querySelectorAll?.('.dv-groupview') || []).find(group => {
    const rect = group.getBoundingClientRect?.();
    return rect && x >= rect.left && x <= rect.right && y >= rect.top && y <= rect.bottom;
  }) || null;
}

function dockviewBeginPanePointerDrag(event, sourceSlot) {
  if (event.button !== undefined && event.button !== 0) return;
  if (dockviewPanePointerDragSuppressed() || dockviewLayoutState.panePointerDrag) return;
  if (!sourceSlot || slotIsFileExplorerPane(sourceSlot) || !activeItemForSide(sourceSlot)) return;
  dockviewLayoutState.panePointerDrag = {
    sourceSlot,
    active: false,
    previewStarted: false,
    x: Number(event.clientX) || 0,
    y: Number(event.clientY) || 0,
  };
}

function dockviewPanePointerIntent(event) {
  const state = dockviewLayoutState.panePointerDrag;
  if (!state?.sourceSlot) return null;
  const group = dockviewGroupForPoint(Number(event.clientX) || 0, Number(event.clientY) || 0);
  const targetSlot = group ? dockviewSlotForGroupElement(group) : null;
  if (!targetSlot || targetSlot === state.sourceSlot) return null;
  return {
    sourceSlot: state.sourceSlot,
    targetSlot,
    zone: 'middle',
    swap: true,
    previewNode: group,
    targetRect: layoutSlotScreenRect(targetSlot),
  };
}

function dockviewTrackPanePointerDrag(event) {
  const state = dockviewLayoutState.panePointerDrag;
  if (!state?.sourceSlot) return;
  const dx = Math.abs((Number(event.clientX) || 0) - state.x);
  const dy = Math.abs((Number(event.clientY) || 0) - state.y);
  if (!state.active && Math.max(dx, dy) < DRAG_HYSTERESIS_PX) return;
  state.active = true;
  if (!state.previewStarted) {
    startPaneDragPreview(event, state.sourceSlot);
    state.previewStarted = true;
  } else {
    moveCustomDragPreview(event);
  }
  const intent = dockviewPanePointerIntent(event);
  if (!paneSwapIntentAllowed(intent)) {
    clearDropPreview();
    return;
  }
  showDropPreview(intent);
}

function dockviewFinishPanePointerDrag(event) {
  const state = dockviewLayoutState.panePointerDrag;
  const intent = dockviewPanePointerIntent(event);
  dockviewLayoutState.panePointerDrag = null;
  if (!state?.active) {
    return;
  }
  if (state.previewStarted) stopCustomDragPreview();
  clearDropPreview();
  if (paneSwapIntentAllowed(intent)) swapPaneSlots(intent.sourceSlot, intent.targetSlot);
}

function dockviewFinishPendingRootBoundaryDrop(event) {
  const pending = dockviewLayoutState.pendingRootBoundaryDrop;
  dockviewClearRootBoundaryPreview();
  if (!pending) return;
  const rect = pending.targetRect || rootBoundaryLayoutTarget()?.rect || dockviewLayoutState.host?.getBoundingClientRect?.();
  const zone = rect ? rootBoundaryDropZoneForEvent(event, rect) : null;
  if (zone !== pending.zone) {
    dockviewLayoutState.pendingRootBoundaryDrop = null;
    return;
  }
  window.setTimeout(() => {
    if (dockviewLayoutState.pendingRootBoundaryDrop !== pending) return;
    dockviewLayoutState.pendingRootBoundaryDrop = null;
    if (layoutSlotsSignature(layoutSlots) !== pending.signature || !itemInLayout(pending.item)) return;
    void splitSessionAtLayoutBoundary(pending.item, pending.zone, pending.sourceSlot);
  }, 0);
}

function dockviewInstallRootBoundaryDropFallback() {
  const finish = event => dockviewFinishPendingRootBoundaryDrop(event);
  window.addEventListener('pointerup', finish, true);
  window.addEventListener('dragend', finish, true);
  return {
    dispose() {
      window.removeEventListener('pointerup', finish, true);
      window.removeEventListener('dragend', finish, true);
    },
  };
}

function dockviewGroupForEvent(event) {
  return event.target?.closest?.('.dv-groupview') || null;
}

function dockviewSlotForGroupElement(group) {
  if (!group) return '';
  const panelSlot = group.querySelector('.dockview-panel-content > .panel')?.dataset?.slot;
  if (panelSlot) return panelSlot;
  const activeItem = group.querySelector('.dv-tab.dv-active-tab .dockview-pane-tab')?.dataset?.paneTab || '';
  return slotForItem(activeItem) || '';
}

function dockviewGroupDropIntentForEvent(event) {
  const group = dockviewGroupForEvent(event);
  const targetSlot = dockviewSlotForGroupElement(group);
  const targetRect = group?.getBoundingClientRect?.();
  if (!group || !targetSlot || !targetRect) return null;
  return {
    targetSlot,
    zone: dropZoneForRect(event, targetRect),
    previewNode: group,
    targetRect,
  };
}

function dockviewFileDropIntentForEvent(event) {
  return dockviewGroupDropIntentForEvent(event);
}

function dockviewCapacityRefusalForDrag(drag) {
  if (drag?.kind !== 'session' || !drag.intent) return '';
  return dropIntentCapacityRefusalStatus(drag.payload?.session, drag.intent, drag.payload?.sourceSlot || slotForItem(drag.payload?.session));
}

function dockviewHandleFileDragOver(event) {
  const drag = classifyLayoutDrag(event, {
    intentForFile: dockviewFileDropIntentForEvent,
    intentForSession: dockviewGroupDropIntentForEvent,
    ignoreMissingIntent: true,
  });
  const capacityRefusal = dockviewCapacityRefusalForDrag(drag);
  if (capacityRefusal) {
    event.preventDefault();
    event.stopPropagation();
    event.dataTransfer.dropEffect = 'none';
    dockviewSetInvalidTabDropPreview(true);
    showDropPreview(drag.intent);
    return;
  }
  applyLayoutDragIntent(event, drag);
}

function dockviewHandleFileDrop(event) {
  const drag = classifyLayoutDrag(event, {
    intentForFile: dockviewFileDropIntentForEvent,
    intentForSession: dockviewGroupDropIntentForEvent,
    ignoreMissingIntent: true,
  });
  const capacityRefusal = dockviewCapacityRefusalForDrag(drag);
  if (capacityRefusal) {
    event.preventDefault();
    event.stopPropagation();
    clearDropPreview();
    dockviewSetInvalidTabDropPreview(false);
    showLayoutStatus(capacityRefusal, 'danger');
    return;
  }
  applyLayoutDragIntent(event, drag, {phase: 'drop'});
}

function dockviewInstallFileDropBridge(host) {
  const dragOver = event => dockviewHandleFileDragOver(event);
  const drop = event => dockviewHandleFileDrop(event);
  const dragLeave = event => {
    if (host?.contains?.(event.relatedTarget)) return;
    clearDropPreview();
    dockviewSetInvalidTabDropPreview(false);
  };
  host.addEventListener('dragover', dragOver, true);
  host.addEventListener('drop', drop, true);
  host.addEventListener('dragleave', dragLeave, true);
  return {
    dispose() {
      host.removeEventListener('dragover', dragOver, true);
      host.removeEventListener('drop', drop, true);
      host.removeEventListener('dragleave', dragLeave, true);
    },
  };
}

function dockviewLayoutToHost(api = dockviewLayoutState.api, host = dockviewLayoutState.host, options = {}) {
  if (!api || !host) return;
  const size = dockviewHostLayoutSize(host);
  const width = Math.max(1, Math.round(size.width || 0));
  const height = Math.max(1, Math.round(size.height || 0));
  const signature = `${width}x${height}`;
  if (options.force !== true && dockviewLayoutState.lastHostLayoutSignature === signature) return;
  dockviewLayoutState.lastHostLayoutSignature = signature;
  api.layout?.(width, height);
  requestAnimationFrame(() => {
    if (api !== dockviewLayoutState.api || host !== dockviewLayoutState.host) return;
    dockviewSyncHeaderActionReservations();
  });
}

function dockviewScheduleLayoutToHost(api = dockviewLayoutState.api, host = dockviewLayoutState.host) {
  if (!api || !host) return;
  if (dockviewLayoutState.hostLayoutFrame) cancelAnimationFrame(dockviewLayoutState.hostLayoutFrame);
  dockviewLayoutState.hostLayoutFrame = requestAnimationFrame(() => {
    dockviewLayoutState.hostLayoutFrame = 0;
    dockviewLayoutToHost(api, host);
  });
}

function dockviewHostLayoutSize(host = dockviewLayoutState.host) {
  if (!host) return {width: DOCKVIEW_MIN_LAYOUT_WIDTH, height: DOCKVIEW_MIN_LAYOUT_HEIGHT};
  const rect = host.getBoundingClientRect?.();
  const width = Number(host.clientWidth || rect?.width || 0);
  const height = Number(host.clientHeight || rect?.height || 0);
  return {
    width: Number.isFinite(width) ? width : 0,
    height: Number.isFinite(height) ? height : 0,
  };
}

function dockviewHostCanAdoptLayout(host = dockviewLayoutState.host) {
  if (!host) return true;
  const {width, height} = dockviewHostLayoutSize(host);
  return width > 1 && height > 1;
}

function dockviewLayoutAdoptionAllowed() {
  return !shareViewMode || shareWriteMode;
}

function dockviewInstallHostResizeObserver(host, api) {
  if (typeof ResizeObserver === 'function') {
    const observer = new ResizeObserver(() => dockviewScheduleLayoutToHost(api, host));
    observer.observe(host);
    return {dispose: () => observer.disconnect()};
  }
  const resize = () => dockviewScheduleLayoutToHost(api, host);
  window.addEventListener('resize', resize);
  return {dispose: () => window.removeEventListener('resize', resize)};
}

function dockviewInstallTabPointerReorderFallback() {
  const track = event => {
    dockviewTrackTabPointerDrag(event);
    dockviewTrackPanePointerDrag(event);
  };
  const finish = event => {
    dockviewFinishTabPointerDrag(event);
    dockviewFinishPanePointerDrag(event);
  };
  document.addEventListener('pointerup', finish, true);
  document.addEventListener('pointercancel', finish, true);
  document.addEventListener('mouseup', finish, true);
  document.addEventListener('pointermove', track, true);
  document.addEventListener('mousemove', track, true);
  return {
    dispose() {
      document.removeEventListener('pointerup', finish, true);
      document.removeEventListener('pointercancel', finish, true);
      document.removeEventListener('mouseup', finish, true);
      document.removeEventListener('pointermove', track, true);
      document.removeEventListener('mousemove', track, true);
    },
  };
}

function dockviewPaneChromeDragExcluded(target) {
  return Boolean(target?.closest?.('.dv-tab, .dockview-pane-tab, [data-pane-drag], button, input, textarea, select, a'));
}

function dockviewBindTabContainerContextMenu(tabsContainer, group) {
  if (!tabsContainer || tabsContainer.__yolomuxEmptySpaceContextMenuBound) return;
  tabsContainer.__yolomuxEmptySpaceContextMenuBound = true;
  tabsContainer.addEventListener('contextmenu', event => {
    // Tab context menus retain their own target and inline-rename behavior. This handler owns only
    // the blank portion of a pane's Dockview tab strip, where the browser menu has no app meaning.
    if (event.target.closest('.dv-tab, .dockview-pane-tab')) return;
    const activeItem = group.querySelector('.dv-tab.dv-active-tab .dockview-pane-tab')?.dataset?.paneTab
      || activeItemForSide(dockviewSlotForGroupElement(group));
    if (!activeItem || !isLayoutItem(activeItem)) return;
    event.preventDefault();
    event.stopPropagation();
    showTabContextMenu(activeItem, event.clientX, event.clientY);
  });
}

function dockviewSyncHeaderBackgroundDragSources() {
  if (!dockviewLayoutActive()) return;
  document.querySelectorAll('.dv-groupview').forEach(group => {
    const header = group.querySelector('.dv-tabs-and-actions-container');
    const tabsContainer = header?.querySelector('.dv-tabs-container');
    const infoBar = group.querySelector('.dockview-panel-content > .panel > .pane-info-bar, .dockview-panel-content > .panel > .panel-detail-row');
    const editorToolbar = group.querySelector('.dockview-panel-content > .file-editor-panel > .file-editor-toolbar');
    const slot = dockviewSlotForGroupElement(group);
    const draggable = Boolean(slot && !slotIsFileExplorerPane(slot) && activeItemForSide(slot));
    const syncDragSource = element => {
      if (!element) return;
      element.dataset.paneDragSlot = draggable ? slot : '';
      element.classList.toggle('pane-drag-source', draggable);
      if (element.__yolomuxPaneDragBound) return;
      element.__yolomuxPaneDragBound = true;
      const begin = event => {
        if (dockviewPaneChromeDragExcluded(event.target)) return;
        const sourceSlot = element.dataset.paneDragSlot || dockviewSlotForGroupElement(group);
        dockviewBeginPanePointerDrag(event, sourceSlot);
      };
      element.addEventListener('pointerdown', begin);
      element.addEventListener('mousedown', begin);
    };
    syncDragSource(header);
    syncDragSource(infoBar);
    syncDragSource(editorToolbar);
    dockviewBindTabContainerContextMenu(tabsContainer, group);
  });
}

function dockviewSyncHeaderActionReservations() {
  if (!dockviewLayoutActive()) return;
  document.querySelectorAll('.dv-groupview').forEach(group => {
    const header = group.querySelector('.dv-tabs-and-actions-container');
    if (!header) return;
    const tabsContainer = header.querySelector('.dv-tabs-container');
    if (!tabsContainer) return;
    tabsContainer.querySelectorAll(':scope > .dockview-tab-first-row-reservation').forEach(node => node.remove());
    const actions = group.querySelector('.dockview-pane-header-actions:not([hidden])');
    const width = actions ? Math.ceil(appSpaceRect(actions).width || actions.offsetWidth || 0) : 0;
    const reservedWidth = width > 0 ? width + 8 : 0;
    // The reservation is a child of the tab container, which may be wider than Dockview's header
    // content box when actions are absolutely positioned. Measure that shared flex surface.
    const headerWidth = Math.floor(appSpaceRect(tabsContainer).width || tabsContainer.clientWidth || 0);
    const slot = dockviewSlotForGroupElement(group);
    const intrinsicSidePaneTabs = Boolean(slot && slotIsSidePane(slot));
    const rootStyle = getComputedStyle(document.documentElement);
    const preferredTabWidth = Number.parseFloat(rootStyle.getPropertyValue('--pane-tab-width')) || 180;
    const minTabWidth = Number.parseFloat(rootStyle.getPropertyValue('--dockview-tab-min-inline-size')) || 64;
    const availableWidth = headerWidth > reservedWidth ? headerWidth - reservedWidth : headerWidth;
    // Keep the first row clear of its absolutely positioned actions, while allowing later rows to
    // use the whole header. The normal tab width is retained without actions. With actions, fit
    // the next whole-tab count across the full header so later rows do not inherit a dead gutter.
    const sampleTab = tabsContainer.querySelector('.dv-tab');
    const sampleTabStyle = sampleTab ? getComputedStyle(sampleTab) : null;
    const tabMargin = sampleTabStyle
      ? Number.parseFloat(sampleTabStyle.marginInlineStart || '0') + Number.parseFloat(sampleTabStyle.marginInlineEnd || '0')
      : 0;
    const tabs = Array.from(tabsContainer.querySelectorAll(':scope > .dv-tab'));
    const preferredTabFootprint = preferredTabWidth + tabMargin;
    const firstRowPreferredCount = availableWidth > 0 ? Math.max(1, Math.floor(availableWidth / preferredTabFootprint)) : 1;
    const tabsNeedWrap = tabs.length > firstRowPreferredCount;
    const fullRowTabCount = headerWidth > 0 ? Math.max(1, Math.ceil(headerWidth / preferredTabWidth)) : 1;
    const laterRowTabWidth = headerWidth > 0 ? Math.floor((headerWidth - tabMargin * fullRowTabCount) / fullRowTabCount) : preferredTabWidth;
    const tabWidth = reservedWidth > 0 && tabsNeedWrap
      ? Math.max(minTabWidth, Math.min(preferredTabWidth, laterRowTabWidth))
      : (availableWidth > 0 ? Math.min(Math.max(minTabWidth, preferredTabWidth), Math.max(minTabWidth, availableWidth)) : Math.max(minTabWidth, preferredTabWidth));
    header.style.setProperty('--dockview-header-actions-reserved-inline-size', reservedWidth > 0 ? `${reservedWidth}px` : '0px');
    // The narrow triplet home uses content-width tabs. Its shared action gutter is ordinary end
    // padding, so all three tabs stay on one row and shrink together instead of inheriting the
    // preferred-width reservation algorithm used by normal multi-row pane tabs.
    if (intrinsicSidePaneTabs) {
      header.style.removeProperty('--dockview-tab-inline-size');
      return;
    }
    header.style.setProperty('--dockview-tab-inline-size', `${tabWidth}px`);
    if (!reservedWidth || !headerWidth) return;
    const firstRowWidth = Math.max(0, headerWidth - reservedWidth);
    let usedWidth = 0;
    let usedActualWidth = 0;
    let firstExcludedTab = null;
    for (const tab of tabs) {
      const style = getComputedStyle(tab);
      const measuredTabWidth = Math.ceil(appSpaceRect(tab).width || tab.offsetWidth || 0)
        + Number.parseFloat(style.marginInlineStart || '0')
        + Number.parseFloat(style.marginInlineEnd || '0');
      // The first row keeps the preferred-width capacity even when later rows shrink slightly to
      // reclaim the action gutter. That gives the rows below enough tabs to use the full header.
      const firstRowTabWidth = reservedWidth > 0
        ? preferredTabWidth + Number.parseFloat(style.marginInlineStart || '0') + Number.parseFloat(style.marginInlineEnd || '0')
        : measuredTabWidth;
      if (usedWidth > 0 && usedWidth + firstRowTabWidth > firstRowWidth) {
        firstExcludedTab = tab;
        break;
      }
      usedWidth += firstRowTabWidth;
      usedActualWidth += measuredTabWidth;
    }
    if (!tabs.length || !usedActualWidth) return;
    const reservation = document.createElement('span');
    reservation.className = 'dockview-tab-first-row-reservation';
    reservation.setAttribute('aria-hidden', 'true');
    reservation.style.setProperty('--dockview-first-row-reservation-inline-size', `${Math.max(0, Math.floor(headerWidth - usedActualWidth))}px`);
    tabsContainer.insertBefore(reservation, firstExcludedTab);
  });
}

function dockviewEnsureHost() {
  if (dockviewLayoutState.host?.isConnected) return dockviewLayoutState.host;
  movePanelsToPool();
  grid.innerHTML = '';
  const host = document.createElement('section');
  host.id = dockviewRootId;
  host.className = 'yolomux-dockview';
  grid.appendChild(host);
  dockviewLayoutState.host = host;
  return host;
}

function dockviewInit() {
  if (dockviewLayoutState.api || !dockviewLayoutEnabled()) return dockviewLayoutState.api;
  const core = dockviewCore();
  const host = dockviewEnsureHost();
  const api = core.createDockview(host, {
    className: 'yolomux-dockview-core',
    createComponent: () => createDockviewPanelRenderer(),
    createRightHeaderActionComponent: () => createDockviewHeaderActionsRenderer(),
    createTabComponent: () => createDockviewTabRenderer(),
    defaultRenderer: dockviewPanelRenderer,
    disableFloatingGroups: true,
    dndStrategy: 'pointer',
    noPanelsOverlay: 'emptyGroup',
    scrollbars: 'native',
    singleTabMode: 'default',
    tabGroupAccent: 'off',
    theme: dockviewThemeForApp(),
    getTabContextMenuItems: () => [],
    getTabGroupChipContextMenuItems: () => [],
  });
  dockviewLayoutState.api = api;
  dockviewLayoutToHost(api, host);
  dockviewLayoutState.disposables = [
    dockviewInstallRootBoundaryDropFallback(),
    dockviewInstallFileDropBridge(host),
    dockviewInstallHostResizeObserver(host, api),
    dockviewInstallTabPointerReorderFallback(),
    api.onDidLayoutChange(() => queueDockviewLayoutAdoption()),
    api.onDidRemoveGroup?.(group => dockviewHandleRemovedGroup(group)),
    api.onDidActivePanelChange(panel => {
      if (dockviewLayoutState.applyingFromLayout) return;
      const item = panel?.id || '';
      if (!item) return;
      dockviewCommitPanelActivation(item);
    }),
    api.onWillShowOverlay(event => dockviewTrackRootBoundaryOverlay(event)),
    api.onWillDrop(event => {
      // Tab drops are handled here (or committed by dockview itself); stamp the gesture so the pinned
      // pointer-reorder FALLBACK stands down instead of double-applying (see dockviewFinishTabPointerDrag).
      if (event?.kind === 'tab') dockviewLayoutState.tabDropHandledAt = Date.now();
      dockviewSetInvalidTabDropPreview(false);
      const sideIntent = dockviewSideVerticalDropIntent(event);
      if (sideIntent) {
        dockviewLayoutState.pendingRootBoundaryDrop = null;
        dockviewClearRootBoundaryPreview();
        event.preventDefault();
        queueMicrotask(() => {
          void dockviewCommitSideVerticalDrop(sideIntent);
        });
        return;
      }
      const rootIntent = dockviewRootBoundaryDropIntent(event);
      if (dockviewPinnedTabRootBoundaryViolation(rootIntent)) {
        dockviewLayoutState.pendingRootBoundaryDrop = null;
        dockviewClearRootBoundaryPreview();
        event.preventDefault();
        return;
      }
      if (rootIntent) {
        dockviewLayoutState.pendingRootBoundaryDrop = null;
        dockviewClearRootBoundaryPreview();
        event.preventDefault();
        queueMicrotask(() => {
          void splitSessionAtLayoutBoundary(rootIntent.item, rootIntent.zone, rootIntent.sourceSlot);
        });
        return;
      }
      const edgeReorder = dockviewTabEdgeReorderIntent(event);
      if (edgeReorder) {
        dockviewLayoutState.pendingRootBoundaryDrop = null;
        dockviewClearRootBoundaryPreview();
        event.preventDefault();
        queueMicrotask(() => {
          void moveSessionToSlot(edgeReorder.item, edgeReorder.targetSlot, edgeReorder.sourceSlot, edgeReorder.insertIndex);
        });
        return;
      }
      if (dockviewTabDropWouldNoop(event)) {
        dockviewLayoutState.pendingRootBoundaryDrop = null;
        dockviewClearRootBoundaryPreview();
        event.preventDefault();
        return;
      }
      if (dockviewTabDropViolatesPinnedPartition(event)) {
        dockviewLayoutState.pendingRootBoundaryDrop = null;
        dockviewClearRootBoundaryPreview();
        event.preventDefault();
        return;
      }
      const tabCapacityRefusal = dockviewTabCapacityRefusalStatus(event);
      if (tabCapacityRefusal) {
        dockviewLayoutState.pendingRootBoundaryDrop = null;
        dockviewClearRootBoundaryPreview();
        event.preventDefault();
        showLayoutStatus(tabCapacityRefusal, 'danger');
        return;
      }
      const tabInsertion = dockviewTabInsertionInfo(event);
      // A tab-header drop is `kind: tab`, not `kind: content`. Dockview otherwise owns that move
      // internally and its later adoption path rejects the protected home group. A triplet item
      // is explicitly allowed to center-stack there, so commit it through the common layout move.
      if (tabInsertion && slotIsSidePane(tabInsertion.targetSlot)
        && paneRoleAllowsItemTransfer(tabInsertion.item, tabInsertion.sourceSlot, tabInsertion.targetSlot)) {
        dockviewLayoutState.pendingRootBoundaryDrop = null;
        dockviewClearRootBoundaryPreview();
        event.preventDefault();
        queueMicrotask(() => {
          void moveSessionToSlot(tabInsertion.item, tabInsertion.targetSlot, tabInsertion.sourceSlot, tabInsertion.adjustedIndex);
        });
        return;
      }
      const stripEndDrop = dockviewTabStripEndDropIntent(event);
      if (stripEndDrop) {
        dockviewLayoutState.pendingRootBoundaryDrop = null;
        dockviewClearRootBoundaryPreview();
        event.preventDefault();
        queueMicrotask(() => {
          void moveSessionToSlot(stripEndDrop.item, stripEndDrop.targetSlot, stripEndDrop.sourceSlot, stripEndDrop.insertIndex);
        });
        return;
      }
      const paneInfo = dockviewPaneContentDropInfo(event);
      const capacityRefusal = paneInfo?.intent?.zone === 'middle'
        ? dropIntentCapacityRefusalStatus(paneInfo.item, paneInfo.intent, paneInfo.intent.sourceSlot)
        : '';
      if (capacityRefusal) {
        dockviewLayoutState.pendingRootBoundaryDrop = null;
        dockviewClearRootBoundaryPreview();
        event.preventDefault();
        showLayoutStatus(capacityRefusal, 'danger');
        return;
      }
      // Dockview's default center-drop mutates its private group first and relies on a later
      // adoption pass. That lost center drops into the protected triplet home column. Apply every
      // allowed center move through the same layout transaction as the rest of the app instead.
      if (paneInfo && paneInfo.intent.zone === 'middle' && dockviewPaneContentDropAllowed(paneInfo)) {
        dockviewLayoutState.pendingRootBoundaryDrop = null;
        dockviewClearRootBoundaryPreview();
        event.preventDefault();
        queueMicrotask(() => {
          void moveSessionToSlot(paneInfo.item, paneInfo.intent.targetSlot, paneInfo.intent.sourceSlot, paneTabs(paneInfo.intent.targetSlot).length);
        });
        return;
      }
      const paneIntent = dockviewPaneContentDropIntent(event);
      if (paneIntent) {
        dockviewLayoutState.pendingRootBoundaryDrop = null;
        dockviewClearRootBoundaryPreview();
        event.preventDefault();
        dockviewLayoutState.tabDropHandledAt = Date.now();
        queueMicrotask(() => {
          void splitSessionAtSlot(paneIntent.item, paneIntent.targetSlot, paneIntent.zone, paneIntent.sourceSlot);
        });
        return;
      }
      if (dockviewShouldSuppressPaneContentDrop(event) || dockviewShouldSuppressReservedRootBoundary(event)) {
        dockviewLayoutState.pendingRootBoundaryDrop = null;
        dockviewClearRootBoundaryPreview();
        event.preventDefault();
        return;
      }
      dockviewLayoutState.pendingRootBoundaryDrop = null;
      dockviewClearRootBoundaryPreview();
      const targetSlot = dockviewSlotForGroupId(event.group?.id || '');
      if (event.position === 'center' && targetSlot) {
        const item = resolveLayoutItem(event.getData?.()?.panelId || '');
        if (!paneRoleAllowsItemTransfer(item, slotForItem(item), targetSlot)) event.preventDefault();
      }
    }),
  ];
  return api;
}

function dockviewDispose() {
  for (const disposable of dockviewLayoutState.disposables) disposable?.dispose?.();
  dockviewLayoutState.disposables = [];
  dockviewLayoutState.api?.dispose?.();
  dockviewLayoutState.api = null;
  dockviewLayoutState.host = null;
  if (dockviewLayoutState.hostLayoutFrame) cancelAnimationFrame(dockviewLayoutState.hostLayoutFrame);
  if (dockviewLayoutState.tabActivationPerf?.frame) cancelAnimationFrame(dockviewLayoutState.tabActivationPerf.frame);
  dockviewLayoutState.tabActivationPerf = null;
  dockviewLayoutState.hostLayoutFrame = 0;
  dockviewLayoutState.lastHostLayoutSignature = '';
  dockviewLayoutState.lastAppliedLayoutSignature = '';
  dockviewLayoutState.lastAppliedActiveOnlySignature = '';
  dockviewLayoutState.groupSlots.clear();
}

function renderPanelsDockview(previousActive = [], options = {}) {
  if (!dockviewLayoutEnabled()) return false;
  const api = dockviewInit();
  if (!api) return false;
  const activePaneCount = layoutSlotKeys().filter(side => activeItemForSide(side) || paneIsPlaceholder(side)).length;
  grid.className = `grid dockview-grid ${activePaneCount === 1 ? 'full' : ''} ${activePaneCount === 0 ? 'empty' : ''}`.trim();
  dockviewEnsureHost();
  api.updateOptions?.({theme: dockviewThemeForApp()});
  dockviewLayoutToHost(api);
  const signature = layoutSlotsSignature(layoutSlots);
  let activeOnlyChange = false;
  if (!dockviewLayoutState.adoptingFromDockview && dockviewLayoutState.lastAppliedLayoutSignature !== signature) {
    const activeOnlySignature = dockviewLayoutActiveOnlySignature(layoutSlots);
    if (dockviewLayoutState.lastAppliedActiveOnlySignature !== activeOnlySignature || !dockviewActivateLayoutTabs(layoutSlots)) {
      dockviewLoadLayout(layoutSlots);
    } else {
      dockviewLayoutState.lastAppliedLayoutSignature = signature;
      activeOnlyChange = true;
    }
  }
  dockviewRefreshTabs();
  dockviewSyncMountedPanels({renderAttached: !activeOnlyChange});
  finishPanelLayoutRender(previousActive, options);
  return true;
}

function syncActivePanelsDockview(previousActive = []) {
  renderPanelsDockview(previousActive, {prune: false});
}

function dockviewLoadLayout(slots = layoutSlots) {
  const api = dockviewLayoutState.api;
  if (!api) return;
  const items = paneItems(slots);
  dockviewLayoutState.applyingFromLayout = true;
  try {
    if (!items.length) {
      api.clear();
      dockviewLayoutState.lastAppliedLayoutSignature = layoutSlotsSignature(slots);
      dockviewLayoutState.lastAppliedActiveOnlySignature = dockviewLayoutActiveOnlySignature(slots);
      return;
    }
    api.fromJSON(dockviewJsonFromLayoutSlots(slots), {reuseExistingPanels: true});
    dockviewLayoutState.lastAppliedLayoutSignature = layoutSlotsSignature(slots);
    dockviewLayoutState.lastAppliedActiveOnlySignature = dockviewLayoutActiveOnlySignature(slots);
    dockviewSyncMountedPanels();
  } finally {
    dockviewLayoutState.applyingFromLayout = false;
  }
}

// An active-tab change does not alter the Dockview topology or its mounted panel contents. Calling
// fromJSON in that case rebuilds the whole layout and is the visible tab-switch delay; activate the
// existing panel in each group instead, which is Dockview's native pre-rendered-panel path.
function dockviewActivateLayoutTabs(slots = layoutSlots) {
  const api = dockviewLayoutState.api;
  if (!api || !dockviewLayoutActive()) return false;
  const activeItems = layoutSlotKeys(slots)
    .map(slot => activeItemForSide(slot, slots))
    .filter(Boolean);
  if (!activeItems.length && paneItems(slots).length) return false;
  const panels = activeItems.map(item => api.getPanel?.(item));
  if (panels.some(panel => typeof panel?.api?.setActive !== 'function')) return false;
  for (const panel of panels) panel.api.setActive();
  return true;
}

function dockviewJsonFromLayoutSlots(slots = layoutSlots) {
  const tree = slots?.[layoutTreeKey] || legacyLayoutTree(slots);
  const rootOrientation = dockviewOrientationForSplit(tree?.split === 'column' ? 'column' : 'row');
  const panelItems = paneItems(slots);
  const size = dockviewHostLayoutSize(dockviewLayoutState.host || grid);
  const viewport = appViewport();
  const sidePaneMaximumWidth = Math.max(
    minSplitPaneWidthPx(),
    Math.floor((size.width || viewport.width || 0) * sidePaneRoleDefinition.maxViewportFraction),
  );
  const panels = {};
  for (const item of panelItems) {
    const slot = slotForItem(item, slots);
    const sidePane = slotIsSidePane(slot, slots);
    panels[item] = {
      id: item,
      contentComponent: dockviewContentComponentName,
      tabComponent: dockviewTabComponentName,
      title: itemLabel(item),
      renderer: dockviewPanelRenderer,
      params: {item},
      minimumWidth: sidePane ? minWidthForSidePaneItem(item) : minWidthForLayoutItem(item),
      ...(sidePane ? {maximumWidth: sidePaneMaximumWidth} : {}),
      minimumHeight: minSplitPaneHeightPx(),
    };
  }
  for (const slot of layoutSlotKeys(slots)) {
    if (!paneIsPlaceholder(slot, slots)) continue;
    const item = dockviewEmptyPaneItem(slot);
    panels[item] = {
      id: item,
      contentComponent: dockviewContentComponentName,
      tabComponent: dockviewTabComponentName,
      title: t('pane.empty'),
      renderer: dockviewPanelRenderer,
      params: {item},
      minimumWidth: minSplitPaneWidthPx(),
      minimumHeight: minSplitPaneHeightPx(),
    };
  }
  return {
    grid: {
      root: dockviewSerializedNodeFromLayout(tree, slots, rootOrientation),
      height: Math.max(DOCKVIEW_MIN_LAYOUT_HEIGHT, Math.round(size.height || viewport.height || 0)),
      width: Math.max(DOCKVIEW_MIN_LAYOUT_WIDTH, Math.round(size.width || viewport.width || 0)),
      orientation: rootOrientation,
    },
    panels,
    activeGroup: slotForItem(focusedPanelItem, slots) || layoutSlotKeys(slots)[0],
  };
}

function dockviewSerializedNodeFromLayout(node, slots, orientation, weight = SERIALIZED_WEIGHT_BASE) {
  if (!node || node.slot) {
    return {
      type: 'branch',
      data: [dockviewSerializedLeaf(node?.slot || layoutSlotKeys(slots)[0] || 'left', slots, weight)],
      size: Math.max(1, Math.round(weight)),
    };
  }
  return dockviewSerializedNodeContentFromLayout(node, slots, orientation, weight);
}

function dockviewSerializedNodeContentFromLayout(node, slots, orientation, weight = SERIALIZED_WEIGHT_BASE) {
  if (!node || node.slot) return dockviewSerializedLeaf(node?.slot || layoutSlotKeys(slots)[0] || 'left', slots, weight);
  const direction = dockviewSplitForOrientation(orientation);
  const parts = flattenLayoutNodeForDirection(node, slots, direction);
  if (parts.length === 1) {
    const part = parts[0];
    return dockviewSerializedNodeContentFromLayout(part.node, slots, dockviewOppositeOrientation(orientation), weight);
  }
  const totalWeight = parts.reduce((sum, part) => sum + part.weight, 0) || 1;
  return {
    type: 'branch',
    data: parts.map(part => dockviewSerializedNodeContentFromLayout(
      part.node,
      slots,
      dockviewOppositeOrientation(orientation),
      Math.max(1, Math.round((part.weight / totalWeight) * weight)),
    )),
    size: Math.max(1, Math.round(weight)),
  };
}

function flattenLayoutNodeForDirection(node, slots, direction, weight = 1) {
  if (!node || node.slot || node.split !== direction) return [{node, weight}];
  const pct = splitPercent(node.pct) / 100;
  const children = node.children || [];
  return [
    ...flattenLayoutNodeForDirection(children[0], slots, direction, weight * pct),
    ...flattenLayoutNodeForDirection(children[1], slots, direction, weight * (1 - pct)),
  ];
}

function dockviewSerializedLeaf(slot, slots, weight = SERIALIZED_WEIGHT_BASE) {
  const tabs = paneTabs(slot, slots);
  const groupId = slot || nextLayoutSlot(slots);
  const placeholder = paneIsPlaceholder(slot, slots);
  dockviewLayoutState.groupSlots.set(groupId, groupId);
  return {
    type: 'leaf',
    data: {
      id: groupId,
      // Dockview does not visually retain a zero-view group. Its synthetic, headerless panel
      // gives our existing empty-pane renderer a real group to occupy while keeping app state
      // explicitly tab-free.
      views: placeholder ? [dockviewEmptyPaneItem(groupId)] : tabs.slice(),
      activeView: placeholder ? dockviewEmptyPaneItem(groupId) : (activeItemForSide(slot, slots) || tabs[0]),
      // The Dockview group header is the only tab strip when an inner panel head is hidden.
      // A singleton Finder used to suppress it as a legacy reserved-pane optimization, leaving
      // no visible route to the other independent triplet tabs after they are added.
      hideHeader: placeholder,
    },
    size: Math.max(1, Math.round(weight)),
    visible: true,
  };
}

function queueDockviewLayoutAdoption() {
  if (!dockviewLayoutAdoptionAllowed()) return;
  if (dockviewLayoutState.applyingFromLayout || dockviewLayoutState.adoptingFromDockview) return;
  if (dockviewLayoutState.syncQueued) return;
  dockviewLayoutState.syncQueued = true;
  queueMicrotask(adoptDockviewLayout);
}

function adoptDockviewLayout() {
  dockviewLayoutState.syncQueued = false;
  const api = dockviewLayoutState.api;
  if (!api || dockviewLayoutState.applyingFromLayout) return;
  if (!dockviewLayoutAdoptionAllowed()) return;
  if (!dockviewHostCanAdoptLayout()) return;
  let next = layoutSlotsFromDockviewJson(api.toJSON());
  const missingSurfaces = layoutFileSurfaceItems().filter(item => itemInLayout(item, layoutSlots) && !itemInLayout(item, next));
  if (missingSurfaces.length) {
    next = layoutWithSidePaneItems(next, missingSurfaces, {side: paneSideLeft});
    dockviewLayoutState.reloadAfterAdoption = true;
  }
  if (!layoutHasRestorableContent(next)) return;
  const nextSignature = layoutSlotsSignature(next);
  if (nextSignature === layoutSlotsSignature(layoutSlots)) {
    dockviewRefreshTabs();
    dockviewSyncMountedPanels();
    return;
  }
  dockviewLayoutState.lastAppliedLayoutSignature = nextSignature;
  dockviewLayoutState.adoptingFromDockview = true;
  try {
    applyLayoutSlots(next, {prune: false, preservePlaceholderSlots: true});
    if (dockviewLayoutState.reloadAfterAdoption) {
      dockviewLayoutState.reloadAfterAdoption = false;
      dockviewLoadLayout(layoutSlots);
    }
  } finally {
    dockviewLayoutState.reloadAfterAdoption = false;
    dockviewLayoutState.adoptingFromDockview = false;
  }
}

function layoutSlotsFromDockviewJson(data, previous = layoutSlots) {
  const next = emptyLayoutSlots();
  const usedSlots = new Set();
  const parse = (node, orientation) => {
    if (!node) return null;
    if (node.type === 'leaf') {
      const group = node.data || {};
      const slot = dockviewSlotForGroupId(group.id, usedSlots);
      usedSlots.add(slot);
      const views = Array.isArray(group.views) ? group.views : [];
      let tabs = views
        .filter(view => dockviewEmptyPaneSlot(view) === null)
        .map(resolveLayoutItem)
        .filter(item => isLayoutItem(item));
      let activeView = resolveLayoutItem(group.activeView);
      const previousTabs = paneTabs(slot, previous);
      if (!tabs.length && previousTabs.some(layoutIsFileSurfaceItem)) {
        tabs = previousTabs.slice();
        activeView = activeItemForSide(slot, previous) || tabs[0];
        dockviewLayoutState.reloadAfterAdoption = true;
      }
      // Dockview keeps an explicit zero-tab group after a directional Move so the user has the
      // empty half they asked for. It is not stale layout: retain it as our placeholder pane
      // instead of dropping the leaf while translating Dockview back into app state.
      const previousRole = paneRoleForSlot(slot, previous);
      next[slot] = tabs.length ? paneStateWithTabs(tabs, activeView, previousRole) : emptyPlaceholderPaneState(previousRole);
      return leafNode(slot);
    }
    const children = (Array.isArray(node.data) ? node.data : [])
      .map(child => ({
        node: parse(child, dockviewOppositeOrientation(orientation)),
        size: Number(child?.size) || 1,
      }))
      .filter(child => child.node);
    return dockviewLayoutTreeFromChildren(children, dockviewSplitForOrientation(orientation));
  };
  next[layoutTreeKey] = parse(data?.grid?.root, data?.grid?.orientation || 'HORIZONTAL');
  const missingPlaceholder = layoutSlotKeys(previous).find(slot => (
    paneIsPlaceholder(slot, previous)
    && !layoutSlotKeys(next).includes(slot)
  ));
  if (missingPlaceholder) {
    // fromJSON can emit an intermediate layout event before its synthetic empty-pane group is
    // mounted. That event is not a user deletion; adopting it would immediately erase the visible
    // disposable peer created by directional Move.
    dockviewLayoutState.reloadAfterAdoption = true;
    return cloneLayoutSlots(previous);
  }
  if (dockviewLayoutHasRoleTransferViolation(next, previous)) {
    dockviewLayoutState.reloadAfterAdoption = true;
    return cloneLayoutSlots(previous);
  }
  preserveDockviewSidePaneSplit(next, previous);
  return normalizeLayoutSlots(
    compactLayoutSlots(next, {preservePlaceholderSlots: true}),
    {preservePlaceholderSlots: true},
  );
}

function dockviewLayoutHasRoleTransferViolation(next, previous = layoutSlots) {
  return paneItems(next).some(item => {
    const previousSlot = slotForItem(item, previous);
    const nextSlot = slotForItem(item, next);
    if (!previousSlot || !nextSlot || previousSlot === nextSlot) return false;
    return !paneRoleAllowsItemTransfer(item, previousSlot, nextSlot, next, {
      sourceRole: paneRoleForSlot(previousSlot, previous),
      targetRole: paneRoleForSlot(nextSlot, next),
    });
  });
}

function dockviewGroupId(group) {
  return String(group?.id || group?.api?.id || group?.model?.id || group?.data?.id || '');
}

function dockviewRemovedGroupItems(group) {
  const raw = [
    ...(Array.isArray(group?.panels) ? group.panels : []),
    ...(Array.isArray(group?.api?.panels) ? group.api.panels : []),
    ...(Array.isArray(group?.model?.panels) ? group.model.panels : []),
  ];
  return raw
    .map(panel => resolveLayoutItem(panel?.id || panel?.api?.id || panel?.data?.id || panel))
    .filter(item => isLayoutItem(item));
}

function dockviewHandleRemovedGroup(group) {
  const items = dockviewRemovedGroupItems(group);
  const groupId = dockviewGroupId(group);
  const slot = dockviewLayoutState.groupSlots.get(groupId) || layoutSlotName(groupId);
  if (!items.some(layoutIsFileSurfaceItem) && !(slot && paneTabs(slot).some(layoutIsFileSurfaceItem))) return;
  dockviewLayoutState.reloadAfterAdoption = true;
  queueDockviewLayoutAdoption();
}

function preserveDockviewSidePaneSplit(next, previous = layoutSlots) {
  const previousRoot = previous?.[layoutTreeKey];
  const nextRoot = next?.[layoutTreeKey];
  const previousDocked = layoutSidePaneRootSplit(previousRoot, previous);
  const nextDocked = layoutSidePaneRootSplit(nextRoot, next);
  if (!previousDocked || !nextDocked || !nextRoot) return;
  if (dockviewLayoutContentSignature(next) === dockviewLayoutContentSignature(previous)) {
    preserveDockviewContentSplitPercentagesAfterDockResize(nextRoot, previousRoot, nextDocked, previousDocked);
    return;
  }
  const sidePct = previousDocked.sideIndex === 0 ? previousDocked.pct : 100 - previousDocked.pct;
  const preservedPct = nextDocked.sideIndex === 0 ? sidePct : 100 - sidePct;
  if (Math.abs((Number(nextRoot.pct) || 0) - preservedPct) > SPLIT_PCT_EPSILON) {
    nextRoot.pct = preservedPct;
    dockviewLayoutState.reloadAfterAdoption = true;
  }
}

function preserveDockviewContentSplitPercentagesAfterDockResize(nextRoot, previousRoot, nextDocked, previousDocked) {
  const previousSidePct = previousDocked.sideIndex === 0 ? previousDocked.pct : 100 - previousDocked.pct;
  const nextSidePct = nextDocked.sideIndex === 0 ? nextDocked.pct : 100 - nextDocked.pct;
  if (Math.abs(nextSidePct - previousSidePct) <= SPLIT_PCT_EPSILON) return;
  const nextContent = nextRoot.children?.[nextDocked.contentIndex];
  const previousContent = previousRoot.children?.[previousDocked.contentIndex];
  if (copyLayoutSplitPercentagesByShape(nextContent, previousContent)) {
    dockviewLayoutState.reloadAfterAdoption = true;
  }
}

function copyLayoutSplitPercentagesByShape(target, source) {
  if (!target || !source || target.slot || source.slot || target.split !== source.split) return false;
  let changed = false;
  const sourcePct = splitPercent(source.pct);
  if (Math.abs(splitPercent(target.pct) - sourcePct) > SPLIT_PCT_EPSILON) {
    target.pct = sourcePct;
    changed = true;
  }
  const targetChildren = target.children || [];
  const sourceChildren = source.children || [];
  for (let index = 0; index < Math.min(targetChildren.length, sourceChildren.length); index += 1) {
    changed = copyLayoutSplitPercentagesByShape(targetChildren[index], sourceChildren[index]) || changed;
  }
  return changed;
}

function dockviewLayoutContentSignature(slots = layoutSlots) {
  const nodeSignature = node => {
    if (!node) return '';
    if (node.slot) return `S:${node.slot}`;
    return `${node.split || ''}:[${(node.children || []).map(nodeSignature).join(',')}]`;
  };
  const paneSignature = layoutSlotKeys(slots)
    .slice()
    .sort()
    .map(slot => `${slot}:${paneTabs(slot, slots).slice().sort().join(',')}`)
    .join('|');
  return `${nodeSignature(slots?.[layoutTreeKey])}::${paneSignature}`;
}

// Tab order is observable in Dockview (including pinning); only the active item is safe to change
// without fromJSON. Keep this distinct from the unordered content signature used for resize math.
function dockviewLayoutActiveOnlySignature(slots = layoutSlots) {
  const paneSignature = layoutSlotKeys(slots)
    .slice()
    .sort()
    .map(slot => `${slot}:${paneTabs(slot, slots).join(',')}`)
    .join('|');
  return `${layoutShapeSignature(slots)}::${paneSignature}`;
}

function dockviewLayoutTreeFromChildren(children, direction) {
  if (!children.length) return null;
  if (children.length === 1) return children[0].node;
  const [first, ...rest] = children;
  const restSize = rest.reduce((sum, child) => sum + child.size, 0);
  const total = first.size + restSize;
  const secondNode = dockviewLayoutTreeFromChildren(rest, direction);
  return splitNode(direction, first.node, secondNode, total ? (first.size / total) * 100 : defaultSplitPercent);
}

function dockviewSlotForGroupId(groupId, usedSlots = new Set()) {
  const text = String(groupId || '');
  const existing = dockviewLayoutState.groupSlots.get(text);
  if (existing && !usedSlots.has(existing)) return existing;
  if (layoutSlotName(text) && !usedSlots.has(text)) {
    dockviewLayoutState.groupSlots.set(text, text);
    return text;
  }
  let slot = nextLayoutSlot({...layoutSlots, ...Object.fromEntries(Array.from(usedSlots).map(key => [key, emptyPaneState()]))});
  while (usedSlots.has(slot)) slot = nextLayoutSlot({...layoutSlots, [slot]: emptyPaneState()});
  dockviewLayoutState.groupSlots.set(text || slot, slot);
  return slot;
}

function dockviewEnsureMountedTerminal(item, panel) {
  if (!isTmuxSession(item)) return;
  queueMicrotask(() => {
    if (!panel?.isConnected || !itemInLayout(item)) return;
    const slot = slotForItem(item);
    if (slot && activeItemForSide(slot) !== item) return;
    if (typeof ensureTerminalRunning === 'function') void ensureTerminalRunning(item);
    if (typeof scheduleFit === 'function') scheduleFit(item);
  });
}

function createDockviewPanelRenderer() {
  const element = document.createElement('div');
  element.className = 'dockview-panel-content';
  let item = '';
  let panel = null;
  const mount = params => {
    item = params?.params?.item || params?.api?.id || item;
    const emptySlot = dockviewEmptyPaneSlot(item);
    if (emptySlot) {
      panel = null;
      element.replaceChildren(renderEmptyPane(emptySlot));
      return;
    }
    if (!isLayoutItem(item)) return;
    panel = getOrCreatePanel(item);
    const slot = slotForItem(item) || dockviewSlotForGroupId(params?.api?.group?.id || '');
    updatePanelSlot(panel, item, slot);
    element.replaceChildren(panel);
    renderAttachedPanelContent(item);
    restorePaneViewState(item, panel);
    dockviewEnsureMountedTerminal(item, panel);
  };
  const pool = () => {
    if (!panel || panel.parentElement !== element) return;
    capturePaneViewState(item, panel);
    panel.classList.remove('active-pane');
    panel.dataset.slot = '';
    panelPool.appendChild(panel);
  };
  return {
    element,
    init: mount,
    update: event => mount({params: event?.params || {item}, api: {id: item}}),
    onShow: () => mount({params: {item}, api: {id: item}}),
    onHide: pool,
    dispose: pool,
    layout: () => {
      if (isTmuxSession(item)) {
        dockviewEnsureMountedTerminal(item, panel);
        scheduleFit(item);
      }
    },
  };
}

function dockviewHeaderActionsHtml(item, slot = slotForItem(item)) {
  if (!isLayoutItem(item)) return '';
  if (slotIsSidePane(slot)) {
    return paneFrameControlsGroupHtml(item, {
      slot,
      actions: false,
      details: false,
      popout: false,
      expand: false,
      close: false,
      minimize: true,
    });
  }
  const paneHandle = paneDragHandleHtml(item, slot);
  if (isTmuxSession(item)) return `${paneHandle}${panelControlsHtml(item)}`;
  if (isFileEditorItem(item)) {
    return `${paneHandle}${paneFrameControlsGroupHtml(item, {
      groupClass: 'file-editor-frame-controls',
      actions: false,
      popout: paneCanPopout(item),
      minimize: true,
      expand: true,
      close: true,
      closeClass: 'file-editor-panel-close',
      closeTitle: t('editor.closePane'),
      closeLabel: t('editor.closePane'),
    })}`;
  }
  if (isVirtualItem(item)) return `${paneHandle}${virtualPanelControlsHtml(item, {popout: paneCanPopout(item)})}`;
  return '';
}

function paneDragHandleHtml(item, slot = slotForItem(item)) {
  if (!slot || slotIsFileExplorerPane(slot)) return '';
  return `<button type="button" class="tab pane-drag-handle" data-pane-drag="${esc(slot)}" draggable="true" title="${esc(t('pane.drag'))}" aria-label="${esc(t('pane.drag'))}"></button>`;
}

function handleDockviewHeaderActionClick(event, fallbackItem = '') {
  const button = event.target?.closest?.('button');
  if (!button) return;
  const item = button.dataset.tab || button.dataset.windowSession || button.dataset.detailToggle
    || button.dataset.paneActions || button.dataset.paneMinimize || button.dataset.paneExpand
    || button.dataset.panePopout || button.dataset.paneClose || fallbackItem;
  if (!item) return;
  if (button.dataset.tab !== undefined) {
    event.preventDefault();
    event.stopPropagation();
    const currentName = button.dataset.tabName;
    const nextName = currentName !== 'terminal' && button.classList.contains(CLS.active) ? 'terminal' : currentName;
    activateTab(button.dataset.tab, nextName, {userInitiated: true});
    return;
  }
  if (button.dataset.windowDir !== undefined || button.dataset.windowIndex !== undefined) {
    event.preventDefault();
    event.stopPropagation();
    handleWindowStepButtonClick(event);
    return;
  }
  if (button.dataset.detailToggle !== undefined) {
    event.preventDefault();
    event.stopPropagation();
    const panel = document.getElementById(panelDomId(item));
    if (panel) setPanelDetailsCollapsed(panel, !panel.classList.contains('details-collapsed'));
    return;
  }
  if (button.dataset.paneActions !== undefined) {
    event.preventDefault();
    event.stopPropagation();
    const rect = button.getBoundingClientRect();
    showSessionContextMenu(button.dataset.paneActions || item, rect.left, rect.bottom + 4);
    return;
  }
  if (button.dataset.paneMinimize !== undefined) {
    event.preventDefault();
    event.stopPropagation();
    minimizePaneFromLayout(button.dataset.paneMinimize || item);
    return;
  }
  if (button.dataset.paneExpand !== undefined) {
    event.preventDefault();
    event.stopPropagation();
    expandPaneFromLayout(button.dataset.paneExpand || item);
    return;
  }
  if (button.dataset.panePopout !== undefined) {
    event.preventDefault();
    event.stopPropagation();
    openPanePopout(button.dataset.panePopout || item);
    return;
  }
  if (button.dataset.paneClose !== undefined) {
    event.preventDefault();
    event.stopPropagation();
    closePaneFrameItem(button.dataset.paneClose || item);
  }
}

function createDockviewHeaderActionsRenderer() {
  const element = document.createElement('div');
  element.className = 'dockview-pane-header-actions';
  let group = null;
  let activeItem = '';
  let disposables = [];
  const render = () => {
    activeItem = resolveLayoutItem(group?.activePanel?.id || '');
    const slot = dockviewSlotForGroupId(group?.id || '') || slotForItem(activeItem);
    const html = dockviewHeaderActionsHtml(activeItem, slot);
    element.hidden = !html;
    element.innerHTML = html;
    updatePanelWindowStepButtons(activeItem, transcriptMetadataState.payload.sessions?.[activeItem]);
    const panel = document.getElementById(panelDomId(activeItem));
    if (panel) {
      updatePaneExpandButton(panel, activeItem);
      syncPanelDetailsToggleState(panel);
    }
  };
  const dispose = () => {
    for (const disposable of disposables) disposable?.dispose?.();
    disposables = [];
  };
  element.addEventListener('dragstart', event => {
    const handle = event.target?.closest?.('[data-pane-drag]');
    if (!handle) return;
    event.stopPropagation();
    startPaneDrag(event, handle.dataset.paneDrag || slotForItem(activeItem));
  });
  element.addEventListener('dragend', endSessionDrag);
  element.addEventListener('click', event => handleDockviewHeaderActionClick(event, activeItem));
  element.__yolomuxDockviewRefresh = render;
  return {
    element,
    init: params => {
      dispose();
      group = params?.group || null;
      disposables = [
        params?.api?.onDidActivePanelChange?.(render),
        params?.api?.onDidActiveChange?.(render),
      ].filter(Boolean);
      render();
    },
    update: render,
    dispose,
  };
}

function captureDockviewPreviousPaneBeforeTabActivation(tabElement, targetItem) {
  const group = tabElement?.closest?.('.dv-groupview');
  const slot = group && typeof dockviewSlotForGroupElement === 'function' ? dockviewSlotForGroupElement(group) : null;
  const previous = slot ? activeItemForSide(slot) : focusedPanelItem;
  if (previous && previous !== targetItem) capturePaneViewStateForItemIfPresent(previous);
}

function createDockviewTabRenderer() {
  const element = document.createElement('div');
  element.className = 'pane-tab dockview-pane-tab';
  element.role = 'button';
  element.tabIndex = 0;
  let item = '';
  let api = null;
  let disposables = [];
  const render = () => {
    if (!item) return;
    if (dockviewEmptyPaneSlot(item)) {
      element.hidden = true;
      element.replaceChildren();
      return;
    }
    syncDockviewTabShell(element, item, api);
    if (paneTabShouldPreserve(element)) {
      syncPaneTabPinnedIcon(element, item);
      const popover = paneTabPopoverForAnchor(element);
      if (popover) positionPaneTabPopover(element, popover);
      if (isFileEditorItem(item)) refreshFileTabPopover(element, item);
      return;
    }
    cleanupDetachedPaneTabPopover(element);
    element.innerHTML = dockviewPaneTabHtml(item);
    if (isFileEditorItem(item)) {
      bindFilePopoverActions(element);
      bindPaneTabPopover(element, item);
    } else if (!isVirtualItem(item)) {
      bindPaneTabPopover(element, item);
    } else bindTabInteraction({anchor: element, item, sourceSlot: () => slotForItem(item)});
  };
  const dispose = () => {
    cleanupDetachedPaneTabPopover(element);
    for (const disposable of disposables) disposable?.dispose?.();
    disposables = [];
  };
  const commitExplicitTabInteraction = () => {
    dockviewCommitPanelActivation(item, {userInitiated: true});
  };
  element.__yolomuxDockviewRefresh = render;
  element.addEventListener('pointerdown', event => {
    dragTimingReset();
    dragTimingMark('pointerdown');
    if (event.target.closest('[data-pane-tab-close], [data-auto-session]')) event.stopPropagation();
    else {
      dockviewBeginTabActivationPerf(item);
      dockviewLayoutState.pendingUserPanelActivation = item;
      captureDockviewPreviousPaneBeforeTabActivation(element, item);
      dockviewBeginTabPointerDrag(event, item);
    }
  });
  element.addEventListener('mousedown', event => {
    if (event.target.closest('[data-pane-tab-close], [data-auto-session]')) return;
    captureDockviewPreviousPaneBeforeTabActivation(element, item);
    dockviewBeginTabPointerDrag(event, item);
  });
  element.addEventListener('click', async event => {
    const close = event.target.closest('[data-pane-tab-close]');
    if (close) {
      event.preventDefault();
      event.stopPropagation();
      event.stopImmediatePropagation?.();
      if (isFileEditorItem(item)) closeFileTab(fileItemPath(item), {item});
      else removeSessionFromLayout(item);
      return;
    }
    const autoTarget = event.target.closest('[data-auto-session]');
    if (autoTarget) {
      event.preventDefault();
      event.stopPropagation();
      const shouldRefocus = activeSessions.includes(item);
      await toggleAutoApprove(autoTarget.dataset.autoSession);
      if (shouldRefocus) focusPanel(item);
      return;
    }
    captureDockviewPreviousPaneBeforeTabActivation(element, item);
    commitExplicitTabInteraction();
    dockviewFinishTabActivationPerf(item);
  });
  element.addEventListener('keydown', event => {
    if (!['Enter', ' '].includes(event.key)) return;
    event.preventDefault();
    captureDockviewPreviousPaneBeforeTabActivation(element, item);
    commitExplicitTabInteraction();
    api?.setActive?.();
  });
  element.addEventListener('dblclick', event => {
    if (event.target.closest('[data-auto-session], [data-pane-tab-close]')) return;
    event.preventDefault();
    event.stopPropagation();
    beginPaneTabRename(element, item);
  });
  return {
    element,
    init: params => {
      dispose();
      item = params?.params?.item || params?.api?.id || '';
      api = params?.api || null;
      disposables = [
        api?.onDidActiveChange?.(render),
        api?.onDidTitleChange?.(render),
        api?.onDidParametersChange?.(parameters => {
          item = parameters?.item || item;
          render();
        }),
      ].filter(Boolean);
      render();
    },
    update: event => {
      if (event?.params?.item) item = event.params.item;
      render();
    },
    dispose,
  };
}

function syncDockviewTabShell(tab, item, api = null) {
  tab.dataset.paneTab = item;
  syncDockviewTabActiveClass(tab, api);
  tab.classList.toggle('tmux-pane-tab-token', isTmuxSession(item));
  tab.classList.toggle('file-missing', isFileEditorItem(item) && openFileIsMissing(fileItemPath(item)));
  tab.classList.toggle('pinned-tab', tabIsPinned(item));
  applySessionStateClasses(tab, isVirtualItem(item) ? null : sessionState(item, transcriptMetadataState.payload.sessions?.[item]));
  tab.setAttribute('aria-label', dockviewTabAriaLabel(item));
}

function dockviewPaneTabHtml(item) {
  // Shares paneTabInnerHtml with the DOM-building createPaneTab so pin/close/popover markup parity is
  // enforced in one place (the Dockview tab renderer just needs the string form).
  return paneTabInnerHtml(item);
}

function dockviewTabAriaLabel(item) {
  return paneTabAriaLabel(item);
}

function dockviewRefreshTabs() {
  if (!dockviewLayoutActive()) return;
  document.querySelectorAll('.dockview-pane-tab').forEach(tab => {
    syncDockviewTabActiveClass(tab);
    tab.__yolomuxDockviewRefresh?.();
  });
  document.querySelectorAll('.dockview-pane-header-actions').forEach(actions => {
    actions.__yolomuxDockviewRefresh?.();
  });
  dockviewSyncHeaderBackgroundDragSources();
  dockviewSyncHeaderActionReservations();
  scheduleAgentWindowActivityAnimationSync();
}

function syncDockviewTabActiveClass(tab, api = null) {
  const dockviewActive = tab?.closest?.('.dv-tab')?.classList?.contains('dv-active-tab') === true;
  tab?.classList?.toggle(CLS.active, api?.isActive === true || dockviewActive);
}

function dockviewSyncMountedPanels(options = {}) {
  if (!dockviewLayoutActive()) return;
  for (const item of activePaneItems()) {
    const panel = panelNodes.get(item);
    if (!panel?.isConnected) continue;
    const slot = slotForItem(item);
    if (slot) {
      updatePanelSlot(panel, item, slot);
      syncPaneRoleDom(panel.closest?.('.dv-groupview'), slot);
    }
    if (options.renderAttached !== false) renderAttachedPanelContent(item);
  }
  updatePanelInactiveOverlays();
}

// Re-run the existing Dockview renderer's shared mount path after a cached panel is evicted.
// A normal renderPanels() call cannot do this when the layout signature is unchanged: Dockview keeps
// its component instance, so its content stays empty until updateParameters tells that renderer to
// resolve the panel from panelNodes again.
function dockviewRemountPanel(item) {
  if (!dockviewLayoutActive()) return false;
  const dockviewPanel = dockviewLayoutState.api?.getPanel?.(item);
  const panelApi = dockviewPanel?.api;
  if (typeof panelApi?.updateParameters !== 'function') return false;
  panelApi.updateParameters({
    ...(typeof panelApi.getParameters === 'function' ? panelApi.getParameters() : {}),
    item,
    locale: typeof i18nActiveLocaleId === 'function' ? i18nActiveLocaleId() : '',
  });
  return panelNodes.get(item)?.isConnected === true;
}

function hideDockviewInnerPaneTabs(panel) {
  if (!panel || !dockviewLayoutEnabled()) return false;
  panel.classList.remove('dockview-inner-head-collapsed');
  const head = panel.querySelector('.panel-head');
  if (!head) return true;
  // Collapse the inner head for every non-file-explorer terminal panel — even one without a
  // .pane-tabs strip — so the dockview tab bar is the only tab row and NO pane keeps the head's
  // min-height as an inconsistent buffer above the Info Bar. (file-explorer heads keep their head.)
  if (!head.classList.contains('file-explorer-head')) {
    head.hidden = true;
    head.classList.add('dockview-inner-head-hidden');
    panel.classList.add('dockview-inner-head-collapsed');
  }
  const strip = head.querySelector('.pane-tabs');
  if (strip) {
    strip.hidden = true;
    strip.replaceChildren();
  }
  const controls = head.querySelector('.virtual-panel-controls');
  if (controls) controls.remove();
  return true;
}
function setDomBuilderOptions(element, options = {}) {
  if (!element) return element;
  if (options.id) element.id = options.id;
  if (options.className) element.className = options.className;
  if (options.role) element.setAttribute('role', options.role);
  if (options.title) element.title = options.title;
  if (options.ariaLabel) element.setAttribute('aria-label', options.ariaLabel);
  if (options.ariaHidden !== undefined) element.setAttribute('aria-hidden', options.ariaHidden ? 'true' : 'false');
  if (options.hidden !== undefined) element.hidden = options.hidden === true;
  if (options.dataset) {
    for (const [key, value] of Object.entries(options.dataset)) {
      if (value !== undefined && value !== null && value !== false) element.dataset[key] = value === true ? '' : String(value);
    }
  }
  if (options.attributes) {
    for (const [name, value] of Object.entries(options.attributes)) {
      if (!name || value === undefined || value === null || value === false) continue;
      element.setAttribute(name, value === true ? '' : String(value));
    }
  }
  if (options.html !== undefined) element.innerHTML = options.html;
  else if (options.label !== undefined) element.textContent = options.label;
  return element;
}

function domBuilderSerializedAttributes(element) {
  const attrs = [];
  const seen = new Set();
  const add = (name, value) => {
    if (!name || value === undefined || value === null || value === false || seen.has(name)) return;
    seen.add(name);
    if (value === true) attrs.push(` ${name}`);
    else attrs.push(` ${name}="${esc(value)}"`);
  };
  const attrMap = element?.attributes || {};
  if (element?.id) add('id', element.id);
  if (String(element?.localName || '').toLowerCase() === 'button') add('type', element.type || attrMap.type || 'button');
  const className = typeof element?.className === 'string' ? element.className : '';
  if (className) add('class', className);
  if (element?.title) add('title', element.title);
  if (typeof attrMap.length === 'number') {
    for (const attr of Array.from(attrMap)) add(attr.name, attr.value);
  } else {
    for (const [name, value] of Object.entries(attrMap)) add(name, value);
  }
  if (element?.dataset && typeof element.dataset === 'object') {
    for (const [key, value] of Object.entries(element.dataset)) add(domDataAttributeName(key), value);
  }
  if (element?.hidden === true) add('hidden', true);
  if (element?.disabled === true) add('disabled', true);
  return attrs.join('');
}

function domBuilderElementHtml(element) {
  if (!element) return '';
  const tagName = String(element.localName || element.tagName || element.nodeName || 'div').toLowerCase();
  const childHtml = Array.from(element.children || []).map(child => domBuilderElementHtml(child)).join('');
  const body = childHtml || element.innerHTML || esc(element.textContent || '');
  return `<${tagName}${domBuilderSerializedAttributes(element)}>${body}</${tagName}>`;
}

function createToolbarButton(options = {}) {
  const dataset = {...(options.dataset || {})};
  if (options.action) dataset.action = options.action;
  const button = makeButton({
    type: options.type || 'button',
    id: options.id,
    className: options.className,
    role: options.role,
    html: options.html,
    label: options.label,
    disabled: options.disabled,
    title: options.title,
    ariaLabel: options.ariaLabel,
    pressed: options.pressed,
    checked: options.checked,
    dataset,
  });
  return setDomBuilderOptions(button, options);
}

function createActionRowItem(item = {}) {
  if (item.node) return item.node;
  if (item.kind === 'separator') {
    const separator = document.createElement(item.tagName || 'span');
    return setDomBuilderOptions(separator, {
      className: item.className,
      hidden: item.hidden,
      dataset: item.dataset,
      attributes: item.attributes,
      ariaHidden: item.ariaHidden !== false,
    });
  }
  if (item.kind === 'custom') {
    const node = document.createElement(item.tagName || 'span');
    return setDomBuilderOptions(node, item);
  }
  return createToolbarButton(item);
}

function createActionRow(options = {}) {
  const row = document.createElement(options.tagName || 'div');
  setDomBuilderOptions(row, options);
  for (const item of options.items || options.actions || []) {
    row.appendChild(createActionRowItem(item));
  }
  return row;
}

function createSegmentedControl(options = {}) {
  return createActionRow({
    tagName: options.tagName || 'span',
    className: options.className,
    role: options.role || 'group',
    ariaLabel: options.ariaLabel,
    hidden: options.hidden,
    dataset: options.dataset,
    attributes: options.attributes,
    actions: (options.items || []).map(item => ({
      ...item,
      className: item.className || options.buttonClassName || '',
      action: item.action || options.action,
    })),
  });
}

function toolbarButtonHtml(options = {}) {
  return domBuilderElementHtml(createToolbarButton(options));
}

function actionRowHtml(options = {}) {
  return domBuilderElementHtml(createActionRow(options));
}

function segmentedControlHtml(options = {}) {
  return domBuilderElementHtml(createSegmentedControl(options));
}

function bindActionDispatcher(parent, handlers = {}, options = {}) {
  return delegate(parent, options.type || 'click', options.selector || '[data-action]', async (event, target) => {
    const action = target?.dataset?.action || '';
    const handler = handlers[action];
    if (!handler || options.ignore?.(event, target) === true) return;
    if (options.preventDefault !== false) event.preventDefault();
    if (options.stopPropagation !== false) event.stopPropagation();
    if (options.skipDisabled !== false && (target.disabled || target.hidden)) return;
    await handler(event, target, action);
  }, options.listenerOptions || {});
}
